import type { Capability, SmeTier, SubModuleEntry } from "../types/canonical";
import { getCapQuestion } from "../lib/checklistFormat";
import { TIER_LABEL, TIER_CLASS } from "../lib/tier";
import "./Type11Table.css";

export interface Props {
  moduleId: string;
  caps: Capability[];
  /**
   * Sub-modules in declaration order. When provided, caps render grouped by
   * family → sub-module with continuous numbering (matches IMDA Type 1.1
   * deliverable shape). Caps without a sub-module fall under
   * "Other / Unassigned" at the end.
   *
   * When omitted, the table falls back to a single ungrouped section in
   * input order — useful for the bare per-tier preview before
   * enrich_canonical_with_submodules.py has populated cap.sub_module_id.
   */
  subModules?: SubModuleEntry[];
  /**
   * Sequence start for the first cap row. Default 1; pass a higher value if
   * the table sits below another sequenced section (e.g. when split across
   * multiple <Type11Table> instances).
   */
  startSeq?: number;
}

// Tier sort within a sub-module: R first, then P, then A. Caps without a
// tier (shouldn't happen post-canonicalise) sink to the bottom.
const TIER_RANK: Record<string, number> = {
  required: 0,
  preferred: 1,
  advanced: 2,
};

function tierRank(c: Capability): number {
  return TIER_RANK[c.sme_tier ?? ""] ?? 99;
}

function formatSeq(seq: number): string {
  return seq < 10 ? `0${seq}` : String(seq);
}

interface Section {
  key: string;
  family: string | null;
  subModuleName: string | null;
  caps: Capability[];
}

function buildSections(caps: Capability[], subModules: SubModuleEntry[]): Section[] {
  const byCapId = new Map(caps.map(c => [c.id, c]));
  const placedCapIds = new Set<string>();
  const sections: Section[] = [];
  for (const sm of subModules) {
    const inScope = sm.caps
      .map(cid => byCapId.get(cid))
      .filter((c): c is Capability => c !== undefined);
    if (inScope.length === 0) continue;
    inScope.sort((a, b) => tierRank(a) - tierRank(b));
    inScope.forEach(c => placedCapIds.add(c.id));
    sections.push({
      key: sm.id,
      family: sm.family,
      subModuleName: sm.canonical_name,
      caps: inScope,
    });
  }
  const orphans = caps.filter(c => !placedCapIds.has(c.id));
  if (orphans.length > 0) {
    orphans.sort((a, b) => tierRank(a) - tierRank(b));
    sections.push({
      key: "_unassigned",
      family: null,
      subModuleName: null,
      caps: orphans,
    });
  }
  return sections;
}

function CapRow({ cap, seq, moduleId }: { cap: Capability; seq: number; moduleId: string }) {
  const tier: SmeTier = cap.sme_tier ?? "required";
  return (
    <tr>
      <td className="t11-col-no">{moduleId}.{formatSeq(seq)}</td>
      <td className="t11-col-feature">{cap.name}</td>
      <td className={`t11-col-tier ${TIER_CLASS[tier]} tier-text`}>{TIER_LABEL[tier]}</td>
      <td className="t11-col-q">{getCapQuestion(cap)}</td>
    </tr>
  );
}

function FlatTable({ caps, moduleId, startSeq }: { caps: Capability[]; moduleId: string; startSeq: number }) {
  return (
    <table className="t11-table">
      <thead>
        <tr>
          <th className="t11-col-no">No.</th>
          <th className="t11-col-feature">Feature</th>
          <th className="t11-col-tier">Tier</th>
          <th className="t11-col-q">Question</th>
        </tr>
      </thead>
      <tbody>
        {caps.map((c, idx) => (
          <CapRow key={c.id} cap={c} seq={startSeq + idx} moduleId={moduleId} />
        ))}
      </tbody>
    </table>
  );
}

export function Type11Table({ moduleId, caps, subModules, startSeq = 1 }: Props) {
  // No sub-module grouping → single flat table in input order.
  if (!subModules || subModules.length === 0) {
    return <FlatTable caps={caps} moduleId={moduleId} startSeq={startSeq} />;
  }

  const sections = buildSections(caps, subModules);
  let runningSeq = startSeq;

  return (
    <div className="t11-grouped">
      <table className="t11-table">
        <thead>
          <tr>
            <th className="t11-col-no">No.</th>
            <th className="t11-col-feature">Feature</th>
            <th className="t11-col-tier">Tier</th>
            <th className="t11-col-q">Question</th>
          </tr>
        </thead>
        <tbody>
          {sections.map(s => {
            const headerLabel = s.subModuleName
              ? (s.family ? `${s.family} — ${s.subModuleName}` : s.subModuleName)
              : "Other / Unassigned";
            const sectionStart = runningSeq;
            runningSeq += s.caps.length;
            return (
              <SectionRows
                key={s.key}
                label={headerLabel}
                caps={s.caps}
                moduleId={moduleId}
                startSeq={sectionStart}
              />
            );
          })}
        </tbody>
      </table>
    </div>
  );
}

function SectionRows({
  label,
  caps,
  moduleId,
  startSeq,
}: {
  label: string;
  caps: Capability[];
  moduleId: string;
  startSeq: number;
}) {
  return (
    <>
      <tr className="t11-section-head">
        <td colSpan={4}>{label}</td>
      </tr>
      {caps.map((c, idx) => (
        <CapRow key={c.id} cap={c} seq={startSeq + idx} moduleId={moduleId} />
      ))}
    </>
  );
}
