import type { CanonicalModule } from "../types/canonical";
import { getFileJson, type GitHubAuth } from "./githubClient";

/**
 * Fetch a canonical module's JSON payload. Three deploy surfaces, two
 * fetch paths:
 *
 *   - CF Worker deploy        → /canonical/<slug>.json (assets binding)
 *   - GH Pages bridge (viewer)→ /erp-mapper/canonical/<slug>.json (bundled)
 *   - GH Pages v2 native      → GitHub API: GET /repos/<owner>/<repo>/contents/output/canonical/<slug>.json
 *
 * The first two share `loadCanonicalModuleStatic`; the third is
 * `loadCanonicalModuleFromGitHub` and runs against a user-supplied PAT/OAuth
 * token. Callers branch on GITHUB_NATIVE from AuthContext.
 */
export async function loadCanonicalModuleStatic(slug: string): Promise<CanonicalModule> {
  const res = await fetch(
    `${import.meta.env.BASE_URL}canonical/${encodeURIComponent(slug)}.json`,
    { credentials: "same-origin" },
  );
  if (!res.ok) {
    throw new Error(`canonical fetch failed for ${slug}: ${res.status}`);
  }
  return res.json() as Promise<CanonicalModule>;
}

export async function loadCanonicalModuleFromGitHub(
  slug: string,
  auth: GitHubAuth,
  ref: string = "main",
): Promise<CanonicalModule> {
  return getFileJson<CanonicalModule>(auth, `output/canonical/${slug}.json`, ref);
}

/** Backwards-compat alias used by existing callers. Continues to read from
 *  the bundled static path so the CF Worker + GH Pages bridge surfaces don't
 *  change behaviour. v2 callers should switch to the explicit pair above. */
export const loadCanonicalModule = loadCanonicalModuleStatic;
