/**
 * TypeScript shapes for the canonical JSON files at output/canonical/<module>.json.
 *
 * The Python pipeline emits a much richer schema than this — these types only
 * cover what the SPA renders. Extend as we port more views (use cases,
 * compliance, integrations etc.).
 *
 * Source of truth for the full shape:
 *   pipeline/canonicalise.py (the orchestrator)
 *   pipeline/steps/_common.py (helpers)
 *   docs/architecture.md
 */

export type SmeTier = "required" | "preferred" | "advanced" | "deleted";

export interface VendorQuestions {
  question?: string;        // Type 1 verbose
  question_terse?: string;  // Type 1.1 single-line
  question_t2?: string;     // Type 2 umbrella bullet (verb-led summary)
  covers?: Array<{ text?: string }>;
}

export interface SectorRelevance {
  generic?: boolean;
  scope_sectors?: string[];
  sectors?: Record<string, { relevant?: boolean }>;
}

export interface CapOverride {
  fields_overridden?: string[];
  note?: string;
  original?: Partial<{
    name: string;
    description: string;
    sme_tier: SmeTier;
    in_checklist: boolean;
    vendor_question: string;
    vendor_question_terse: string;
    vendor_question_t2: string;
  }>;
}

export interface Capability {
  id: string;
  name: string;
  description?: string;
  sme_tier?: SmeTier;
  in_checklist?: boolean;
  vendor_questions?: VendorQuestions;
  sector_relevance?: SectorRelevance;
  _cap_override?: CapOverride;
  // Per-cap sub-module + family fields stamped by
  // scripts/enrich_canonical_with_submodules.py. Null when the cap is a
  // baseline cross-cutting cap (Platform & Data) or otherwise unassigned.
  family?: string | null;
  sub_module_id?: string | null;
  sub_module_name?: string | null;
  sub_module_desc?: string | null;
  // Anything else lives on c[any] but isn't typed for the SPA yet.
  [key: string]: unknown;
}

export interface SubModuleEntry {
  id: string;
  canonical_name: string;
  description?: string;
  family: string;
  caps: string[];   // cap_ids in declaration order
}

export interface ClusterConfig {
  mode: "single" | "multi";
  clusters?: Array<{ id: string; name: string; caps: string[] }>;
}

export interface PreferredClustersConfig {
  required?: ClusterConfig;
  preferred?: ClusterConfig;
}

export interface ModuleSectorApplicability {
  applicable_sectors?: string[];
  generic_score?: number;
  rationale?: string;
}

export interface AiFeatureExample {
  title?: string;
  description?: string;
}

export interface AiFeaturesBlock {
  question?: string;
  tier_label?: string;
  source?: string;
  examples?: AiFeatureExample[];
}

export interface CanonicalModule {
  module: string;          // slug, e.g. "financial_management"
  module_id?: string;      // numeric prefix used in IMDA, e.g. "100"
  module_name?: string;    // display name
  module_description?: string;
  module_headline?: string;
  capabilities: Capability[];
  module_sector_applicability?: ModuleSectorApplicability;
  preferred_clusters?: PreferredClustersConfig;
  ai_features?: AiFeaturesBlock;
  total_required_qs?: number;
  total_preferred_qs?: number;
  // Sub-modules touching this module, in declaration order from
  // config/sub_modules.yaml. Drives Type 1.1 rendering: family →
  // sub-module → caps.
  sub_modules?: SubModuleEntry[];
  // Plenty more — add as the SPA grows.
  [key: string]: unknown;
}

// Partition helpers —————————————————————————————————————————————————————

export interface CapPartition {
  required: Capability[];
  preferred: Capability[];
  advanced: Capability[];
  optional: Capability[]; // in_checklist === false
}

export function partitionCaps(caps: Capability[]): CapPartition {
  const out: CapPartition = { required: [], preferred: [], advanced: [], optional: [] };
  for (const c of caps) {
    if (c.sme_tier === "deleted") continue;
    if (c.in_checklist === false) { out.optional.push(c); continue; }
    if (c.sme_tier === "required") out.required.push(c);
    else if (c.sme_tier === "preferred") out.preferred.push(c);
    else if (c.sme_tier === "advanced") out.advanced.push(c);
  }
  return out;
}

// Build clusters honouring `preferred_clusters` config (or single fallback).
export function buildClusters(
  caps: Capability[],
  cfg: ClusterConfig | undefined,
  defaultLabel: string,
): Array<{ id: string; name: string; caps: Capability[] }> {
  if (!cfg || cfg.mode !== "multi" || !Array.isArray(cfg.clusters)) {
    return [{ id: "all", name: defaultLabel, caps }];
  }
  const claimed = new Set<string>();
  const out: Array<{ id: string; name: string; caps: Capability[] }> = [];
  for (const cl of cfg.clusters) {
    const inCluster = caps.filter(c => (cl.caps || []).includes(c.id));
    inCluster.forEach(c => claimed.add(c.id));
    if (inCluster.length > 0) out.push({ id: cl.id, name: cl.name, caps: inCluster });
  }
  const orphans = caps.filter(c => !claimed.has(c.id));
  if (orphans.length > 0) out.push({ id: "_other", name: `${defaultLabel} — other`, caps: orphans });
  return out;
}
