import { Fragment } from "react";
import type { StakeholdersSummary } from "../lib/stakeholdersData";
import { TermTip } from "./TermTip";
import "./MethodologySection.css";

export interface Props {
  summary: StakeholdersSummary;
}

interface KpiStat {
  num: number;
  label: string;
}

interface Principle {
  title: string;
  body: string;
}

export function MethodologySection({ summary }: Props) {
  const k = summary.kpis;
  const excludedNote = k.sol_cats_excluded > 0 ? ` (${k.sol_cats_excluded} excluded as non-ERP)` : "";

  const stats: KpiStat[] = [
    { num: k.sol_cats, label: `PSG sol cats${excludedNote}` },
    { num: k.proxy_erps, label: "reference ERPs" },
    { num: k.unique_caps, label: "canonical capabilities" },
    { num: k.modules, label: "ERP modules" },
  ];

  const principles: Principle[] = [
    {
      title: "Two anchors, not one",
      body: "IMDA names the regulatory baseline. Reference ERPs name the industry baseline. Each contributes caps the other missed; the canonical checklist is the union, with provenance tracked per cap.",
    },
    {
      title: "Curated, not scraped",
      body: "Every checklist row carries a documented derivation chain — sol cat → question → cap, or reference-ERP → cap. Click any row in the Coverage tab to read its sources.",
    },
    {
      title: "Sectorally specific",
      body: "Sector relevance is scored per cap within the sectors a module actually applies to (L1+L2 layering) — not generic boilerplate across all 16 PSG sectors.",
    },
  ];

  return (
    <section className="ms-section">
      <header className="ms-hero">
        <h1>How this ERP checklist was built</h1>
        <p className="ms-pitch">
          An evidence-grounded vendor-qualification checklist for Singapore SMEs.
          Two anchors converge: the IMDA PSG pre-approval guide names <em>what's
          required to qualify for grant funding</em>; {k.proxy_erps}+ reference ERPs
          (NetSuite, SAP, Odoo, ERPNext, Microsoft Dynamics, Oracle) name <em>what
          mature SMEs actually run</em>. Each fills gaps the other missed.
        </p>
        <div className="ms-stat-strip">
          {stats.map(s => (
            <div key={s.label} className="ms-stat">
              <div className="ms-stat-num">{s.num.toLocaleString()}</div>
              <div className="ms-stat-lbl">{s.label}</div>
            </div>
          ))}
        </div>
      </header>

      <div className="ms-anchors">
        <div className="ms-anchor ms-anchor-imda">
          <div className="ms-anchor-eyebrow">Regulatory baseline</div>
          <div className="ms-anchor-title">IMDA / PSG</div>
          <p>
            {k.sol_cats.toLocaleString()} pre-approval sol cats, {k.raw_requirements.toLocaleString()}+ raw
            requirements parsed. Defines what an SME-grade ERP must support to qualify
            for grant funding. Ground truth for compliance — but not exhaustive (some
            production-grade caps the regulator never asked about).
          </p>
        </div>
        <div className="ms-anchor-arrow" aria-hidden="true">→</div>
        <div className="ms-anchor ms-anchor-erp">
          <div className="ms-anchor-eyebrow">Industry baseline</div>
          <div className="ms-anchor-title">{k.proxy_erps}+ reference ERPs</div>
          <p>
            NetSuite, SAP, Odoo, ERPNext, Microsoft Dynamics, Oracle. Defines the
            capability vocabulary mature SMEs run in production — modules, sub-modules,
            cap names. Adds caps IMDA missed; sets the structural typology the
            pipeline groups requirements under.
          </p>
        </div>
      </div>

      <div className="ms-taxonomy">
        <span className="ms-taxonomy-eyebrow">Our taxonomy</span>
        {k.modules || 10} ERP modules + ~60 vendor-specialty sub-modules — derived from
        major-suite convention. Sub-modules represent coherent vendor specialties a
        PSG buyer can qualify independently. Full definitions in the{" "}
        <TermTip hint="config/erp_modules.yaml + config/sub_modules.yaml">module + sub-module configs</TermTip>.
      </div>

      <h2 className="ms-h2"><span className="ms-num">§1</span>Pipeline</h2>
      <p className="ms-sub">
        Six-stage pipeline that takes both anchors and produces a single
        sector-aware checklist. Step 1 groups raw IMDA requirements under
        reference-ERP capability vocabulary (caps inherit their structure
        from industry-standard ERPs). Later steps trace every canonical cap
        back to the IMDA Qs that back it — giving each cap a "regulator
        agrees" / "industry-only" / "regulator-only gap" verdict.
      </p>

      <ol className="ms-pipeline">
        {summary.pipeline_stages.slice(0, 6).map((s, i) => (
          <li key={s.name} className="ms-stage">
            <div className="ms-stage-step">Stage {i + 1}</div>
            <div className="ms-stage-name">{s.name}</div>
            <div className="ms-stage-ds" title="Data-science analogue">{s.ds_analogue}</div>
            <div className="ms-stage-desc">{s.plain_description}</div>
            {s.stat && <div className="ms-stage-stat">{s.stat}</div>}
          </li>
        ))}
      </ol>

      <div className="ms-principles">
        {principles.map(p => (
          <div key={p.title} className="ms-principle">
            <div className="ms-principle-title">{p.title}</div>
            <div className="ms-principle-body">{p.body}</div>
          </div>
        ))}
      </div>

      <h2 className="ms-h2"><span className="ms-num">§2</span>Reference ERPs cited</h2>
      <p className="ms-sub">
        The capability vocabulary at step 1 is grounded in 12 production ERP
        suites. Distribution across the 305 caps in the proxy library:
      </p>
      <ul className="ms-sources">
        <li><strong>NetSuite</strong> — finance + GL + AP/AR + suiteanalytics</li>
        <li><strong>SAP S/4HANA</strong> — PM (plant maint), PP (production planning), MM (materials)</li>
        <li><strong>Oracle Fusion</strong> — manufacturing, field service</li>
        <li><strong>Microsoft Dynamics 365</strong> — Finance, SCM, Field Service, CE</li>
        <li><strong>Odoo</strong> — accounting, sales, CRM, inventory, HR, project, fleet, planning, recruitment, timesheets, purchase, invoicing</li>
        <li><strong>ERPNext</strong> — core, HR, projects, stock</li>
        <li><strong>Workday HCM</strong> + <strong>SuitePeople</strong></li>
        <li><strong>Sage Intacct</strong></li>
        <li><strong>Salesforce</strong> — Sales Cloud, Field Service</li>
        <li><strong>HubSpot</strong></li>
        <li><strong>IBM Maximo</strong> + <strong>Infor CloudSuite</strong></li>
        <li><strong>Smaller specialists</strong> — Xero, QuickBooks, Cin7, Fishbowl, Fleetio, Jobber, Gusto, Deel, ADP, BambooHR, Chevin FleetWave</li>
      </ul>
      <p className="ms-sub small">
        Known omissions: Acumatica, Epicor, SYSPRO, MYOB, Microsoft Business
        Central. Worth re-grounding caps against these for a future pass —
        the SG SMB context is under-represented today.
      </p>

      <h2 className="ms-h2"><span className="ms-num">§3</span>Sizing — micro / small / mid / enterprise</h2>
      <p className="ms-sub">
        Each cap in the proxy library carries a{" "}
        <TermTip hint="applicability field in data/proxy/*.yaml">size-applicability</TermTip>{" "}
        annotation naming the firm sizes it makes sense for. Distribution
        across 305 caps:
      </p>
      <table className="ms-size-table">
        <thead>
          <tr><th>Applicability</th><th>Caps</th><th>%</th><th>Examples</th></tr>
        </thead>
        <tbody>
          <tr><td>SME + mid-market + enterprise</td><td>259</td><td>85%</td><td>most caps (asset register, GL, contacts)</td></tr>
          <tr><td>Mid-market + enterprise (NOT SME)</td><td>32</td><td>10%</td><td>geospatial GIS, intercompany consolidation</td></tr>
          <tr><td>Enterprise only</td><td>10</td><td>3%</td><td>RCM/FMEA, complex linear assets</td></tr>
          <tr><td>Other patterns</td><td>4</td><td>&lt;2%</td><td>edge cases</td></tr>
        </tbody>
      </table>
      <p className="ms-sub">
        The Mandatory tier classification rule has two clauses: a cap is
        Mandatory iff (a) it's <strong>universal across industries</strong> AND
        (b) it's <strong>applicable at the SME size</strong>. The 32+10 caps
        that aren't SME-applicable cannot be Mandatory regardless of how
        cross-industry they are — they fall to Preferred or Advanced. This
        keeps the Mandatory list aligned with the PSG target (SME grant
        qualification), not enterprise feature parity.
      </p>

      <h2 className="ms-h2"><span className="ms-num">§4</span>Caveats &amp; known gaps</h2>
      <p className="ms-sub">
        Where this checklist might be wrong, in the team's own words.
      </p>
      <div className="ms-caveats">
        <div className="ms-caveat">
          <div className="ms-caveat-title">1. Manufacturing depth is thin</div>
          <p>
            The IMDA PSG catalogue under-represents manufacturing — only a
            handful of mfg-specific sol cats exist. As a result, 18 of 32
            canonical mfg caps (MRP, production scheduling, WIP tracking,
            S&amp;OP capacity planning, traceability/genealogy, subcontracting,
            process vs discrete modes, demand planning, repair returns,
            safety compliance) come from reference ERPs only — IMDA didn't
            ask. Validate manufacturing-heavy vendors against industry
            frameworks (APICS SCOR, ISA-95) in addition to the IMDA list.
          </p>
        </div>
        <div className="ms-caveat">
          <div className="ms-caveat-title">2. Sub-module structure is hand-curated</div>
          <p>
            The{" "}
            <TermTip hint="config/sub_modules.yaml">sub-module config</TermTip>{" "}
            is human-authored — every cap → sub-module assignment is an
            editorial call. The pipeline doesn't auto-cluster caps into
            sub-modules yet; that's deferred to a future automation step
            (cap-name embedding + Haiku-validate cluster proposal). Today,
            sub-module verdicts and the L2 vendor-question wording are
            pinned by hand.
          </p>
        </div>
        <div className="ms-caveat">
          <div className="ms-caveat-title">3. Manual cap overrides on top of pipeline</div>
          <p>
            58 caps (~19%) carry hand-edited overrides in the{" "}
            <TermTip hint="data/manual_cap_overrides.yaml">manual override file</TermTip>{" "}
            on top of the pipeline output. Each entry is timestamped,
            attributed to{" "}
            <TermTip hint="author: human-review">human review</TermTip>, and
            carries a note explaining why. Three patterns dominate, and we're
            working to fold them back into the pipeline:
          </p>
          <ul className="ms-caveat-list">
            <li>
              <strong>Cross-module baselines</strong> — caps like Data governance,
              User access &amp; roles, and Integration / import-export are
              platform/baseline capabilities that exist in every module. As of{" "}
              <TermTip hint="pipeline/steps/step15_baseline_tier_resolution.py">step 15 (May 2026)</TermTip>{" "}
              the pipeline auto-demotes these Required → Preferred by reading
              the sub-module config's baseline block — so the manual override
              layer no longer carries the tier flip for them.
            </li>
            <li>
              <strong>Tier rebalance</strong> (~10 entries) — caps whose
              Required/Preferred classification doesn't match PSG endorsement
              evidence. Already detectable by the{" "}
              <TermTip hint="scripts/audit_tier_psg_consistency.py">tier-PSG-consistency audit</TermTip>{" "}
              + the new size-applicability rule (§3) — could become a pipeline
              step that auto-applies high-confidence proposals.
            </li>
            <li>
              <strong>Demote non-universal</strong> (~39 entries) — caps that
              exist in some industries but aren't universal (B2B-only,
              retail-only, service-only). Genuinely editorial; expected to
              stay manual but will shrink as the (industry × size) rule
              from §3 catches more of them automatically.
            </li>
          </ul>
        </div>
      </div>

      <PricingSummary summary={summary} />

      <p className="ms-footer muted small">
        Data refreshed {formatDateForDisplay(summary.generated_at)}. Re-runs
        on every Publish to repo (rebuilds the canonical pipeline + this
        page in CI).
      </p>
    </section>
  );
}

/**
 * Cross-module pricing summary — 4 commodity-suite modules × 3 tiers.
 * Renders only when summary.vendor_pricing has data; otherwise hides
 * (the data file may not exist on first deploys).
 *
 * Headlines per (module × tier): vendors with data, avg Year-1 SGD,
 * avg Mandatory coverage in base. Links into Coverage > Module >
 * Pricing check for the per-cap detail.
 */
function PricingSummary({ summary }: { summary: StakeholdersSummary }) {
  const vp = summary.vendor_pricing;
  if (!vp || !vp.modules) return null;

  const modulePricingKeys: Array<{ key: string; slug: string; label: string }> = [
    { key: "financial",    slug: "financial_management",         label: "Financial" },
    { key: "sales_crm",    slug: "sales_and_crm",                label: "Sales & CRM" },
    { key: "hr",           slug: "human_resources_management",   label: "HR" },
    { key: "supply_chain", slug: "supply_chain_and_inventory",   label: "Supply Chain" },
  ];
  const tierKeys: Array<{ key: "sme" | "mid" | "enterprise"; label: string }> = [
    { key: "sme",        label: "SME" },
    { key: "mid",        label: "Mid-market" },
    { key: "enterprise", label: "Enterprise" },
  ];

  return (
    <>
      <h2 className="ms-h2"><span className="ms-num">§5</span>Pricing reality check</h2>
      <p className="ms-sub">
        Cross-module summary of how the Mandatory tier maps to commercial
        pricing across {vp._meta.vendor_count_with_pricing} catalogued
        vendors with public/PSG data (of {vp._meta.vendor_count_total} total).
        Year-1 SGD = software×12 + PS one-time + training one-time. PSG
        bundles include all 3. Drill into any module via Coverage &gt;
        Module &gt; Pricing check for per-cap + per-vendor breakdown.
      </p>
      <table className="ms-pricing-table">
        <thead>
          <tr>
            <th>Module</th>
            {tierKeys.map(t => (
              <th key={t.key} colSpan={2} className="ms-pricing-tier-h">
                {t.label}
              </th>
            ))}
          </tr>
          <tr>
            <th />
            {tierKeys.map(t => (
              <Fragment key={t.key}>
                <th className="num small">avg Year-1</th>
                <th className="num small">avg M cov</th>
              </Fragment>
            ))}
          </tr>
        </thead>
        <tbody>
          {modulePricingKeys.map(m => {
            const mdata = vp.modules[m.key];
            return (
              <tr key={m.key}>
                <td>
                  <a href={`#/dashboard?p=module&mt=pricing&fm=${m.slug}`}>{m.label}</a>
                  <div className="muted small">
                    {mdata?.mandatory_total ?? "?"} M caps
                  </div>
                </td>
                {tierKeys.map(t => {
                  const td = mdata?.by_tier?.[t.key];
                  if (!td || td.vendor_count_with_pricing === 0) {
                    return (
                      <Fragment key={t.key}>
                        <td className="num muted small">—</td>
                        <td className="num muted small">—</td>
                      </Fragment>
                    );
                  }
                  const withPricing = td.vendors.filter(v => v.year1_total_sgd != null);
                  const avgY1 = withPricing.length > 0
                    ? Math.round(withPricing.reduce((s, v) => s + (v.year1_total_sgd || 0), 0) / withPricing.length)
                    : null;
                  const avgCov = withPricing.length > 0
                    ? Math.round(withPricing.reduce((s, v) => s + v.mandatory_pct, 0) / withPricing.length)
                    : null;
                  return (
                    <Fragment key={t.key}>
                      <td className="num">
                        {avgY1 != null ? `S$${avgY1.toLocaleString()}` : <span className="muted">—</span>}
                        <div className="muted small">{td.vendor_count_with_pricing}/{td.vendor_count_total}</div>
                      </td>
                      <td className={`num ${avgCov != null && avgCov >= 80 ? "ms-pricing-cov-ok" : avgCov != null && avgCov >= 50 ? "ms-pricing-cov-warn" : "ms-pricing-cov-fail"}`}>
                        {avgCov != null ? `${avgCov}%` : <span className="muted">—</span>}
                      </td>
                    </Fragment>
                  );
                })}
              </tr>
            );
          })}
        </tbody>
      </table>
      <p className="ms-sub small">
        Note: average Year-1 excludes vendors that are quote-on-request
        (NetSuite, SAP B1, Workday, etc.). Coverage % counts caps in the
        base plan only — add-ons treated separately.
      </p>
    </>
  );
}

/**
 * Render an ISO-8601 timestamp as a stakeholder-friendly date.
 * Falls back to the raw string if parsing fails.
 */
function formatDateForDisplay(iso: string | undefined): string {
  if (!iso) return "—";
  try {
    const d = new Date(iso);
    if (Number.isNaN(d.getTime())) return iso;
    const opts: Intl.DateTimeFormatOptions = {
      year: "numeric",
      month: "short",
      day: "numeric",
      hour: "2-digit",
      minute: "2-digit",
      timeZone: "Asia/Singapore",
      timeZoneName: "short",
    };
    return new Intl.DateTimeFormat("en-SG", opts).format(d);
  } catch {
    return iso;
  }
}
