import type { ReactNode } from "react";
import "./TermTip.css";

export interface TermTipProps {
  /**
   * The technical identifier the surface label maps to. Shown as the
   * hover tooltip so devs can still find the underlying file/field/cap-id.
   */
  hint: string;
  /** Plain-English label shown to the reader. */
  children: ReactNode;
}

/**
 * Inline term with a hover tooltip — used to swap snake_case identifiers
 * for plain-English on stakeholder-facing surfaces while still letting
 * devs hover to see the underlying file path / field name / cap-id.
 *
 * Usage:
 *   <TermTip hint="config/sub_modules.yaml">the sub-module config</TermTip>
 *   <TermTip hint="data_governance">Data governance</TermTip>
 */
export function TermTip({ hint, children }: TermTipProps) {
  return (
    <span className="term-tip" title={hint}>
      {children}
    </span>
  );
}
