import type { VendorPricingRow } from "../../lib/stakeholdersData";
import {
  applyComponents,
  rescale,
  formatPriceForDisplay,
  type PricingProfile,
} from "../../lib/pricingProfile";
import "./PricingChart.css";

interface Props {
  vendors: VendorPricingRow[];
  /** Active profile — chart points + axis labels honour this. When null,
   *  falls back to backend baseline (annual SGD, 10-pax). */
  profile?: PricingProfile;
}

/**
 * Hand-rolled SVG scatter: x = total cost (rescaled per active profile),
 * y = Mandatory coverage %. Each vendor is a labelled dot. Bundled-PSG
 * vendors filled, software-only vendors outlined. Vendors with no
 * pricing data are listed in a footer row instead of plotted.
 *
 * The chart respects the active pricing profile (pax / period /
 * components / currency) — flip Currency to USD and the X-axis labels
 * + dot positions all update.
 */
export function PricingChart({ vendors, profile }: Props) {
  // Compute the active-profile x value for each vendor. Falls back to the
  // raw year1_total_sgd when no profile is provided.
  const points = vendors
    .filter(v => v.year1_total_sgd != null && !v.no_pricing_data)
    .map(v => {
      // Apply components filter + rescale through the active profile so
      // chart cells match the table cells exactly.
      const breakdown = v.year1_breakdown;
      const componentTotal = profile
        ? applyComponents(breakdown, v.year1_total_sgd, profile.components)
        : v.year1_total_sgd;
      const baselineSgdMonth = componentTotal != null ? componentTotal / 12 : null;
      const r = profile
        ? rescale(baselineSgdMonth, v.base_price_label, profile)
        : { value: baselineSgdMonth != null ? baselineSgdMonth * 12 : null, scaled: false, label: "", baseline_sgd_month: baselineSgdMonth };
      return {
        v,
        x: r.value as number,
        y: v.mandatory_pct,
        bundled: breakdown?.bundled === true,
        rescaleNote: r.scaled ? r.label : null,
      };
    })
    .filter(p => p.x != null && p.x > 0);

  const noDataVendors = vendors.filter(v => v.no_pricing_data || v.year1_total_sgd == null);

  if (points.length === 0) {
    return (
      <div className="pcc-empty muted small">
        No pricing data to chart at this tier.
        {noDataVendors.length > 0 && (
          <> {noDataVendors.length} vendor(s) with no data: {noDataVendors.map(v => v.name).join(", ")}</>
        )}
      </div>
    );
  }

  // X-axis: total cost on a log-ish scale so $200 and $200,000 both fit.
  const xs = points.map(p => p.x);
  const xMinRaw = Math.max(1, Math.min(...xs));
  const xMaxRaw = Math.max(...xs);
  const padFactor = 1.4;
  const xMin = xMinRaw / padFactor;
  const xMax = xMaxRaw * padFactor;
  const xLog = (x: number) => (Math.log10(Math.max(1, x)) - Math.log10(xMin)) / (Math.log10(xMax) - Math.log10(xMin) || 1);

  // Smaller chart per user feedback — was 720×320, now 540×220.
  const W = 540;
  const H = 220;
  const M = { top: 16, right: 22, bottom: 44, left: 50 };
  const innerW = W - M.left - M.right;
  const innerH = H - M.top - M.bottom;

  const xPx = (x: number) => M.left + xLog(x) * innerW;
  const yPx = (y: number) => M.top + (1 - y / 100) * innerH;

  // X-axis ticks at order-of-magnitude steps within range
  const xTicks: number[] = [];
  for (let p = Math.floor(Math.log10(xMin)); p <= Math.ceil(Math.log10(xMax)); p++) {
    const v = Math.pow(10, p);
    if (v >= xMin / 1.1 && v <= xMax * 1.1) xTicks.push(v);
  }
  const yTicks = [0, 25, 50, 75, 100];

  const currencySym = profile?.currency === "USD" ? "US$" : "S$";
  const periodLabel =
    profile?.period === "monthly" ? "monthly" :
    profile?.period === "3yr_tco" ? "3-yr TCO" : "Year-1";
  const xAxisLabel = `${periodLabel} ${currencySym} total (log scale)`;

  return (
    <div className="pcc-wrap">
      {profile && (
        <div className="pcc-active-profile" title="Toggle pax / period / components / currency below the chart">
          Active profile: <strong>{profile.pax} pax</strong> ·{" "}
          <strong>{periodLabel}</strong> ·{" "}
          <strong>{profile.components === "sw_only" ? "Software only"
            : profile.components === "sw_ps" ? "+ PS"
            : "+ PS + Training"}</strong> ·{" "}
          <strong>{profile.currency}</strong>
        </div>
      )}
      <svg className="pcc-svg" viewBox={`0 0 ${W} ${H}`} role="img" aria-label="Vendor pricing scatter chart">
        <title>{xAxisLabel} × Mandatory coverage % per vendor</title>

        {/* Background bands for coverage bands */}
        <rect x={M.left} y={yPx(100)} width={innerW} height={yPx(80) - yPx(100)} fill="#ecfdf5" opacity="0.6" />
        <rect x={M.left} y={yPx(80)} width={innerW} height={yPx(50) - yPx(80)} fill="#fefce8" opacity="0.6" />
        <rect x={M.left} y={yPx(50)} width={innerW} height={yPx(0) - yPx(50)} fill="#fef2f2" opacity="0.5" />

        {/* Y-axis grid + labels */}
        {yTicks.map(t => (
          <g key={t}>
            <line
              x1={M.left} x2={W - M.right}
              y1={yPx(t)} y2={yPx(t)}
              stroke="#e2e8f0" strokeDasharray="2 2"
            />
            <text x={M.left - 6} y={yPx(t) + 3} textAnchor="end" fontSize="9" fill="#64748b">
              {t}%
            </text>
          </g>
        ))}

        {/* X-axis grid + labels (log) */}
        {xTicks.map(t => (
          <g key={t}>
            <line
              x1={xPx(t)} x2={xPx(t)}
              y1={M.top} y2={H - M.bottom}
              stroke="#f1f5f9" strokeDasharray="2 2"
            />
            <text x={xPx(t)} y={H - M.bottom + 13} textAnchor="middle" fontSize="9" fill="#64748b">
              {currencySym}{t < 1000 ? t : `${t / 1000}k`}
            </text>
          </g>
        ))}

        {/* Axis lines */}
        <line x1={M.left} x2={M.left} y1={M.top} y2={H - M.bottom} stroke="#94a3b8" />
        <line x1={M.left} x2={W - M.right} y1={H - M.bottom} y2={H - M.bottom} stroke="#94a3b8" />

        {/* Axis labels */}
        <text x={W / 2} y={H - 6} textAnchor="middle" fontSize="10" fill="#475569" fontWeight="600">
          {xAxisLabel}
        </text>
        <text
          x={-(H / 2)} y={12}
          transform="rotate(-90)" textAnchor="middle"
          fontSize="10" fill="#475569" fontWeight="600"
        >
          Mandatory coverage % (in base plan)
        </text>

        {/* Points */}
        {points.map(p => {
          const cx = xPx(p.x);
          const cy = yPx(p.y);
          const r = 6;
          const fill = p.bundled ? "#1d4ed8" : "#fff";
          const stroke = p.bundled ? "#1e3a8a" : "#1d4ed8";
          return (
            <g key={p.v.id}>
              <circle cx={cx} cy={cy} r={r} fill={fill} stroke={stroke} strokeWidth={2}>
                <title>
                  {p.v.name} ({p.v.tier})
                  {"\n"}{periodLabel}: {formatPriceForDisplay(p.x, profile || { pax: 10, currency: "SGD", period: "annual", components: "sw_ps_tr" })}
                  {p.rescaleNote ? `\n${p.rescaleNote}` : ""}
                  {"\n"}Mandatory: {p.y}% in base ({p.v.mandatory_covered_in_base}/{p.v.mandatory_total})
                  {"\n"}Source: {p.v.year1_source}
                  {p.v.base_price_label ? `\nQuoted as: ${p.v.base_price_label}` : ""}
                </title>
              </circle>
              <text
                x={cx + r + 2} y={cy + 3}
                fontSize="9" fill="#0f172a" fontWeight="500"
              >
                {shortenName(p.v.name)}
              </text>
            </g>
          );
        })}
      </svg>

      <div className="pcc-legend">
        <span className="pcc-leg-item">
          <svg width="12" height="12" viewBox="0 0 14 14"><circle cx="7" cy="7" r="5" fill="#1d4ed8" stroke="#1e3a8a" strokeWidth={2} /></svg>
          PSG-bundled (incl. PS + training)
        </span>
        <span className="pcc-leg-item">
          <svg width="12" height="12" viewBox="0 0 14 14"><circle cx="7" cy="7" r="5" fill="#fff" stroke="#1d4ed8" strokeWidth={2} /></svg>
          Software-only
        </span>
      </div>

      {noDataVendors.length > 0 && (
        <div className="pcc-no-data muted small">
          Not plotted ({noDataVendors.length}):{" "}
          {noDataVendors.map(v => `${v.name} (${v.pricing_status})`).join(" · ")}
        </div>
      )}
    </div>
  );
}

function shortenName(name: string, max = 16): string {
  if (name.length <= max) return name;
  const cleaned = name
    .replace(/\s+(Pte\.?\s*Ltd\.?|Inc\.?|GmbH|Corp\.?)$/i, "")
    .replace(/\s+\(.*?\)\s*$/, "");
  if (cleaned.length <= max) return cleaned;
  return cleaned.slice(0, max - 1) + "…";
}
