import { useEffect, useMemo, useState } from "react";
import { useSearchParams } from "react-router-dom";
import {
  loadPricingPayload,
  type PricingPayload,
  type PricingVendor,
  type PricingPackage,
  moduleLabel,
} from "../lib/pricingData";
import { fuzzyFilter } from "../lib/fuzzy";
import "./PricingLibraryPage.css";

/**
 * Pricing Library — sol cat (PSG category) → vendor packages browse.
 *
 * Sister view to Coverage > Module > Pricing (which compares 4 commodity
 * modules using the 23 curated benchmark vendors). This page covers the
 * full 414-vendor PSG catalogue at package level — every solution that
 * appears in the PSG IT Solutions directory.
 *
 * Filters: module, category, exclude-non-ERP. Each row shows lowest +
 * highest package price (SGD verbatim from GoBusiness export) and the
 * PSG support %. Click a row to expand into the full package table.
 *
 * Detail layer (Haiku-parsed tier breakdowns) is shown for vendors that
 * have been through the PDF parser pipeline — ~15 so far, will grow as
 * Phase 1-4 ingest expands.
 */
export function PricingLibraryPage() {
  const [payload, setPayload] = useState<PricingPayload | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [search, setSearch] = useSearchParams();

  const moduleFilter = search.get("mod") || "";
  const categoryFilter = search.get("cat") || "";
  const includeExcluded = search.get("inc") === "1";
  const query = search.get("q") || "";
  const expanded = search.get("ex") || "";

  useEffect(() => {
    loadPricingPayload().then(setPayload).catch(e => setError(String(e?.message || e)));
  }, []);

  const sortedModules = useMemo(() => {
    if (!payload) return [];
    return Object.entries(payload.by_module)
      .sort((a, b) => b[1].vendor_count - a[1].vendor_count)
      .map(([slug, info]) => ({ slug, ...info }));
  }, [payload]);

  const sortedCategories = useMemo(() => {
    if (!payload) return [];
    return Object.entries(payload.by_category)
      .filter(([_, info]) => includeExcluded || !info.excluded)
      .filter(([_, info]) => {
        if (!moduleFilter) return true;
        return info.modules.includes(moduleFilter);
      })
      .map(([name, info]) => ({ name, ...info }))
      .sort((a, b) => b.vendor_ids.length - a.vendor_ids.length);
  }, [payload, moduleFilter, includeExcluded]);

  const activeCategory = useMemo(() => {
    if (!payload || !categoryFilter) return null;
    return payload.by_category[categoryFilter] || null;
  }, [payload, categoryFilter]);

  const visibleVendors = useMemo<PricingVendor[]>(() => {
    if (!payload) return [];
    let list: PricingVendor[];
    if (activeCategory) {
      list = activeCategory.vendor_ids.map(id => payload.vendors[id]).filter(Boolean);
    } else if (moduleFilter) {
      const idx = payload.by_module[moduleFilter];
      list = idx ? idx.vendor_ids.map(id => payload.vendors[id]).filter(Boolean) : [];
    } else {
      list = Object.values(payload.vendors);
    }
    if (!includeExcluded) {
      list = list.filter(v => !v.excluded_from_erp);
    }
    return fuzzyFilter(list, query, ["vendor_name", "solution_name", "category"]);
  }, [payload, activeCategory, moduleFilter, includeExcluded, query]);

  function update(key: string, value: string | null) {
    updateMany({ [key]: value });
  }

  /** Single setSearch call across an arbitrary number of patches. Each
   *  individual `update` would otherwise read the same stale `search`
   *  state and overwrite each other when called consecutively in one
   *  handler — that was the bug that made the Module dropdown snap back
   *  to "All" after every selection. */
  function updateMany(patches: Record<string, string | null>) {
    const next = new URLSearchParams(search);
    for (const [key, value] of Object.entries(patches)) {
      if (value == null || value === "") {
        next.delete(key);
      } else {
        next.set(key, value);
      }
    }
    setSearch(next, { replace: false });
  }

  if (error) {
    return (
      <section className="pricing-lib-page">
        <h1>Pricing Library</h1>
        <p>Failed to load pricing payload: {error}</p>
      </section>
    );
  }

  if (!payload) {
    return (
      <section className="pricing-lib-page">
        <h1>Pricing Library</h1>
        <p className="muted">Loading PSG vendor pricing…</p>
      </section>
    );
  }

  return (
    <section className="pricing-lib-page">
      <header className="pricing-lib-header">
        <h1>Pricing Library</h1>
        <p className="muted">
          Verbatim package pricing from the GoBusiness PSG IT Solutions
          directory ({payload._meta.summary_count} vendors).
          Detail breakdown available for {payload._meta.detailed_count} vendors
          so far (more added as PSG submission PDFs are parsed).
          Generated {new Date(payload._meta.generated_at).toLocaleDateString()}.
        </p>
      </header>

      <div className="pricing-lib-filters">
        <label>
          <span>Module:</span>
          <select value={moduleFilter} onChange={e => updateMany({ mod: e.target.value, cat: "" })}>
            <option value="">All modules</option>
            {sortedModules.map(m => (
              <option key={m.slug} value={m.slug}>
                {moduleLabel(m.slug)} ({m.vendor_count})
              </option>
            ))}
          </select>
        </label>
        <label>
          <span>Sol cat / category:</span>
          <select value={categoryFilter} onChange={e => update("cat", e.target.value)}>
            <option value="">All categories</option>
            {sortedCategories.map(c => (
              <option key={c.name} value={c.name}>
                {c.name} ({c.vendor_ids.length})
              </option>
            ))}
          </select>
        </label>
        <label>
          <span>Search:</span>
          <input
            type="search"
            value={query}
            placeholder="vendor or solution name…"
            onChange={e => update("q", e.target.value)}
          />
        </label>
        <label className="pricing-lib-inline-check">
          <input
            type="checkbox"
            checked={includeExcluded}
            onChange={e => update("inc", e.target.checked ? "1" : null)}
          />
          <span>Include non-ERP categories</span>
        </label>
      </div>

      <div className="pricing-lib-summary">
        Showing <strong>{visibleVendors.length}</strong> vendor
        {visibleVendors.length === 1 ? "" : "s"}
        {moduleFilter && <> in <strong>{moduleLabel(moduleFilter)}</strong></>}
        {categoryFilter && <> · <strong>{categoryFilter}</strong></>}
        .
      </div>

      <table className="pricing-lib-table">
        <thead>
          <tr>
            <th>Vendor / Solution</th>
            <th>Category</th>
            <th>Packages</th>
            <th>Lowest total</th>
            <th>Highest total</th>
            <th>PSG support</th>
            <th>Detail</th>
          </tr>
        </thead>
        <tbody>
          {visibleVendors.map(v => {
            const id = v.psg_id || v.benchmark_id || `${v.vendor_name}-${v.solution_name}`;
            const isExpanded = expanded === id;
            const lowest = v.packages.map(p => p.total_cost_sgd).filter((n): n is number => typeof n === "number");
            const highest = lowest.length ? Math.max(...lowest) : null;
            const lo = lowest.length ? Math.min(...lowest) : null;
            return (
              <Row
                key={id}
                v={v}
                isExpanded={isExpanded}
                onToggle={() => update("ex", isExpanded ? "" : id)}
                lo={lo}
                hi={highest}
              />
            );
          })}
          {visibleVendors.length === 0 && (
            <tr><td colSpan={7} className="muted">No vendors match the current filters.</td></tr>
          )}
        </tbody>
      </table>
    </section>
  );
}

interface RowProps {
  v: PricingVendor;
  isExpanded: boolean;
  onToggle: () => void;
  lo: number | null;
  hi: number | null;
}

function Row({ v, isExpanded, onToggle, lo, hi }: RowProps) {
  const hasDetail = !!v.detail;
  const isBenchmark = !!v.benchmark_id;
  return (
    <>
      <tr className={`pricing-lib-row${isBenchmark ? " benchmark" : ""}${v.excluded_from_erp ? " excluded" : ""}`}>
        <td>
          <strong>{v.vendor_name || "—"}</strong>
          <br />
          <span className="solution-name">{v.solution_name || "—"}</span>
          {isBenchmark && <span className="badge benchmark-badge">Benchmark ERP</span>}
          {v.excluded_from_erp && <span className="badge excluded-badge">Non-ERP</span>}
        </td>
        <td>
          {v.category || "—"}
          {v.modules.length > 0 && (
            <div className="module-chips">
              {v.modules.map(m => <span key={m} className="chip">{moduleLabel(m)}</span>)}
            </div>
          )}
        </td>
        <td className="num">{v.packages.length}</td>
        <td className="num">{lo != null ? formatSgd(lo) : "—"}</td>
        <td className="num">{hi != null ? formatSgd(hi) : "—"}</td>
        <td className="num">{v.psg_support_pct_raw || "—"}</td>
        <td>
          <button type="button" className="link-btn" onClick={onToggle}>
            {isExpanded ? "Hide" : hasDetail ? "Show + breakdown" : "Show packages"}
          </button>
          {v.psg_url && (
            <> · <a href={v.psg_url} target="_blank" rel="noopener noreferrer">PSG listing ↗</a></>
          )}
          {v.vendor_url && (
            <> · <a href={v.vendor_url} target="_blank" rel="noopener noreferrer">Vendor site ↗</a></>
          )}
        </td>
      </tr>
      {isExpanded && (
        <tr className="pricing-lib-detail-row">
          <td colSpan={7}>
            <VendorDetailExpansion v={v} />
          </td>
        </tr>
      )}
    </>
  );
}

function VendorDetailExpansion({ v }: { v: PricingVendor }) {
  return (
    <div className="pricing-lib-detail">
      {v.description && (
        <p className="vendor-desc">{v.description}</p>
      )}
      {v.packages.length > 0 && (
        <>
          <h4>Packages (verbatim from PSG listing)</h4>
          <table className="pkg-table">
            <thead>
              <tr>
                <th>Package</th>
                <th>Total cost</th>
                <th>Qualifying cost</th>
                <th>Net cost after PSG</th>
              </tr>
            </thead>
            <tbody>
              {v.packages.map((p, i) => <PackageRow key={i} p={p} />)}
            </tbody>
          </table>
          {v.payment_mode && (
            <p className="muted">Payment mode: <strong>{v.payment_mode}</strong></p>
          )}
        </>
      )}
      {v.detail && v.detail.plans.length > 0 && (
        <>
          <h4>Tier + feature breakdown (Haiku-parsed)</h4>
          <p className="muted">
            Source: {v.detail.fetched_from || "vendor source"} ·
            Extracted: {v.detail.extracted_at ? new Date(v.detail.extracted_at).toLocaleDateString() : "—"} ·
            Model: {v.detail.model}
          </p>
          {v.detail.plans.map((plan, i) => (
            <div key={i} className="detail-plan">
              <h5>
                {plan.name || `Plan ${i + 1}`}
                {plan.price && (
                  <span className="plan-price">
                    {" — "}
                    {plan.price.amount} {plan.price.currency} / {plan.price.unit}
                  </span>
                )}
              </h5>
              {plan.price?.source_phrase && (
                <p className="source-phrase">"{plan.price.source_phrase}"</p>
              )}
              {plan.included_features && plan.included_features.length > 0 && (
                <ul>
                  {plan.included_features.slice(0, 12).map((f, j) => <li key={j}>{f.text}</li>)}
                  {plan.included_features.length > 12 && (
                    <li className="muted">+ {plan.included_features.length - 12} more features…</li>
                  )}
                </ul>
              )}
            </div>
          ))}
        </>
      )}
      {!v.detail && v.packages.length === 0 && (
        <p className="muted">
          No package pricing or detail breakdown available for this vendor yet.
          {v.benchmark_id && " Benchmark ERPs without a PSG listing may require a vendor-site enrichment pass."}
        </p>
      )}
    </div>
  );
}

function PackageRow({ p }: { p: PricingPackage }) {
  return (
    <tr>
      <td><strong>{p.name}</strong></td>
      <td className="num">{p.total_cost_raw || "—"}</td>
      <td className="num">{p.qualifying_cost_raw || "—"}</td>
      <td className="num">{p.net_cost_raw || "—"}</td>
    </tr>
  );
}

function formatSgd(n: number): string {
  return `S$${n.toLocaleString("en-SG", { maximumFractionDigits: 0 })}`;
}
