import { useMemo, useState } from "react";
import type {
  CapEvidence,
  ModuleEntry,
  ModuleImdaQuestion,
  ModuleImdaSummary,
} from "../lib/stakeholdersData";
import "./CapComparison.css";

export interface Props {
  modules: ModuleEntry[];
  capsIndex: CapEvidence[];
  moduleImdaSummary: Record<string, ModuleImdaSummary>;
  moduleImdaQuestions: Record<string, ModuleImdaQuestion[]>;
}

interface Row {
  slug: string;
  name: string;
  total: number;
  imdaBacked: number;
  proxyOnly: number;
  imdaPct: number;
  topSolCats: Array<{ id: string; short: string; cap_count: number }>;
}

/**
 * §2 — three-way cap comparison per module.
 *
 * Three buckets per module:
 *   IMDA-backed   = caps with imda_refs (both regulator + industry agree)
 *   Proxy-only    = caps without imda_refs (industry says SMEs need it,
 *                   IMDA missed it — kept because real ERPs ship it)
 *   Orphan IMDA Qs = IMDA Qs not backed by any cap (regulator asks, we
 *                    miss — real gap)
 *
 * Click a row to drill into the proxy-only caps list for that module.
 */
export function CapComparison({
  modules,
  capsIndex,
  moduleImdaSummary,
}: Props) {
  const [expanded, setExpanded] = useState<string | null>(null);

  const rows: Row[] = useMemo(() => {
    return modules
      .map(m => {
        const s = moduleImdaSummary[m.slug];
        const total = s?.total_caps ?? 0;
        const imdaBacked = s?.imda_driven_count ?? 0;
        const proxyOnly = s?.proxy_only_count ?? 0;
        const imdaPct = total > 0 ? Math.round((imdaBacked / total) * 100) : 0;
        const topSolCats = (s?.top_solcats || []).slice(0, 3).map(t => ({
          id: t.sol_cat,
          short: t.sol_cat_short,
          cap_count: t.cap_count,
        }));
        return { slug: m.slug, name: m.name, total, imdaBacked, proxyOnly, imdaPct, topSolCats };
      })
      .sort((a, b) => b.proxyOnly - a.proxyOnly);
  }, [modules, moduleImdaSummary]);

  const proxyOnlyCapsByModule = useMemo(() => {
    const map: Record<string, CapEvidence[]> = {};
    for (const c of capsIndex) {
      if (!c.imda_refs || c.imda_refs.length === 0) {
        (map[c.module] ||= []).push(c);
      }
    }
    return map;
  }, [capsIndex]);

  const totals = useMemo(() => {
    return rows.reduce(
      (acc, r) => {
        acc.total += r.total;
        acc.imdaBacked += r.imdaBacked;
        acc.proxyOnly += r.proxyOnly;
        return acc;
      },
      { total: 0, imdaBacked: 0, proxyOnly: 0 },
    );
  }, [rows]);
  const totalsPct = totals.total > 0 ? Math.round((totals.imdaBacked / totals.total) * 100) : 0;

  return (
    <section className="capcomp-section">
      <h2 className="capcomp-h2">
        <span className="capcomp-num">§2</span>
        Where each cap comes from
      </h2>
      <p className="capcomp-lede">
        Per-module breakdown of the three buckets that make up the canonical
        checklist. <strong>IMDA-backed</strong> caps are where regulator and
        industry agree (the validated core). <strong>Proxy-only</strong> caps
        are kept because mature SMEs run them in production even though the
        IMDA guide didn't ask for them — they represent gaps in the regulatory
        baseline. Click any row to inspect the proxy-only caps for that module.
      </p>

      <table className="capcomp-table">
        <thead>
          <tr>
            <th>Module</th>
            <th className="capcomp-num-col">Caps</th>
            <th className="capcomp-num-col">IMDA-backed</th>
            <th className="capcomp-num-col">Proxy-only</th>
            <th>Top backing sol cats</th>
            <th aria-label="Drill" />
          </tr>
        </thead>
        <tbody>
          {rows.map(r => {
            const isOpen = expanded === r.slug;
            const proxyCaps = proxyOnlyCapsByModule[r.slug] || [];
            return (
              <FragmentRow
                key={r.slug}
                row={r}
                isOpen={isOpen}
                proxyCaps={proxyCaps}
                onToggle={() => setExpanded(isOpen ? null : r.slug)}
              />
            );
          })}
        </tbody>
        <tfoot>
          <tr className="capcomp-totals-row">
            <td>All modules</td>
            <td className="capcomp-num-col">{totals.total}</td>
            <td className="capcomp-num-col">
              {totals.imdaBacked} <span className="capcomp-pct">({totalsPct}%)</span>
            </td>
            <td className="capcomp-num-col">{totals.proxyOnly}</td>
            <td colSpan={2} />
          </tr>
        </tfoot>
      </table>

      <p className="capcomp-footnote muted small">
        IMDA-backed = cap has at least one <code>imda_refs</code> entry from a
        PSG sol cat Q. Proxy-only = cap exists in the canonical library but
        carries no IMDA reference; verify each is genuinely industry-standard
        before shipping.
      </p>
    </section>
  );
}

function FragmentRow({
  row,
  isOpen,
  proxyCaps,
  onToggle,
}: {
  row: Row;
  isOpen: boolean;
  proxyCaps: CapEvidence[];
  onToggle: () => void;
}) {
  return (
    <>
      <tr
        className={`capcomp-row${isOpen ? " open" : ""}`}
        onClick={onToggle}
        aria-expanded={isOpen}
      >
        <td>
          <strong>{row.name}</strong>
        </td>
        <td className="capcomp-num-col">{row.total}</td>
        <td className="capcomp-num-col">
          {row.imdaBacked} <span className="capcomp-pct">({row.imdaPct}%)</span>
        </td>
        <td className="capcomp-num-col">
          {row.proxyOnly > 0 ? (
            <span className="capcomp-proxy-only-badge">{row.proxyOnly}</span>
          ) : (
            <span className="muted">0</span>
          )}
        </td>
        <td className="capcomp-solcats">
          {row.topSolCats.length === 0 ? (
            <span className="muted">—</span>
          ) : (
            row.topSolCats.map((s, i) => (
              <span key={s.id}>
                {i > 0 && " · "}
                <span title={s.id}>{s.short}</span>
                <span className="muted small"> ({s.cap_count})</span>
              </span>
            ))
          )}
        </td>
        <td className="capcomp-drill-col">{isOpen ? "▾" : "▸"}</td>
      </tr>
      {isOpen && (
        <tr className="capcomp-drill-row">
          <td colSpan={6}>
            <div className="capcomp-drill-body">
              <h4>Proxy-only caps in {row.name} ({proxyCaps.length})</h4>
              {proxyCaps.length === 0 ? (
                <p className="muted">
                  None — every cap in this module is IMDA-backed.
                </p>
              ) : (
                <ul className="capcomp-cap-list">
                  {proxyCaps.map(c => (
                    <li key={c.id}>
                      <code>{c.id}</code> — {c.name}
                      {c.sub_module_name && (
                        <span className="muted small"> · {c.sub_module_name}</span>
                      )}
                      {c.sme_tier && (
                        <span className={`capcomp-tier-${c.sme_tier}`}>{c.sme_tier}</span>
                      )}
                    </li>
                  ))}
                </ul>
              )}
            </div>
          </td>
        </tr>
      )}
    </>
  );
}
