import { useState, type CSSProperties } from "react";
import { useSortable } from "@dnd-kit/sortable";
import { CSS } from "@dnd-kit/utilities";
import type { Capability } from "../types/canonical";
import { useDrafts } from "../contexts/DraftsContext";
import { useEffectiveRole } from "../lib/useEffectiveRole";
import { canEdit } from "../lib/role";
import { CapEditor } from "./CapEditor";
import "./CapRow.css";

const BASELINE_SUFFIXES = new Set([
  "mobile_access",
  "user_access_roles",
  "data_governance",
  "integration_import_export",
]);

function capSuffix(c: Capability): string {
  const id = c.id || "";
  return id.includes(".") ? id.split(".").pop()! : id;
}
function isBaseline(c: Capability): boolean {
  return BASELINE_SUFFIXES.has(capSuffix(c));
}
function bulletText(c: Capability, draftTerse?: string, draftT2?: string): string {
  // Phase 0: dedicated question_t2 field is the source of truth. Falls back
  // to the legacy strip-from-terse path when t2 is missing — covers any cap
  // whose t2 was manually cleared. Note: previous BASELINE_BULLET_OVERRIDES
  // hard-coded mechanism was removed 2026-05-09 since the editable t2 layer
  // replaces the need for hard-coded per-suffix overrides.
  if (draftT2 !== undefined && draftT2 !== "") return draftT2;

  const vq = c.vendor_questions || {};
  const t2 = (vq.question_t2 || "").trim();
  if (t2) return t2;

  const baseTerse = draftTerse !== undefined && draftTerse !== ""
    ? draftTerse
    : (vq.question_terse || "");
  let src = baseTerse.trim();
  if (src) {
    src = src
      .replace(/^(Does|Can|Will|Should|Is|Are|Do)\s+(your|the)\s+(solution|product|system|module|software|service)\s+/i, "")
      .replace(/^(Does|Can|Will|Should|Is|Are|Do)\s+/i, "")
      .replace(/\?\s*$/, "")
      .trim();
    // "Allow <any subject> to" — broader than the previous you/users/customers
    // match so "Allow sales teams to" / "Allow warehouse staff to" also strip.
    src = src.replace(/^(allow|allows|enable|enables|let|lets|help|helps)\s+[^,.]+?\s+to\s+/i, "");
    src = src.replace(/\byour\b/gi, "the");
    if (src) src = src.charAt(0).toUpperCase() + src.slice(1);
    return src;
  }

  const desc = (c.description || "").trim();
  const m = desc.match(/^([^.?!]+[.?!])\s*/);
  // No char-cap — full first sentence. Display-side CSS handles visual clipping.
  const text = m ? m[1].trim() : desc;
  return text || c.name || c.id;
}

function shortAuthor(emailOrName: string | undefined): string {
  if (!emailOrName) return "?";
  const at = emailOrName.indexOf("@");
  return at > 0 ? emailOrName.slice(0, at) : emailOrName;
}

function relTime(iso: string | undefined): string {
  if (!iso) return "";
  const t = new Date(iso).getTime();
  if (isNaN(t)) return "";
  const diffSec = Math.max(0, (Date.now() - t) / 1000);
  if (diffSec < 60) return "just now";
  if (diffSec < 3600) return `${Math.round(diffSec / 60)}m ago`;
  if (diffSec < 86400) return `${Math.round(diffSec / 3600)}h ago`;
  return new Date(iso).toLocaleDateString();
}

interface Props {
  cap: Capability;
  index: number;
  multiSelect: boolean;
  module: string;
  signedInEmail?: string;
}

export function CapRow({ cap, index, multiSelect, module, signedInEmail }: Props) {
  const { getDraft } = useDrafts();
  const role = useEffectiveRole();
  const editable = canEdit(role);
  const [editing, setEditing] = useState(false);
  const draftRecord = getDraft(module, cap.id);
  const draft = draftRecord?.fields;

  // dnd-kit sortable hook — gives us refs + listeners for the drag handle.
  // Listeners attach only to the dedicated handle so clicks on edit / checkboxes
  // / sector pills don't accidentally start a drag.
  const {
    attributes,
    listeners,
    setNodeRef,
    setActivatorNodeRef,
    transform,
    transition,
    isDragging,
  } = useSortable({ id: cap.id });

  const baseline = isBaseline(cap);
  const activeName = draft?.name !== undefined ? draft.name : cap.name;
  const draftFromOther = !!draftRecord
    && !!signedInEmail
    && draftRecord.author?.email !== signedInEmail;
  const draftFromYou = !!draftRecord && (!signedInEmail || draftRecord.author?.email === signedInEmail);

  const sortableStyle: CSSProperties = {
    transform: CSS.Transform.toString(transform),
    transition,
    opacity: isDragging ? 0.4 : 1,
    background: isDragging ? "#fef9c3" : undefined,
  };

  return (
    <li
      ref={setNodeRef}
      style={sortableStyle}
      // id used by deep-links — /canonical/<mod>?cap=<id> auto-scrolls
      // here on load.
      id={`cap-${cap.id}`}
      className={`t2-bullet ${baseline ? "t2-bullet-baseline" : ""} ${isDragging ? "t2-bullet-dragging" : ""}`}
    >
      <div className="t2-bullet-head">
        {editable && (
          <button
            ref={setActivatorNodeRef}
            {...attributes}
            {...listeners}
            className="cap-drag-handle"
            title="Drag to reorder within this umbrella"
            aria-label="Drag handle"
          >
            ⋮⋮
          </button>
        )}
        {!multiSelect && <span className="t2-bullet-number">{index})</span>}
        {multiSelect && (
          <input
            type="checkbox"
            className="t2-bullet-check"
            disabled
            title="Multi-select disabled in this preview"
          />
        )}
        <span className="t2-bullet-name">{activeName}</span>
        {cap.sub_module_name && (
          <span
            className="t2-submodule-ref"
            title={`Sub-module reference (informational; not part of the checklist structure): ${cap.sub_module_name}`}
          >
            {cap.sub_module_name}
          </span>
        )}
        {baseline && (
          <span className="t2-baseline-chip" title="Baseline cross-cutting cap">
            baseline
          </span>
        )}
        {cap.sector_relevance?.generic === true && (
          <span className="fc-sector-pill" title="Relevant across this module's applicable sectors">
            generic ✓
          </span>
        )}
        {draftFromOther && draftRecord && (
          <span
            className="cap-cloud-pill"
            title={`Saved by ${draftRecord.author?.email} · ${relTime(draftRecord.updated_at)}. Visible to all reviewers; not yet published.`}
          >
            draft ({shortAuthor(draftRecord.author?.email)})
          </span>
        )}
        {draftFromYou && draftRecord && (
          <span
            className="cap-draft-pill"
            title={`Your saved draft · ${relTime(draftRecord.updated_at)}. Click Publish to commit to repo.`}
          >
            draft (you)
          </span>
        )}
        {editable && (
          <span className="cap-edit-btn-row">
            <button
              className="cap-edit-btn"
              onClick={() => setEditing(v => !v)}
              title={editing ? "Close editor" : "Edit cap (tier, name, question, in_checklist)"}
            >
              ✎
            </button>
          </span>
        )}
      </div>
      <div className="t2-bullet-body">
        {bulletText(cap, draft?.vendor_question_terse, draft?.vendor_question_t2)}
      </div>
      {editing && (
        <CapEditor
          module={module}
          cap={cap}
          onClose={() => setEditing(false)}
        />
      )}
    </li>
  );
}
