import { useEffect, useMemo, useState } from "react";
import {
  loadStakeholdersSummary,
  type StakeholdersSummary,
  type CapEvidence,
} from "../../lib/stakeholdersData";
import "./SubModuleMandatoryMatrix.css";

interface Props {
  /** Module slug to focus the matrix on. */
  moduleSlug: string;
  /** Module display name for the header. */
  moduleShort: string;
}

interface SubModuleCol {
  sub_module_id: string;
  sub_module_name: string;
  // R caps in this sub-module (in_checklist:true).
  r_caps: CapEvidence[];
}

interface SolCatRow {
  sc_id: string;
  display_name: string;
  vertical?: string;
  vertical_saas?: boolean;
  is_primary: boolean;          // primary_modules includes this module
  /** Per sub-module: backed/total + names of failing caps for tooltip */
  cells: Map<string, { backed: number; total: number; failing: string[]; passing: string[] }>;
}

/**
 * Sub-module Mandatory pass matrix — IMDA-trace based.
 *
 * For the focused module:
 * 1. Group R caps in that module by sub_module_id (caps_index, in_checklist=true).
 * 2. For each sol cat that has ≥1 IMDA Q backing an R cap in this module:
 *    - Per sub-module, count R caps where this sol cat appears in
 *      requirements.imda_refs.sources.
 *    - Cell verdict: ✓ all backed, △ some backed, × zero backed, — no R caps.
 *
 * Aligned with the Module > IMDA gap verdict logic so the two views agree.
 */
export function SubModuleMandatoryMatrix({ moduleSlug, moduleShort }: Props) {
  const [data, setData] = useState<StakeholdersSummary | null>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    loadStakeholdersSummary()
      .then(setData)
      .catch(e => setError(String(e?.message || e)));
  }, []);

  const { cols, rows } = useMemo(() => {
    if (!data) return { cols: [] as SubModuleCol[], rows: [] as SolCatRow[] };
    return computeMatrix(data, moduleSlug);
  }, [data, moduleSlug]);

  if (error) return <div className="smm-error">Failed to load: {error}</div>;
  if (!data) return <div className="smm-loading">Loading sub-module matrix…</div>;

  if (cols.length === 0) {
    return (
      <div className="smm-empty">
        No Mandatory caps in scope for {moduleShort} (or all M caps lack
        a sub-module assignment).
      </div>
    );
  }
  if (rows.length === 0) {
    return (
      <div className="smm-empty">
        No sol cats trace IMDA Qs to {moduleShort}'s Mandatory caps via
        canonical imda_refs.
      </div>
    );
  }

  return (
    <div className="smm-wrap">
      <p className="smm-blurb">
        <strong>Cap-coverage scoring</strong> — each cell counts how many of
        the sub-module's Mandatory caps are backed by this sol cat's IMDA Qs
        via canonical <code>imda_refs</code>.{" "}
        <span className="smm-tag smm-tag-pass">✓ green</span> all M caps
        traced,{" "}
        <span className="smm-tag smm-tag-partial">amber</span> some,{" "}
        <span className="smm-tag smm-tag-fail">✗ red</span> zero,{" "}
        <span className="smm-tag smm-tag-na">grey</span> sol cat doesn't trace
        any cap in this sub-module.
      </p>
      <div className="smm-table-wrap">
        <table className="smm-table">
          <thead>
            <tr>
              <th className="smm-th-sc">Sol cat</th>
              {cols.map(c => (
                <th key={c.sub_module_id} className="smm-th-sm">
                  <div className="smm-sm-name">{c.sub_module_name}</div>
                  <div className="tier-mix">
                    <span className="tier-mix-seg tier-mix-m">{c.r_caps.length}M</span>
                  </div>
                </th>
              ))}
              <th className="smm-th-total">M sub-mods<br/>complete</th>
            </tr>
          </thead>
          <tbody>
            {rows.map(row => (
              <Row key={row.sc_id} row={row} cols={cols} />
            ))}
          </tbody>
        </table>
      </div>
      <p className="smm-footer muted small">
        {rows.length} sol cat{rows.length === 1 ? "" : "s"} with IMDA Q traces
        into {moduleShort}. Primary rows ranked above ride-alongs.
      </p>
    </div>
  );
}

function Row({ row, cols }: { row: SolCatRow; cols: SubModuleCol[] }) {
  let completeRSm = 0;
  let totalRSm = 0;
  for (const c of cols) {
    const cell = row.cells.get(c.sub_module_id);
    if (!cell || cell.total === 0) continue;
    totalRSm += 1;
    if (cell.backed === cell.total) completeRSm += 1;
  }

  return (
    <tr className={row.is_primary ? "smm-row-primary" : "smm-row-ride"}>
      <td className="smm-td-sc">
        <div className="smm-sc-name">{row.display_name}</div>
        {!row.is_primary && (
          <span className="smm-ride-chip" title="Ride-along — module is not this sol cat's primary scope">
            ride-along
          </span>
        )}
        {row.vertical_saas && (
          <span className="smm-vsaas-chip">vertical SaaS</span>
        )}
      </td>
      {cols.map(c => {
        const cell = row.cells.get(c.sub_module_id);
        const total = c.r_caps.length;
        const backed = cell?.backed || 0;
        if (total === 0) {
          return <td key={c.sub_module_id} className="smm-cell smm-cell-na">—</td>;
        }
        let cls: "pass" | "partial" | "fail" | "na" = "fail";
        let sym = "✗";
        if (backed === total) { cls = "pass"; sym = "✓"; }
        else if (backed > 0)  { cls = "partial"; sym = "△"; }
        // Tooltip: list which caps failed (or passed if all passed) so the
        // reviewer doesn't have to drill into a separate view.
        const failing = cell?.failing || [];
        const passing = cell?.passing || [];
        const tip =
          failing.length === 0
            ? `All ${total} M caps backed:\n  • ${passing.join("\n  • ")}`
            : `${backed}/${total} M caps backed.\nFailing:\n  • ${failing.join("\n  • ")}`;
        return (
          <td
            key={c.sub_module_id}
            className={`smm-cell smm-cell-${cls}`}
            data-tooltip={tip}
          >
            {sym} {backed}/{total} M
          </td>
        );
      })}
      <td className="smm-td-total">
        {totalRSm === 0 ? (
          <span className="smm-total-na">—</span>
        ) : completeRSm === totalRSm ? (
          <span className="smm-total-pass">✓ {completeRSm}/{totalRSm}</span>
        ) : completeRSm === 0 ? (
          <span className="smm-total-fail">✗ {completeRSm}/{totalRSm}</span>
        ) : (
          <span className="smm-total-partial">{completeRSm}/{totalRSm}</span>
        )}
      </td>
    </tr>
  );
}

// ──────────────────────────────────────────────────────────────────────

function computeMatrix(
  data: StakeholdersSummary,
  moduleSlug: string,
): { cols: SubModuleCol[]; rows: SolCatRow[] } {
  const capsIndex: CapEvidence[] = data.caps_index || [];

  // 1. Filter to R caps in this module that are in_checklist (caps_index
  //    excludes deleted; in_checklist not exposed there, so we trust it).
  const rCaps = capsIndex.filter(
    c => c.module === moduleSlug && c.sme_tier === "required" && c.sub_module_id,
  );

  // 2. Group by sub_module_id (preserve first-seen ordering for stable cols).
  const subModuleOrder: string[] = [];
  const colMap = new Map<string, SubModuleCol>();
  for (const c of rCaps) {
    const smId = c.sub_module_id!;
    if (!colMap.has(smId)) {
      colMap.set(smId, {
        sub_module_id: smId,
        sub_module_name: c.sub_module_name || smId,
        r_caps: [],
      });
      subModuleOrder.push(smId);
    }
    colMap.get(smId)!.r_caps.push(c);
  }
  const cols = subModuleOrder.map(id => colMap.get(id)!);

  // 3. For each sol cat that backs ≥1 R cap in this module, build a row.
  //    Walk caps_index → imda_refs.sources to enumerate sol cats.
  const scIdsTouching = new Set<string>();
  for (const c of rCaps) {
    for (const r of c.imda_refs || []) {
      for (const src of r.sources || []) scIdsTouching.add(src);
    }
  }

  const solCatMeta = new Map(
    (data.sol_cats || []).map(s => [s.id, s] as const),
  );

  // For each sol cat: per sub-module, count R caps backed.
  const rows: SolCatRow[] = [];
  for (const scId of scIdsTouching) {
    const meta = solCatMeta.get(scId);
    if (!meta) continue;
    const cells = new Map<string, { backed: number; total: number; failing: string[]; passing: string[] }>();
    for (const col of cols) {
      const failing: string[] = [];
      const passing: string[] = [];
      for (const cap of col.r_caps) {
        const tracesThisSc = (cap.imda_refs || []).some(r =>
          (r.sources || []).includes(scId),
        );
        if (tracesThisSc) passing.push(cap.name);
        else failing.push(cap.name);
      }
      cells.set(col.sub_module_id, {
        backed: passing.length,
        total: col.r_caps.length,
        failing,
        passing,
      });
    }
    rows.push({
      sc_id: scId,
      display_name: meta.display_name,
      vertical: meta.vertical,
      vertical_saas: meta.vertical_saas,
      is_primary: (meta.modules || []).includes(moduleSlug),
      cells,
    });
  }
  rows.sort((a, b) => {
    if (a.is_primary !== b.is_primary) return a.is_primary ? -1 : 1;
    return a.display_name.localeCompare(b.display_name);
  });

  return { cols, rows };
}
