import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useRef,
  useState,
  type ReactNode,
} from "react";

/**
 * Module-scoped state shared across reviewers via the Cloudflare Worker
 * (workers/cap-edit-api `/api/module-state/:module`). Two state_keys today:
 *
 *   cap_order              — per-umbrella cap sequencing. Audit-logged under
 *                            synthetic cap_id `_cap_order`, publishable via
 *                            the Publish flow → data/manual_reorder_overrides.yaml.
 *   ai_features_response   — IMDA checklist deliverable; ALWAYS audited
 *                            (see memory feedback_checklist_audit_logging.md).
 *
 * Read on mount + on focus refresh; writes are queued with a 600 ms debounce
 * so chained edits emit one PUT. Optimistic local state.
 *
 * `flushStatus` exposes per-umbrella saving state so each umbrella header
 * can render a "Saving…" / "Saved ✓" badge near the drag handles.
 */

import { emptyAiFeaturesResponse, type AiFeaturesResponse } from "../lib/aiFeatures";
import { GITHUB_NATIVE, useAuth } from "./AuthContext";
import * as ms from "../lib/moduleState";

type CapOrderMap = Record<string, string[]>;        // umbrellaKey -> [capId, ...]

export type FlushStatus = "idle" | "saving" | "saved" | "error";

interface ModuleStateValue {
  capOrder: CapOrderMap;
  setCapOrderForUmbrella: (umbrellaKey: string, capIds: string[]) => void;
  /** Status of the most recent cap-order flush for an umbrella. UI badges
   *  should auto-dismiss `"saved"` after ~2s. */
  flushStatus: Record<string, FlushStatus>;
  aiFeaturesResponse: AiFeaturesResponse;
  setAiFeaturesResponse: (next: AiFeaturesResponse) => void;
  refresh: () => Promise<void>;
  loading: boolean;
}

const ModuleStateContext = createContext<ModuleStateValue | null>(null);

interface Props {
  moduleSlug: string;
  children: ReactNode;
}

const DEBOUNCE_MS = 600;
const SAVED_DISMISS_MS = 2000;

export function ModuleStateProvider({ moduleSlug, children }: Props) {
  const [capOrder, setCapOrder] = useState<CapOrderMap>({});
  const [aiFeaturesResponse, setAiFeaturesResponseLocal] =
    useState<AiFeaturesResponse>(emptyAiFeaturesResponse);
  const [loading, setLoading] = useState<boolean>(true);
  const [flushStatus, setFlushStatus] = useState<Record<string, FlushStatus>>({});

  const orderDebounceTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const aiDebounceTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const savedDismissTimers = useRef<Map<string, ReturnType<typeof setTimeout>>>(new Map());

  const setUmbrellaStatus = useCallback((umbrellaKey: string, status: FlushStatus) => {
    setFlushStatus(prev => ({ ...prev, [umbrellaKey]: status }));
    const existing = savedDismissTimers.current.get(umbrellaKey);
    if (existing) {
      clearTimeout(existing);
      savedDismissTimers.current.delete(umbrellaKey);
    }
    if (status === "saved") {
      const t = setTimeout(() => {
        setFlushStatus(prev => {
          if (prev[umbrellaKey] !== "saved") return prev;
          const next = { ...prev };
          delete next[umbrellaKey];
          return next;
        });
        savedDismissTimers.current.delete(umbrellaKey);
      }, SAVED_DISMISS_MS);
      savedDismissTimers.current.set(umbrellaKey, t);
    }
  }, []);

  useEffect(() => {
    const timers = savedDismissTimers.current;
    return () => {
      timers.forEach(t => clearTimeout(t));
      timers.clear();
    };
  }, []);

  // v2 mode pulls auth from AuthContext. The stub returned by useAuth when no
  // provider is present is fine for v1 + tests (auth.user is null → v2 paths
  // early-return + the legacy /api/module-state path runs unchanged).
  const auth = useAuth();
  const ghAuth = GITHUB_NATIVE ? auth.auth : null;
  const ghUser = GITHUB_NATIVE ? auth.user : null;

  const refresh = useCallback(async () => {
    if (!moduleSlug) return;
    setLoading(true);
    try {
      if (GITHUB_NATIVE) {
        // v2: read user's draft (overlay on top of published main).
        if (!ghAuth || !ghUser) {
          setCapOrder({});
          setAiFeaturesResponseLocal(emptyAiFeaturesResponse());
          return;
        }
        const userOrder = await ms.getUserCapOrder(ghAuth, ghUser.login, moduleSlug);
        if (Object.keys(userOrder).length > 0) {
          setCapOrder(userOrder);
        } else {
          // Fall back to the published cap_order on main so reviewers see
          // the existing order when they haven't reordered themselves yet.
          try {
            setCapOrder(await ms.getPublishedCapOrder(ghAuth, moduleSlug));
          } catch {
            setCapOrder({});
          }
        }
        const userAi = await ms.getUserAiFeatures(ghAuth, ghUser.login, moduleSlug);
        if (userAi) {
          setAiFeaturesResponseLocal(userAi);
        } else {
          try {
            const published = await ms.getPublishedAiFeatures(ghAuth, moduleSlug);
            setAiFeaturesResponseLocal(published || emptyAiFeaturesResponse());
          } catch {
            setAiFeaturesResponseLocal(emptyAiFeaturesResponse());
          }
        }
        return;
      }
      const res = await fetch(
        `/api/module-state/${encodeURIComponent(moduleSlug)}`,
        { credentials: "same-origin" },
      );
      if (!res.ok) {
        console.warn(`[module-state] GET ${res.status}`);
        return;
      }
      const data = await res.json() as {
        state?: {
          cap_order?: { value?: CapOrderMap };
          ai_features_response?: { value?: AiFeaturesResponse };
        };
      };
      const order = data.state?.cap_order?.value;
      if (order && typeof order === "object") setCapOrder(order);
      else setCapOrder({});
      const aiResp = data.state?.ai_features_response?.value;
      if (aiResp && typeof aiResp === "object" && Array.isArray(aiResp.checkedTitles)) {
        setAiFeaturesResponseLocal({
          checkedTitles: [...aiResp.checkedTitles],
          othersText: typeof aiResp.othersText === "string" ? aiResp.othersText : "",
        });
      } else {
        setAiFeaturesResponseLocal(emptyAiFeaturesResponse());
      }
    } catch (e: unknown) {
      console.warn("[module-state] refresh failed:", e);
    } finally {
      setLoading(false);
    }
  }, [moduleSlug, ghAuth, ghUser]);

  useEffect(() => {
    refresh();
    const onFocus = () => refresh();
    window.addEventListener("focus", onFocus);
    return () => window.removeEventListener("focus", onFocus);
  }, [refresh]);

  const flushStateKey = useCallback(async (
    stateKey: string,
    value: unknown,
    umbrellaKey?: string,
  ) => {
    if (!moduleSlug) return;
    try {
      if (GITHUB_NATIVE) {
        if (!ghAuth || !ghUser) throw new Error("Not signed in");
        if (stateKey === "cap_order") {
          await ms.putUserCapOrder(ghAuth, ghUser.login, moduleSlug, value as CapOrderMap);
        } else if (stateKey === "ai_features_response") {
          await ms.putUserAiFeatures(ghAuth, ghUser.login, moduleSlug, value as AiFeaturesResponse);
        } else {
          throw new Error(`unknown state key: ${stateKey}`);
        }
        if (umbrellaKey) setUmbrellaStatus(umbrellaKey, "saved");
        return;
      }
      const res = await fetch(
        `/api/module-state/${encodeURIComponent(moduleSlug)}/${encodeURIComponent(stateKey)}`,
        {
          method: "PUT",
          credentials: "same-origin",
          headers: { "content-type": "application/json" },
          body: JSON.stringify({ value }),
        }
      );
      if (!res.ok) throw new Error(`PUT ${stateKey} → ${res.status}`);
      if (umbrellaKey) setUmbrellaStatus(umbrellaKey, "saved");
    } catch (e: unknown) {
      console.warn(`[module-state] PUT ${stateKey} failed:`, e);
      if (umbrellaKey) setUmbrellaStatus(umbrellaKey, "error");
    }
  }, [moduleSlug, setUmbrellaStatus, ghAuth, ghUser]);

  const setCapOrderForUmbrella = useCallback((umbrellaKey: string, capIds: string[]) => {
    setCapOrder(prev => {
      const next = { ...prev, [umbrellaKey]: capIds };
      if (orderDebounceTimer.current) clearTimeout(orderDebounceTimer.current);
      setUmbrellaStatus(umbrellaKey, "saving");
      orderDebounceTimer.current = setTimeout(() => {
        orderDebounceTimer.current = null;
        flushStateKey("cap_order", next, umbrellaKey);
      }, DEBOUNCE_MS);
      return next;
    });
  }, [flushStateKey, setUmbrellaStatus]);

  const setAiFeaturesResponse = useCallback((next: AiFeaturesResponse) => {
    setAiFeaturesResponseLocal(next);
    if (aiDebounceTimer.current) clearTimeout(aiDebounceTimer.current);
    aiDebounceTimer.current = setTimeout(() => {
      aiDebounceTimer.current = null;
      flushStateKey("ai_features_response", next);
    }, DEBOUNCE_MS);
  }, [flushStateKey]);

  const value = useMemo<ModuleStateValue>(() => ({
    capOrder,
    setCapOrderForUmbrella,
    flushStatus,
    aiFeaturesResponse,
    setAiFeaturesResponse,
    refresh,
    loading,
  }), [
    capOrder, setCapOrderForUmbrella,
    flushStatus,
    aiFeaturesResponse, setAiFeaturesResponse,
    refresh, loading,
  ]);

  return <ModuleStateContext.Provider value={value}>{children}</ModuleStateContext.Provider>;
}

export function useModuleState() {
  const ctx = useContext(ModuleStateContext);
  if (!ctx) throw new Error("useModuleState must be inside ModuleStateProvider");
  return ctx;
}
