// §3 evidence-drill types ─────────────────────────────────────────────

export interface ImdaRef {
  q_title: string;
  sources: string[]; // sol-cat ids
}

export interface SectorEntry {
  relevant: boolean;
  reason?: string;
}

export interface CapSectorRelevance {
  generic?: boolean;
  scope_sectors?: string[];
  sectors?: Record<string, SectorEntry>;
}

export type SizeApplicability = "sme" | "mid_market" | "enterprise";

export interface CapEvidence {
  id: string;
  name: string;
  module: string;
  family?: string | null;
  sme_tier?: string;
  question?: string;
  imda_refs: ImdaRef[];
  /** Reference-ERP systems that grounded this cap at step 1 of the pipeline.
   *  Wikipedia entries are filtered server-side; what reaches the SPA is real
   *  ERP product names (netsuite, odoo_accounting, sap_s4hana_pm, …). */
  cited_sources: string[];
  /** Firm-size dimensions this cap is applicable for. SG-PSG-relevant caps
   *  always include "sme"; some caps are mid-market/enterprise-only. */
  applicability: SizeApplicability[];
  sector_relevance?: CapSectorRelevance;
  sub_module_id?: string | null;
  sub_module_name?: string | null;
  sub_module_description?: string | null;
}

