import { useEffect, useMemo, useRef, useState, type ReactNode } from "react";
import { Link } from "react-router-dom";
import {
  loadStakeholdersSummary,
  type StakeholdersSummary,
  type CapEvidence,
  type SolcatQuestion,
} from "../../lib/stakeholdersData";
import { useUrlParam } from "../../lib/urlState";
import { fuzzyFilter } from "../../lib/fuzzy";
import { tierClass, TIER_SHORT, type SmeTier } from "../../lib/tier";
import { TabHelp } from "../TabHelp";
import "./ModuleSolcatGap.css";

interface ModuleEntry {
  slug: string;
  module_id: string;
  module_name: string;
  short: string;
}

interface Props {
  modules: ModuleEntry[];
}

type RowFilter = "mandatory" | "mandatory_preferred" | "all" | "failing";

interface CapGapRow {
  cap_id: string;
  name: string;
  module: string;
  sub_module_id: string;
  sub_module_name: string;
  family: string;
  sme_tier: string;
  in_checklist: boolean;
  // Whether this sol cat backs this cap via ≥1 IMDA Q.
  backed: boolean;
  backing_qs: string[];      // q_titles
}

interface SubModuleVerdict {
  sub_module_id: string;
  sub_module_name: string;
  family: string;
  required_total: number;
  required_backed: number;
  fully_covered: boolean;     // all R caps backed
}

interface ModuleVerdict {
  slug: string;
  short: string;
  module_id: string;
  status: "PASS" | "PARTIAL" | "FAIL" | "N/A";
  passing_sub_modules: SubModuleVerdict[];
  failing_sub_modules: SubModuleVerdict[];
  /** Cap-level totals across the module's R caps. */
  required_caps_total: number;
  required_caps_backed: number;
}

/**
 * View A — top screenshot. Per-sol-cat IMDA Qs ↔ canonical checklist gap.
 *
 * For the chosen sol cat:
 * 1. Aggregate caps backed via the sol cat's IMDA Qs (caps_index → imda_refs).
 * 2. Identify the sub-modules those backings touch (and pull all caps in
 *    those sub-modules from caps_index — backed + unbacked).
 * 3. Per module: pass/fail verdict based on whether ≥1 sub-module has all
 *    its Required caps backed.
 *
 * Action column is recommendation-only (Keep / Demote-Re-tag).
 */
export function ModuleSolcatGap({ modules }: Props) {
  const [data, setData] = useState<StakeholdersSummary | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [scId, setScId] = useUrlParam<string>("sc", "");
  const [filter, setFilter] = useState<RowFilter>("mandatory");

  // Searchable sol-cat picker state
  const [pickerQuery, setPickerQuery] = useState("");
  const [pickerOpen, setPickerOpen] = useState(false);
  const [highlightIdx, setHighlightIdx] = useState(0);
  const pickerWrapRef = useRef<HTMLDivElement>(null);
  const pickerInputRef = useRef<HTMLInputElement>(null);

  // Close dropdown on outside click
  useEffect(() => {
    if (!pickerOpen) return;
    const onClick = (e: MouseEvent) => {
      if (pickerWrapRef.current && !pickerWrapRef.current.contains(e.target as Node)) {
        setPickerOpen(false);
      }
    };
    document.addEventListener("mousedown", onClick);
    return () => document.removeEventListener("mousedown", onClick);
  }, [pickerOpen]);

  useEffect(() => {
    loadStakeholdersSummary()
      .then(d => {
        setData(d);
        if (!scId && d.sol_cats?.length) {
          const first = d.sol_cats
            .slice()
            .sort((a, b) => a.display_name.localeCompare(b.display_name))[0];
          if (first) setScId(first.id);
        }
      })
      .catch(e => setError(String(e?.message || e)));
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const sortedSolCats = useMemo(() => {
    if (!data) return [];
    return (data.sol_cats || [])
      .slice()
      .sort((a, b) => a.display_name.localeCompare(b.display_name));
  }, [data]);

  const sc = sortedSolCats.find(s => s.id === scId);

  // Filter the dropdown by the user's query (case-insensitive substring on
  // display_name, vertical, or id). When closed, the input shows the
  // currently-picked sol-cat's name (read-only feel); when opened, the
  // input becomes a live filter.
  const filteredSolCats = useMemo(() => {
    return fuzzyFilter(sortedSolCats, pickerQuery, ["display_name", "vertical", "id"]);
  }, [sortedSolCats, pickerQuery]);

  // Reset highlight when filter changes
  useEffect(() => {
    setHighlightIdx(0);
  }, [pickerQuery, pickerOpen]);

  const pickSolCat = (id: string) => {
    setScId(id);
    setPickerOpen(false);
    setPickerQuery("");
  };

  const pickerInputValue = pickerOpen
    ? pickerQuery
    : sc
      ? sc.display_name
      : "";

  // Build all rows + verdicts for the picked sol cat.
  const { rows, modulesVerdict } = useMemo(() => {
    if (!data || !scId) return { rows: [], modulesVerdict: [] };
    return computeGapView(data, scId, modules);
  }, [data, scId, modules]);

  const visibleRows = useMemo(() => {
    return rows.filter(r => {
      if (filter === "mandatory") return r.sme_tier === "required" && r.in_checklist;
      if (filter === "mandatory_preferred")
        return (r.sme_tier === "required" || r.sme_tier === "preferred") && r.in_checklist;
      if (filter === "all") return true;
      if (filter === "failing") return !r.backed && r.in_checklist;
      return true;
    });
  }, [rows, filter]);

  // Map q_title → q_num for the chosen sol cat (for the Backing Q column).
  const qTitleToNum = useMemo(() => {
    const m: Record<string, string> = {};
    const qs: SolcatQuestion[] = data?.solcat_questions?.[scId] || [];
    for (const q of qs) m[q.q_title] = q.q_num;
    return m;
  }, [data, scId]);

  if (error) return <div className="dash-panel msg-error">Failed to load: {error}</div>;
  if (!data) return <div className="dash-panel msg-loading">Loading…</div>;

  return (
    <div className="dash-panel">
      <TabHelp hint="Default filter is Mandatory only — flip to All tiers to see Preferred / Advanced gaps too. ✓ rows are fully covered; ✗ rows highlight the missing caps.">
        Per-sol-cat IMDA Q ↔ canonical checklist gap. Pick a sol cat to see
        which IMDA questions back which canonical caps, and which IMDA Qs
        ask for things our cap library doesn't yet cover.
      </TabHelp>
      <div className="msg-picker-row">
        <label className="msg-picker-label" htmlFor="msg-picker-input">Sol cat</label>
        <div className="msg-picker-combo" ref={pickerWrapRef}>
          <input
            id="msg-picker-input"
            ref={pickerInputRef}
            type="text"
            className="msg-picker-input"
            role="combobox"
            aria-expanded={pickerOpen}
            aria-controls="msg-picker-listbox"
            aria-autocomplete="list"
            placeholder={sc ? "" : `Search ${sortedSolCats.length} sol cats…`}
            value={pickerInputValue}
            onFocus={() => {
              setPickerOpen(true);
              setPickerQuery("");
            }}
            onChange={e => {
              setPickerQuery(e.target.value);
              if (!pickerOpen) setPickerOpen(true);
            }}
            onKeyDown={e => {
              if (e.key === "ArrowDown") {
                e.preventDefault();
                if (!pickerOpen) setPickerOpen(true);
                setHighlightIdx(i => Math.min(i + 1, filteredSolCats.length - 1));
              } else if (e.key === "ArrowUp") {
                e.preventDefault();
                setHighlightIdx(i => Math.max(i - 1, 0));
              } else if (e.key === "Enter") {
                e.preventDefault();
                const pick = filteredSolCats[highlightIdx];
                if (pick) pickSolCat(pick.id);
              } else if (e.key === "Escape") {
                setPickerOpen(false);
                pickerInputRef.current?.blur();
              }
            }}
          />
          {sc && !pickerOpen && (
            <button
              type="button"
              className="msg-picker-clear"
              onClick={() => {
                setScId("");
                setPickerQuery("");
                pickerInputRef.current?.focus();
              }}
              aria-label="Clear sol cat"
              title="Clear"
            >
              ×
            </button>
          )}
          {pickerOpen && (
            <ul
              id="msg-picker-listbox"
              role="listbox"
              className="msg-picker-listbox"
            >
              {filteredSolCats.length === 0 ? (
                <li className="msg-picker-empty">No sol cats match "{pickerQuery}"</li>
              ) : (
                filteredSolCats.map((s, i) => (
                  <li
                    key={s.id}
                    role="option"
                    aria-selected={s.id === scId}
                    className={`msg-picker-option${i === highlightIdx ? " highlight" : ""}${s.id === scId ? " selected" : ""}`}
                    onMouseEnter={() => setHighlightIdx(i)}
                    onMouseDown={e => {
                      // Use mousedown so the click fires before the input's
                      // onBlur tears down the dropdown.
                      e.preventDefault();
                      pickSolCat(s.id);
                    }}
                  >
                    <span className="msg-picker-option-name">{s.display_name}</span>
                    <span className="msg-picker-option-meta">
                      {s.vertical}
                      {s.vertical_saas ? " · vertical SaaS" : ""}
                    </span>
                  </li>
                ))
              )}
            </ul>
          )}
        </div>
      </div>

      {!sc ? (
        <div className="msg-empty">Pick a sol cat to see the IMDA Qs ↔ canonical gap.</div>
      ) : (
        <>
          <header className="msg-head">
            <h3 className="msg-h3">{sc.display_name}</h3>
            <div className="msg-head-meta">
              <span><strong>{sc.vertical}</strong></span>
              <span>·</span>
              <span>Modules:</span>
              {(sc.modules || []).map(m => (
                <span key={m} className="msg-mod-chip">
                  {moduleShort(m, modules)}
                </span>
              ))}
              <span>·</span>
              <span>{sc.imda_req_count} IMDA reqs</span>
            </div>
          </header>

          <div className="msg-trust">
            <strong>Trust assumption (PSG approval baseline):</strong> every
            vendor on this sol cat's PSG list has been verified by IMDA against
            ALL mandatory Qs. Mandatory IMDA Qs are by-definition fulfilled by
            the listed vendors. This view checks our canonical checklist
            against IMDA's Q list — independent of vendor-website data.
          </div>

          <h4 className="msg-section-h">IMDA Qs ↔ canonical checklist gap</h4>
          <p className="msg-step">
            <strong>Step 1</strong> — does each IMDA Q from this sol cat get
            reflected in our canonical checklist? Does each cap in scope come
            from this sol cat's IMDA Qs, or did we expand beyond?
          </p>

          <VerdictPanel modulesVerdict={modulesVerdict} />

          <div className="msg-filter-row">
            <span className="msg-filter-label">Filters</span>
            {([
              ["mandatory", "Mandatory only"],
              ["mandatory_preferred", "+ Preferred"],
              ["all", "All rows"],
              ["failing", "Failing only"],
            ] as Array<[RowFilter, string]>).map(([key, label]) => (
              <button
                key={key}
                type="button"
                className={`msg-filter-pill${filter === key ? " active" : ""}`}
                onClick={() => setFilter(key)}
              >
                {label}
              </button>
            ))}
            <span className="msg-filter-count">
              {visibleRows.length} of {rows.length} rows
            </span>
          </div>

          <table className="msg-table">
            <thead>
              <tr>
                <th>Module</th>
                <th>Mod</th>
                <th>Sub-module</th>
                <th>Sub</th>
                <th>Cap</th>
                <th>Cap ✓</th>
                <th>Tier</th>
                <th>Backing Q</th>
                <th>Action</th>
              </tr>
            </thead>
            <tbody>
              {visibleRows.length === 0 ? (
                <tr>
                  <td colSpan={9} className="msg-empty-row">
                    <div className="msg-empty-state">
                      <div className="msg-empty-icon">○</div>
                      <div className="msg-empty-title">No rows match this filter</div>
                      <div className="msg-empty-hint">
                        {filter === "failing"
                          ? "All caps in scope are backed by an IMDA Q. Try 'All rows' to see them."
                          : "Widen the filter to '+ Preferred' or 'All rows'."}
                      </div>
                    </div>
                  </td>
                </tr>
              ) : (
                renderGroupedRows(visibleRows, modulesVerdict, modules, qTitleToNum)
              )}
            </tbody>
          </table>
        </>
      )}
    </div>
  );
}

// ──────────────────────────────────────────────────────────────────────

function moduleShort(slug: string, modules: ModuleEntry[]): string {
  const m = modules.find(x => x.slug === slug);
  return m ? (m.short || m.module_name || slug) : slug;
}

function VerdictPanel({ modulesVerdict }: { modulesVerdict: ModuleVerdict[] }) {
  const inScope = modulesVerdict.filter(m => m.status !== "N/A");
  const allPass = inScope.length > 0 && inScope.every(m => m.status === "PASS");
  const totalReq = inScope.reduce((n, m) => n + m.required_caps_total, 0);
  const totalBacked = inScope.reduce((n, m) => n + m.required_caps_backed, 0);
  const overallPct = totalReq > 0 ? Math.round((100 * totalBacked) / totalReq) : 0;
  return (
    <div className={`msg-verdict ${allPass ? "msg-verdict-pass" : "msg-verdict-mixed"}`}>
      <div className="msg-verdict-head">
        {allPass
          ? `✅ Sol cat fully covers Mandatory checklist (${totalBacked}/${totalReq} M caps backed)`
          : `⚠ ${totalBacked}/${totalReq} Mandatory caps backed across ${inScope.length} module${inScope.length === 1 ? "" : "s"} in scope (${overallPct}%)`}
      </div>
      <p className="msg-verdict-blurb">
        Per-module breakdown: how many of the module's Mandatory caps are
        backed by an IMDA Q from this sol cat (via canonical{" "}
        <code>imda_refs</code>). Each sub-module is "fully covered" only when
        every Mandatory cap inside it has a trace; gaps are listed explicitly.
      </p>
      <ul className="msg-verdict-list">
        {modulesVerdict.map(mv => (
          <li key={mv.slug} className={`msg-verdict-mod msg-verdict-${mv.status.toLowerCase()}`}>
            <strong>{mv.short}</strong>{" "}
            {mv.status === "N/A" ? (
              <em>— not in scope</em>
            ) : (
              <>
                <span className="msg-verdict-count">
                  {mv.required_caps_backed}/{mv.required_caps_total} M caps backed
                </span>
                {mv.passing_sub_modules.length > 0 && (
                  <div className="msg-verdict-sub">
                    ✓ fully covered:{" "}
                    <em>{mv.passing_sub_modules.map(s => s.sub_module_name).join(", ")}</em>
                  </div>
                )}
                {mv.failing_sub_modules.length > 0 && (
                  <div className="msg-verdict-sub msg-verdict-sub-fail">
                    ✗ gaps in:{" "}
                    {mv.failing_sub_modules.map((s, i) => (
                      <span key={s.sub_module_id}>
                        <em>{s.sub_module_name}</em>
                        <span className="msg-verdict-sub-frac">
                          {" "}({s.required_backed}/{s.required_total})
                        </span>
                        {i < mv.failing_sub_modules.length - 1 ? ", " : ""}
                      </span>
                    ))}
                  </div>
                )}
              </>
            )}
          </li>
        ))}
      </ul>
    </div>
  );
}

function renderGroupedRows(
  rows: CapGapRow[],
  modulesVerdict: ModuleVerdict[],
  modules: ModuleEntry[],
  qTitleToNum: Record<string, string>,
) {
  const verdictByMod = new Map(modulesVerdict.map(m => [m.slug, m] as const));
  // Group by module → sub-module.
  const byMod = new Map<string, Map<string, CapGapRow[]>>();
  for (const r of rows) {
    const m = byMod.get(r.module) || new Map<string, CapGapRow[]>();
    const sm = m.get(r.sub_module_id) || [];
    sm.push(r);
    m.set(r.sub_module_id, sm);
    byMod.set(r.module, m);
  }
  const out: ReactNode[] = [];
  for (const [modSlug, byMSM] of byMod) {
    const mv = verdictByMod.get(modSlug);
    let modRowSpanCounted = false;
    for (const [smId, capRows] of byMSM) {
      let subRowSpanCounted = false;
      const subVerdict = mv?.passing_sub_modules.find(s => s.sub_module_id === smId)
        || mv?.failing_sub_modules.find(s => s.sub_module_id === smId);
      for (const r of capRows) {
        const tier = (r.sme_tier as SmeTier | undefined) || "preferred";
        // Show q_num list (Q1, Q2, …) — looked up from solcat_questions.
        // Fall back to title abbreviation only if the lookup misses. Dedupe
        // — the source may carry the same q_title repeated when multiple
        // subreqs in the cap trace to the same IMDA question.
        const bckQs = r.backing_qs.length > 0
          ? Array.from(new Set(
              r.backing_qs.map(t => qTitleToNum[t] || abbreviateQ(t))
            )).join(", ")
          : "—";
        out.push(
          <tr key={`${modSlug}|${smId}|${r.cap_id}`} className="msg-row">
            <td>{!modRowSpanCounted ? moduleShort(modSlug, modules) : ""}</td>
            <td>{!modRowSpanCounted && mv && (
              <span className={`msg-mod-status msg-mod-status-${mv.status.toLowerCase()}`}>
                {mv.status === "PASS" ? "✅ PASS"
                  : mv.status === "PARTIAL" ? "△ PART"
                  : mv.status === "FAIL" ? "✗ FAIL"
                  : "—"}
              </span>
            )}</td>
            <td>{!subRowSpanCounted ? r.sub_module_name : ""}</td>
            <td>{!subRowSpanCounted && subVerdict && (
              <span className={`msg-sub-status ${subVerdict.fully_covered ? "ok" : "fail"}`}>
                {subVerdict.fully_covered ? "✅" : "✗"}
              </span>
            )}</td>
            <td className="msg-cap-cell">
              <Link
                to={`/canonical/${r.module}?cap=${encodeURIComponent(r.cap_id)}`}
                className="msg-cap-name"
                title={`Open ${r.cap_id} in the ${moduleShort(r.module, modules)} canonical view`}
              >
                {r.name}
              </Link>
              <code className="msg-cap-id">{r.cap_id}</code>
            </td>
            <td>
              <span className={`msg-cap-status ${r.backed ? "ok" : "fail"}`}>
                {r.backed ? "✅" : "✗"}
              </span>
            </td>
            <td>
              <span className={`tier-chip ${tierClass(tier)}`}>
                {TIER_SHORT[tier] || "—"}
              </span>
            </td>
            <td className="msg-backing-q">{bckQs}</td>
            <td>
              <span
                className={`msg-action ${r.backed ? "keep" : "retag"}`}
                title={r.backed
                  ? "No action needed — IMDA Q backs this cap"
                  : "Recommended action: demote the cap's tier or fix its IMDA Q trace via canonical"}
              >
                {r.backed ? "Keep" : "Demote / Re-tag"}
              </span>
            </td>
          </tr>
        );
        subRowSpanCounted = true;
        modRowSpanCounted = true;
      }
    }
  }
  return out;
}

function abbreviateQ(qTitle: string): string {
  // Compact Q identifier. If we recognise a Q### pattern, use it; otherwise
  // truncate the title to 30 chars.
  const m = qTitle.match(/^Q\d+/);
  if (m) return m[0];
  return qTitle.length > 30 ? qTitle.slice(0, 28) + "…" : qTitle;
}

// ──────────────────────────────────────────────────────────────────────
// Compute the gap view for a given sol cat
// ──────────────────────────────────────────────────────────────────────

function computeGapView(
  data: StakeholdersSummary,
  scId: string,
  modules: ModuleEntry[],
): { rows: CapGapRow[]; modulesVerdict: ModuleVerdict[] } {
  const capsIndex: CapEvidence[] = data.caps_index || [];
  const sc = (data.sol_cats || []).find(s => s.id === scId);

  // Per cap: which Q-titles back it via this sol cat?
  const backingQsByCap = new Map<string, string[]>();
  for (const c of capsIndex) {
    const qs: string[] = [];
    for (const ref of c.imda_refs || []) {
      if ((ref.sources || []).includes(scId)) qs.push(ref.q_title);
    }
    if (qs.length > 0) backingQsByCap.set(c.id, qs);
  }

  // Sub-modules that have ≥1 cap backed by this sol cat. We then expand
  // scope to include ALL caps in those sub-modules so the table shows the
  // full sub-module picture (backed + unbacked). Drives the verdict logic.
  const touchedSubModules = new Set<string>();
  for (const c of capsIndex) {
    if (backingQsByCap.has(c.id) && c.sub_module_id) {
      touchedSubModules.add(c.sub_module_id);
    }
  }
  // Sol cat's declared module scope (from the join's modules array).
  const declaredModules = new Set(sc?.modules || []);

  // Collect rows: every cap in a touched sub-module OR in a declared module.
  const rows: CapGapRow[] = [];
  for (const c of capsIndex) {
    const inTouched = c.sub_module_id ? touchedSubModules.has(c.sub_module_id) : false;
    const inDeclared = declaredModules.has(c.module);
    if (!inTouched && !inDeclared) continue;
    if (!c.sub_module_id) continue;  // skip baseline / cross-cutting caps without a sub-module
    const backingQs = backingQsByCap.get(c.id) || [];
    rows.push({
      cap_id: c.id,
      name: c.name,
      module: c.module,
      sub_module_id: c.sub_module_id || "",
      sub_module_name: c.sub_module_name || c.sub_module_id || "—",
      family: c.family || "",
      sme_tier: c.sme_tier || "",
      in_checklist: true,  // caps_index excludes deleted; we don't have in_checklist in CapEvidence
      backed: backingQs.length > 0,
      backing_qs: backingQs,
    });
  }
  // Sort: module → sub-module → backed first → tier order.
  rows.sort((a, b) => {
    if (a.module !== b.module) return a.module.localeCompare(b.module);
    if (a.sub_module_name !== b.sub_module_name)
      return a.sub_module_name.localeCompare(b.sub_module_name);
    if (a.backed !== b.backed) return a.backed ? -1 : 1;
    return a.name.localeCompare(b.name);
  });

  // Compute verdicts.
  const modulesVerdict: ModuleVerdict[] = [];
  for (const m of modules) {
    if (!declaredModules.has(m.slug) && !rows.some(r => r.module === m.slug)) continue;
    // Build sub-module verdicts within this module.
    const smRows = new Map<string, CapGapRow[]>();
    for (const r of rows) {
      if (r.module !== m.slug) continue;
      const arr = smRows.get(r.sub_module_id) || [];
      arr.push(r);
      smRows.set(r.sub_module_id, arr);
    }
    const passing: SubModuleVerdict[] = [];
    const failing: SubModuleVerdict[] = [];
    for (const [smId, arr] of smRows) {
      const reqRows = arr.filter(r => r.sme_tier === "required" && r.in_checklist);
      const reqTotal = reqRows.length;
      if (reqTotal === 0) continue;  // no R caps in this sub-module → ignore
      const reqBacked = reqRows.filter(r => r.backed).length;
      const fully = reqBacked === reqTotal;
      const verdict: SubModuleVerdict = {
        sub_module_id: smId,
        sub_module_name: arr[0].sub_module_name,
        family: arr[0].family,
        required_total: reqTotal,
        required_backed: reqBacked,
        fully_covered: fully,
      };
      if (fully) passing.push(verdict);
      else failing.push(verdict);
    }
    let status: ModuleVerdict["status"] = "N/A";
    if (passing.length === 0 && failing.length === 0) status = "N/A";
    else if (failing.length === 0) status = "PASS";
    else if (passing.length === 0) status = "FAIL";
    else status = "PARTIAL";
    // Module-wide R cap totals (sum across all sub-modules in scope).
    const reqTotal = passing.concat(failing).reduce((n, s) => n + s.required_total, 0);
    const reqBacked = passing.concat(failing).reduce((n, s) => n + s.required_backed, 0);
    modulesVerdict.push({
      slug: m.slug,
      short: m.short,
      module_id: m.module_id,
      status,
      passing_sub_modules: passing,
      failing_sub_modules: failing,
      required_caps_total: reqTotal,
      required_caps_backed: reqBacked,
    });
  }

  return { rows, modulesVerdict };
}
