/**
 * Centralised role-gating helpers.
 *
 * Two role surfaces in the SPA:
 *   - v1 (CF Worker): /api/me returns `{role: "admin"|"editor"|"viewer"}`
 *   - v2 (GitHub-native): AuthContext.user.app_role, same enum, derived from
 *     GitHub repo permissions + optional users.json override.
 *
 * Both converge on the same string values, so a single helper covers both.
 * The bridge build (VIEWER_ONLY) returns role=viewer via the api.me() stub,
 * so any consumer that calls `canEdit(role)` automatically gets the right
 * answer for read-only colleagues hitting the bridge URL.
 */

export type EditorRole = "admin" | "editor" | "viewer" | undefined;

/** True iff the role lets the user make edits (save drafts, reorder,
 *  add requirements, toggle AI features). */
export function canEdit(role: EditorRole): boolean {
  return role === "admin" || role === "editor";
}

/** True iff the role lets the user Publish drafts to main. */
export function canPublish(role: EditorRole): boolean {
  return role === "admin";
}

/** True iff the role grants admin-only surfaces (user management, etc.). */
export function isAdmin(role: EditorRole): boolean {
  return role === "admin";
}
