/**
 * v2 users-table reader.
 *
 * Repo collaborator permission is the AUTO source of truth for app_role:
 *   GH Admin             → "admin"
 *   GH Write / Maintain  → "editor"
 *   GH Read / Triage     → "viewer"
 *
 * `data/_state/users.json` is OPTIONAL — only needed for:
 *   1. OVERRIDING the auto-derived role (e.g. a GH writer who shouldn't
 *      be able to Publish; downgrade them to "viewer" via this file).
 *   2. SCOPING `visible_modules` per user — that can't come from GitHub
 *      and only matters if you want a colleague to see a subset of modules.
 *
 * Schema (matches `data/_state/users.json`):
 *
 *   {
 *     "_meta": { ... },
 *     "users": [
 *       { "github_username": "alice",
 *         "email": "a@example.com",            // optional
 *         "role": "admin" | "editor" | "viewer",  // optional — omit to use GH default
 *         "visible_modules": null | ["financial_management", ...],
 *         "note": "..." }
 *     ]
 *   }
 *
 * Anyone signed in with repo access automatically gets a role — they never
 * 401 because of this file. The file's _meta.default_role_for_unknown_users
 * is kept for backward compat but is now an emergency override (only fires
 * if GH permissions return nothing useful, which shouldn't happen).
 */
import { getFileJson, GitHubApiError, type GitHubAuth } from "./githubClient";

export type AppRole = "admin" | "editor" | "viewer";

export interface UserEntry {
  github_username: string;
  email?: string;
  role: AppRole;
  visible_modules?: string[] | null;
  note?: string;
}

export interface UsersTable {
  _meta: {
    description?: string;
    schema_version?: number;
    default_role_for_unknown_users?: AppRole;
  };
  users: UserEntry[];
}

const USERS_TABLE_PATH = "data/_state/users.json";
const DEFAULT_ROLE: AppRole = "viewer";

function isAppRole(v: unknown): v is AppRole {
  return v === "admin" || v === "editor" || v === "viewer";
}

let _cache: UsersTable | null = null;

/** Load the users table from main. Cached for the session — sign-out
 *  clears via clearUsersTableCache(). */
export async function loadUsersTable(auth: GitHubAuth): Promise<UsersTable> {
  if (_cache) return _cache;
  try {
    const data = await getFileJson<UsersTable>(auth, USERS_TABLE_PATH);
    _cache = data;
    return data;
  } catch (e) {
    if (e instanceof GitHubApiError && e.isNotFound) {
      // First-deploy / bootstrap state — file doesn't exist yet. Return an
      // empty table; every signed-in user will get the default role.
      const empty: UsersTable = {
        _meta: { default_role_for_unknown_users: DEFAULT_ROLE },
        users: [],
      };
      _cache = empty;
      return empty;
    }
    throw e;
  }
}

export function clearUsersTableCache(): void {
  _cache = null;
}

export interface ResolvedUserProfile {
  role: AppRole;
  /** null = all modules visible. */
  visible_modules: string[] | null;
  /** Whether the user appears in users.json explicitly. False = role came
   *  from the GitHub-derived auto-mapping (or a fallback). */
  is_known: boolean;
}

/** GitHub repo permissions the SPA derives an app_role from. */
export interface GhPermissions {
  admin: boolean;
  push: boolean;
  pull: boolean;
}

/** Map GitHub repo permissions to the SPA's app_role.
 *  Admin → admin; Maintain/Write → editor; Triage/Read → viewer. */
function roleFromGhPermissions(p: GhPermissions): AppRole {
  if (p.admin) return "admin";
  if (p.push) return "editor"; // covers Maintain + Write
  if (p.pull) return "viewer"; // covers Triage + Read
  return DEFAULT_ROLE;
}

/**
 * Resolve a user's role + module visibility.
 *
 * Priority order:
 *   1. Explicit users.json entry — if the user is listed AND has a `role`
 *      field, use that. Also use their `visible_modules`. This is the
 *      override path.
 *   2. GitHub permissions — auto-mapped via roleFromGhPermissions.
 *      `visible_modules` defaults to null (all modules).
 *   3. _meta.default_role_for_unknown_users — emergency fallback.
 */
export function resolveUserProfile(
  table: UsersTable,
  githubUsername: string,
  ghPermissions?: GhPermissions,
): ResolvedUserProfile {
  const entry = table.users.find(u => u.github_username === githubUsername);
  if (entry) {
    // Explicit entry. `role` field is optional now — if absent, fall through
    // to GH-derived role but keep `visible_modules` if set.
    const explicitRole = isAppRole(entry.role) ? entry.role : null;
    const role = explicitRole
      ?? (ghPermissions ? roleFromGhPermissions(ghPermissions) : DEFAULT_ROLE);
    return {
      role,
      visible_modules: Array.isArray(entry.visible_modules) ? entry.visible_modules : null,
      is_known: true,
    };
  }
  // No explicit entry — derive from GitHub permissions.
  if (ghPermissions) {
    return {
      role: roleFromGhPermissions(ghPermissions),
      visible_modules: null,
      is_known: false,
    };
  }
  // No GH permissions handy either (shouldn't happen in normal sign-in).
  const fallback = isAppRole(table._meta?.default_role_for_unknown_users)
    ? table._meta!.default_role_for_unknown_users!
    : DEFAULT_ROLE;
  return { role: fallback, visible_modules: null, is_known: false };
}
