/**
 * Canonical module list — declaration order matches scripts/_nav.py's
 * NAV_SHORT_NAMES so the SPA nav and the legacy HTML nav stay in sync.
 *
 * Keep this single source: NavBar, Home, and any other surface that
 * needs the per-module loop pulls from here, not from a duplicate
 * inline array.
 */

export interface ModuleEntry {
  slug: string;
  /** Display name in nav / dashboards (short form). */
  short: string;
  /** Full module name for headings / breadcrumbs. */
  full: string;
}

// Ordered by IMDA-style module_id (100..1000). User decision 2026-05-08:
// the four priority modules — Financial / Sales / Supply Chain / HR — are
// 100/200/300/400. Source of truth is _MODULE_IDS in
// scripts/build_canonical_viewer.py — keep this order in sync.
export const MODULES: readonly ModuleEntry[] = [
  { slug: "financial_management",        short: "Financial",     full: "Financial Management" },         // 100
  { slug: "sales_and_crm",               short: "Sales & CRM",   full: "Sales & CRM" },                  // 200
  { slug: "supply_chain_and_inventory",  short: "Supply Chain",  full: "Supply Chain & Inventory" },     // 300
  { slug: "human_resources_management",  short: "HR",            full: "Human Resources" },              // 400
  { slug: "manufacturing_management",    short: "Manufacturing", full: "Manufacturing" },                // 500
  { slug: "asset_management",            short: "Asset Mgmt",    full: "Asset Management" },             // 600
  { slug: "field_service_management",    short: "Field Service", full: "Field Service" },                // 700
  { slug: "fleet_management",            short: "Fleet",         full: "Fleet Management" },             // 800
  { slug: "project_management",          short: "Project Mgmt",  full: "Project Management" },           // 900
  { slug: "others",                      short: "Other",         full: "Others / Cross-cutting" },       // 1000
];

export const MODULE_SLUGS: ReadonlySet<string> = new Set(MODULES.map(m => m.slug));

/** IMDA Type 2 umbrella-question helper.
 *
 * Format from docs/imda_checklist_formats.md Document 2:
 *   "Does your <module> module provide the following functions?"
 *
 * Multi-umbrella cases weave the umbrella name in for clarity:
 *   "Does your asset management module provide the following
 *    compliance, inspection & analytics functions?"
 *
 * Returns null when the module slug isn't known — caller falls back
 * to no question line (Type2Umbrella renders without it). */
export function umbrellaQuestionFor(slug: string, umbrellaName?: string): string | null {
  // Module-specific noun. Distinct from `short` and `full` because both
  // read awkwardly in the question ("Does your Asset Mgmt module…" /
  // "Does your Human Resources module…"). Lowercased + grammar-clean.
  const noun: Record<string, string> = {
    financial_management: "finance",
    sales_and_crm: "sales & CRM",
    supply_chain_and_inventory: "supply chain",
    human_resources_management: "HR",
    manufacturing_management: "manufacturing",
    asset_management: "asset management",
    field_service_management: "field service",
    fleet_management: "fleet management",
    project_management: "project management",
    others: "platform & data",
  };
  const n = noun[slug];
  if (!n) return null;
  // Single-umbrella tiers (umbrellaName="all" / unspecified) → omit.
  if (!umbrellaName || /^(all|preferred|advanced|core)$/i.test(umbrellaName.trim())) {
    return `Does your ${n} module provide the following functions?`;
  }
  // Multi-umbrella: lowercase the umbrella name's first char so e.g.
  // "Compliance, inspection & analytics" → "compliance, inspection & analytics".
  const u = umbrellaName.charAt(0).toLowerCase() + umbrellaName.slice(1);
  return `Does your ${n} module provide the following ${u} functions?`;
}
