import { useEffect, useMemo, useState } from "react";
import { Link } from "react-router-dom";
import { api, type Me, type UserRole, type UserRow } from "../lib/api";
import { TabHelp } from "../components/TabHelp";
import "./AdminUsersPage.css";

const ROLE_DESC: Record<UserRole, string> = {
  admin:  "Full access: can publish, manage users",
  editor: "Save / clear drafts; cannot publish",
  viewer: "Read-only: drafts + audit log",
};

/**
 * Admin-only page at /admin/users. Lists everyone in the D1 users table,
 * lets the signed-in admin promote/demote, add new emails, and remove
 * rows (which falls them back to DEFAULT_ROLE = 'editor').
 *
 * Server enforces admin gating on every /api/users call. The UI just
 * hides itself for non-admins as a UX shortcut.
 */
export function AdminUsersPage() {
  const [me, setMe] = useState<Me | null>(null);
  const [users, setUsers] = useState<UserRow[] | null>(null);
  const [defaultRole, setDefaultRole] = useState<UserRole>("editor");
  const [error, setError] = useState<string | null>(null);
  const [busyEmail, setBusyEmail] = useState<string | null>(null);
  const [newEmail, setNewEmail] = useState("");
  const [newRole, setNewRole] = useState<UserRole>("editor");
  const [newName, setNewName] = useState("");
  const [flash, setFlash] = useState<string | null>(null);

  const refresh = async () => {
    setError(null);
    try {
      const r = await api.listUsers();
      setUsers(r.users);
      setDefaultRole(r.default_role);
    } catch (e) {
      setError(e instanceof Error ? e.message : String(e));
    }
  };

  useEffect(() => {
    api.me().then(setMe).catch(() => setMe(null));
    refresh();
  }, []);

  const sortedUsers = useMemo(() => {
    if (!users) return [];
    const order: Record<UserRole, number> = { admin: 0, editor: 1, viewer: 2 };
    return users.slice().sort((a, b) => {
      if (order[a.role] !== order[b.role]) return order[a.role] - order[b.role];
      return a.email.localeCompare(b.email);
    });
  }, [users]);

  const flashFor = (msg: string) => {
    setFlash(msg);
    setTimeout(() => setFlash(null), 3000);
  };

  const handleRoleChange = async (email: string, role: UserRole) => {
    setBusyEmail(email);
    setError(null);
    try {
      await api.setUserRole(email, role);
      flashFor(`${email} → ${role}`);
      await refresh();
    } catch (e) {
      setError(e instanceof Error ? e.message : String(e));
    } finally {
      setBusyEmail(null);
    }
  };

  const handleRemove = async (email: string) => {
    if (!window.confirm(`Remove ${email} from the users table?\n\nThey will fall back to the default role (${defaultRole}) on next sign-in. This is reversible — promote/demote them again any time.`)) return;
    setBusyEmail(email);
    setError(null);
    try {
      await api.removeUser(email);
      flashFor(`${email} removed`);
      await refresh();
    } catch (e) {
      setError(e instanceof Error ? e.message : String(e));
    } finally {
      setBusyEmail(null);
    }
  };

  const handleAdd = async (e: React.FormEvent) => {
    e.preventDefault();
    const email = newEmail.trim().toLowerCase();
    if (!email) return;
    if (!email.includes("@")) {
      setError("Please enter a valid email");
      return;
    }
    setBusyEmail(email);
    setError(null);
    try {
      await api.setUserRole(email, newRole, newName.trim() || null);
      flashFor(`Added ${email} as ${newRole}`);
      setNewEmail("");
      setNewName("");
      setNewRole("editor");
      await refresh();
    } catch (e) {
      setError(e instanceof Error ? e.message : String(e));
    } finally {
      setBusyEmail(null);
    }
  };

  // Soft gate — server is the real gate, this just shows a friendly message.
  if (me && me.role !== "admin") {
    return (
      <section className="admin-page">
        <header className="admin-header">
          <h1>Admin · Users</h1>
        </header>
        <div className="admin-deny">
          <h2>You're signed in as <code>{me.role}</code></h2>
          <p>Only admins can manage user access. Ask an admin to promote you.</p>
          <Link to="/" className="admin-back">← back to Home</Link>
        </div>
      </section>
    );
  }

  return (
    <section className="admin-page">
      <header className="admin-header">
        <span className="admin-eyebrow">Admin</span>
        <h1>User access</h1>
      </header>
      <TabHelp hint={`Server enforces admin gating on every /api/users call — this UI is the convenient front door. Unknown emails default to ${defaultRole}.`}>
        Manage who can edit drafts, publish to GitHub, or just read. Role
        hierarchy: <strong>admin</strong> &gt; <strong>editor</strong> &gt; <strong>viewer</strong>.
      </TabHelp>

      <table className="admin-roles-table">
        <thead>
          <tr>
            <th>Role</th>
            <th>What it can do</th>
          </tr>
        </thead>
        <tbody>
          {(Object.keys(ROLE_DESC) as UserRole[]).map(r => (
            <tr key={r}>
              <td><span className={`admin-role admin-role-${r}`}>{r}</span></td>
              <td>{ROLE_DESC[r]}</td>
            </tr>
          ))}
        </tbody>
      </table>

      {error && (
        <div className="admin-error">Error: {error}</div>
      )}
      {flash && (
        <div className="admin-flash">{flash}</div>
      )}

      <h2 className="admin-section-h">Add a user</h2>
      <form className="admin-add-form" onSubmit={handleAdd}>
        <input
          type="email"
          required
          placeholder="email@example.com"
          value={newEmail}
          onChange={e => setNewEmail(e.target.value)}
          className="admin-input admin-input-email"
        />
        <input
          type="text"
          placeholder="Display name (optional)"
          value={newName}
          onChange={e => setNewName(e.target.value)}
          className="admin-input admin-input-name"
        />
        <select
          value={newRole}
          onChange={e => setNewRole(e.target.value as UserRole)}
          className="admin-input admin-input-role"
        >
          <option value="admin">admin</option>
          <option value="editor">editor</option>
          <option value="viewer">viewer</option>
        </select>
        <button type="submit" className="admin-btn-primary" disabled={!!busyEmail}>
          Add / Update
        </button>
      </form>

      <h2 className="admin-section-h">Current users</h2>
      {users === null ? (
        <p className="muted">Loading…</p>
      ) : users.length === 0 ? (
        <p className="muted">No users in the table yet.</p>
      ) : (
        <table className="admin-users-table">
          <thead>
            <tr>
              <th>Email</th>
              <th>Display name</th>
              <th>Role</th>
              <th>Updated</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {sortedUsers.map(u => {
              const isMe = !!(me && u.email === me.email);
              return (
                <tr key={u.email}>
                  <td>
                    <code>{u.email}</code>
                    {isMe && <span className="admin-self-tag">you</span>}
                  </td>
                  <td>{u.display_name || <span className="muted">—</span>}</td>
                  <td>
                    <select
                      value={u.role}
                      onChange={e => handleRoleChange(u.email, e.target.value as UserRole)}
                      disabled={busyEmail === u.email || isMe}
                      className={`admin-role admin-role-${u.role}`}
                      title={isMe ? "Can't change your own role" : ""}
                    >
                      <option value="admin">admin</option>
                      <option value="editor">editor</option>
                      <option value="viewer">viewer</option>
                    </select>
                  </td>
                  <td className="muted small">{formatDate(u.updated_at)}</td>
                  <td>
                    <button
                      type="button"
                      className="admin-btn-danger"
                      onClick={() => handleRemove(u.email)}
                      disabled={busyEmail === u.email || isMe}
                      title={isMe ? "Can't remove yourself" : "Remove from users table (falls back to default role)"}
                    >
                      Remove
                    </button>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      )}

      <p className="admin-footnote muted small">
        Removing a user just deletes the explicit role row — they'll fall
        back to <strong>{defaultRole}</strong> next sign-in (still able to
        log in via Cloudflare Access). To block sign-in entirely, manage
        the CF Access policy.
      </p>
    </section>
  );
}

function formatDate(iso: string): string {
  try {
    const d = new Date(iso);
    if (Number.isNaN(d.getTime())) return iso;
    return d.toISOString().slice(0, 16).replace("T", " ");
  } catch {
    return iso;
  }
}
