/**
 * Adjustable base profile for the Pricing Check panel.
 *
 * The backend (scripts/build_vendor_pricing_summary.py) normalises every
 * vendor's quoted price to one canonical baseline so the SPA can compare
 * apples to apples. The baseline today: 10-user, monthly, SGD,
 * USD→SGD = 1.35, one-time costs amortised as 20%/yr maintenance + 12mo.
 *
 * Users want to pivot that baseline without re-running the backend
 * (e.g. "how does this look if I assume 5 users instead?"). This module
 * lets the panel rescale the backend's normalised numbers using cheap,
 * deterministic math — no extra round-trips.
 *
 * Profile fields:
 *   - pax: target user count (1 / 5 / 10 / 25 / 50)
 *   - currency: SGD or USD display
 *   - period: monthly / annual / 3yr_tco (3-year total cost of ownership)
 *   - components: which cost lines to roll up (sw_only / sw_ps / sw_ps_tr)
 *
 * Note: rescaling pax from the backend's 10-user baseline is approximate.
 *   - Per-user pricing models (per_user_month, per_user_year) scale linearly.
 *   - Flat / one-time / bundled-PSG pricing models DON'T scale with pax
 *     — but the backend already collapsed those into the same normalised
 *     SGD/month number, so we can't recover the original unit reliably.
 *     For accurate pax rescaling, the row's `base_price_label` field exposes
 *     the original unit; if it says "per user" we scale, else we display
 *     "fixed (does not scale with pax)" and use the unscaled number.
 */

import { useState, useCallback } from "react";

export type PricingPax = 1 | 5 | 10 | 25 | 50;
export type PricingCurrency = "SGD" | "USD";
export type PricingPeriod = "monthly" | "annual" | "3yr_tco";
export type PricingComponents = "sw_only" | "sw_ps" | "sw_ps_tr";

export interface PricingProfile {
  pax: PricingPax;
  currency: PricingCurrency;
  period: PricingPeriod;
  components: PricingComponents;
}

export const DEFAULT_PROFILE: PricingProfile = {
  pax: 10,           // matches the backend's USER_BASELINE
  currency: "SGD",
  period: "annual",
  // Software-only is the cleanest comparison basis. PS + training are
  // one-time + vary wildly by vendor — including them by default skews
  // cross-vendor comparisons. Users can opt in via the Components pills.
  components: "sw_only",
};

/** SGD → USD conversion. Backend stores everything in SGD. */
const SGD_TO_USD = 1 / 1.35;

/** Backend baseline (must match build_vendor_pricing_summary.py constants). */
export const BACKEND_BASELINE = {
  pax: 10,
  currency: "SGD" as const,
};

export interface RescaleResult {
  /** Final number to display, in the chosen currency + period. */
  value: number | null;
  /** Human-readable label (e.g. "scaled from 10 to 5 pax"). */
  label: string;
  /** True iff the rescale assumed per-user scaling — flag in UI when
   *  the underlying unit was actually flat / bundled. */
  scaled: boolean;
  /** Original baseline value in SGD/month (for tooltips/debugging). */
  baseline_sgd_month: number | null;
}

/** Rescale a normalised SGD/month number into the active profile.
 *
 * @param baselineSgdMonth backend's normalised value (10-user SGD/month)
 * @param baseLabel        backend's `base_price_label` (e.g. "9 USD/u/mo × 10 users")
 *                         used to detect whether the original unit was per-user
 * @param profile          active SPA profile
 */
export function rescale(
  baselineSgdMonth: number | null | undefined,
  baseLabel: string | null | undefined,
  profile: PricingProfile,
): RescaleResult {
  if (baselineSgdMonth == null) {
    return { value: null, label: "—", scaled: false, baseline_sgd_month: null };
  }
  // Detect per-user scaling from the backend's source label.
  const perUser = !!baseLabel && /\/u\/(mo|yr)/i.test(baseLabel);
  let sgdMonth = baselineSgdMonth;
  if (perUser && profile.pax !== BACKEND_BASELINE.pax) {
    sgdMonth = baselineSgdMonth * (profile.pax / BACKEND_BASELINE.pax);
  }
  // Period
  const monthsByPeriod: Record<PricingPeriod, number> = {
    monthly: 1,
    annual: 12,
    "3yr_tco": 36,
  };
  let value = sgdMonth * monthsByPeriod[profile.period];
  // Currency
  if (profile.currency === "USD") value = value * SGD_TO_USD;
  // Label
  const labelParts: string[] = [];
  if (perUser && profile.pax !== BACKEND_BASELINE.pax) {
    labelParts.push(`scaled ${BACKEND_BASELINE.pax}→${profile.pax} pax`);
  } else if (!perUser) {
    labelParts.push("fixed (not per-pax)");
  }
  return {
    value,
    label: labelParts.join(" · "),
    scaled: perUser && profile.pax !== BACKEND_BASELINE.pax,
    baseline_sgd_month: baselineSgdMonth,
  };
}

/** Apply the chosen components filter to a Year-1 breakdown.
 *  Returns the subset total. When components = "sw_only", returns just
 *  the software component; when "sw_ps", software + PS; etc. */
export function applyComponents(
  breakdown: {
    software_year_sgd?: number | null;
    ps_one_time_sgd?: number | null;
    training_one_time_sgd?: number | null;
    bundled?: boolean;
  } | undefined,
  total: number | null | undefined,
  components: PricingComponents,
): number | null {
  if (total == null) return null;
  // Bundled PSG totals can't be unbundled — return the bundled number as-is.
  if (breakdown?.bundled) return total;
  const sw = breakdown?.software_year_sgd ?? null;
  const ps = breakdown?.ps_one_time_sgd ?? null;
  const tr = breakdown?.training_one_time_sgd ?? null;
  if (components === "sw_only") return sw;
  if (components === "sw_ps") return (sw || 0) + (ps || 0);
  return (sw || 0) + (ps || 0) + (tr || 0);
}

export function formatPriceForDisplay(
  value: number | null,
  profile: PricingProfile,
): string {
  if (value == null) return "—";
  const sym = profile.currency === "SGD" ? "S$" : "US$";
  const rounded = Math.round(value);
  return `${sym}${rounded.toLocaleString()}`;
}

/** Hook — local profile state. Components that want URL-backing should
 *  use useUrlParam directly for each field. */
export function usePricingProfile(
  initial: Partial<PricingProfile> = {},
): [PricingProfile, (patch: Partial<PricingProfile>) => void] {
  const [profile, setProfile] = useState<PricingProfile>({
    ...DEFAULT_PROFILE,
    ...initial,
  });
  const update = useCallback((patch: Partial<PricingProfile>) => {
    setProfile(prev => ({ ...prev, ...patch }));
  }, []);
  return [profile, update];
}

export const PERIOD_LABEL: Record<PricingPeriod, string> = {
  monthly: "Monthly",
  annual: "Annual",
  "3yr_tco": "3-yr TCO",
};

export const COMPONENT_LABEL: Record<PricingComponents, string> = {
  sw_only: "Software only",
  sw_ps: "+ Professional services",
  sw_ps_tr: "+ PS + Training",
};
