/**
 * AI Features umbrella — IMDA module-tail row of every checklist.
 *
 * Persistence: D1 via the cap-edit-api Worker's `/api/module-state` with
 * state_key `ai_features_response` (whitelisted + audit-logged). Reviewer
 * state goes through ModuleStateContext, NOT localStorage — see memory
 * feedback_checklist_audit_logging.md for the rule.
 *
 * This module owns:
 *   - Static-data types (umbrella question + per-module example list).
 *   - The fetch+cache for /ai_features.json (built from config/ai_features.yaml
 *     by scripts/build_ai_features_json.py).
 *
 * Reviewer-response state lives in ModuleStateContext (AiFeaturesResponseValue).
 */

export interface AiFeatureExample {
  title: string;
  description: string;
}

export interface AiFeaturesPayload {
  umbrella_question: string;
  modules: Record<string, { examples: AiFeatureExample[] }>;
}

// The reviewer's response to the AI Features umbrella for a single module.
// Persisted via ModuleStateContext (D1 module_state.ai_features_response,
// audit-logged on every save). Pure data type so the component and the
// context provider can both reference one source.
export interface AiFeaturesResponse {
  checkedTitles: string[];
  othersText: string;
}

export function emptyAiFeaturesResponse(): AiFeaturesResponse {
  return { checkedTitles: [], othersText: "" };
}

// Memoised fetch of the global ai_features.json built by
// scripts/build_ai_features_json.py and served as a static asset.
let _cache: AiFeaturesPayload | null = null;
let _inflight: Promise<AiFeaturesPayload> | null = null;

export async function loadAiFeatures(): Promise<AiFeaturesPayload> {
  if (_cache) return _cache;
  if (_inflight) return _inflight;
  _inflight = fetch(`${import.meta.env.BASE_URL}ai_features.json`, { credentials: "same-origin" })
    .then(res => {
      if (!res.ok) throw new Error(`ai_features fetch failed: ${res.status}`);
      return res.json() as Promise<AiFeaturesPayload>;
    })
    .then(payload => {
      _cache = payload;
      _inflight = null;
      return payload;
    })
    .catch(e => {
      _inflight = null;
      throw e;
    });
  return _inflight;
}

// Test-only: reset the in-process cache so loadAiFeatures() refetches.
export function _resetAiFeaturesCache(): void {
  _cache = null;
  _inflight = null;
}
