import { useEffect, useState, type ReactNode } from "react";
import { useDrafts } from "../contexts/DraftsContext";
import { api, type UserRole } from "../lib/api";
import { GITHUB_NATIVE, useAuth } from "../contexts/AuthContext";
import { preflightPublishConflicts, type OverwriteConflict } from "../lib/publish";
import "./PublishButton.css";

/**
 * Floating bottom-right button: hidden when there are no drafts to publish.
 * Click → 2-step modal:
 *   Step 1: review list of pending drafts (cap_id + author + when)
 *   Step 2: confirm — repo / branch / aggregate counts
 *   Confirm → POST /api/publish; on success drafts drain server-side and
 *   the local cache empties via the context.
 */
type Step = "review" | "preflight" | "conflicts" | "confirm" | "running" | "done" | "error";

export function PublishButton() {
  const { draftsByCap, moduleStatePendingCount, publish } = useDrafts();
  const { user: ghUser, auth: ghAuth } = useAuth();
  const [open, setOpen] = useState(false);
  const [step, setStep] = useState<Step>("review");
  const [error, setError] = useState<string | null>(null);
  const [result, setResult] = useState<{ applied: number; commit_url?: string } | null>(null);
  const [role, setRole] = useState<UserRole | null>(null);
  const [conflicts, setConflicts] = useState<OverwriteConflict[]>([]);

  useEffect(() => {
    if (GITHUB_NATIVE) {
      // v2 uses AuthContext role. Mapped from app_role; only admins publish.
      setRole((ghUser?.app_role as UserRole | undefined) ?? null);
      return;
    }
    api.me()
      .then(me => setRole(me.role || "editor"))
      .catch(() => setRole("editor"));
  }, [ghUser]);

  const drafts = Array.from(draftsByCap.values()).sort((a, b) => {
    return (b.updated_at || "").localeCompare(a.updated_at || "");
  });
  const capDraftCount = drafts.length;
  // The Publish button needs to surface for BOTH cap-level drafts AND
  // module-state changes (cap_order overrides + ai_features responses).
  // Hiding when only module-state is pending was the bug that made users
  // unable to publish a reorder-only or AI-features-only change.
  const total = capDraftCount + moduleStatePendingCount;
  if (total === 0) return null;
  // Non-admins still see drafts in Pending edits + can save them, but the
  // Publish button is hidden so they don't push to main without rights.
  if (role !== "admin") return null;

  const close = () => {
    setOpen(false);
    setStep("review");
    setError(null);
    setResult(null);
    setConflicts([]);
  };

  // v2: between Review and Confirm, run a preflight check for overwrite
  // conflicts on reorder + AI-features files. v1 skips this (the CF Worker
  // handled concurrency server-side).
  const handleReviewNext = async () => {
    if (!GITHUB_NATIVE || !ghAuth || !ghUser) {
      setStep("confirm");
      return;
    }
    setStep("preflight");
    setError(null);
    try {
      const found = await preflightPublishConflicts(ghAuth, ghUser.login);
      setConflicts(found);
      if (found.length > 0) {
        setStep("conflicts");
      } else {
        setStep("confirm");
      }
    } catch (e: unknown) {
      setError(e instanceof Error ? e.message : String(e));
      setStep("error");
    }
  };

  const handleConfirm = async () => {
    setStep("running");
    setError(null);
    try {
      const r = await publish();
      if (r.ok) {
        setResult({ applied: r.applied, commit_url: r.commit_url });
        setStep("done");
      } else {
        setError(r.message || "Publish returned no-op.");
        setStep("error");
      }
    } catch (e: unknown) {
      setError(e instanceof Error ? e.message : String(e));
      setStep("error");
    }
  };

  const fieldList = (fields: Record<string, unknown>): ReactNode[] =>
    Object.keys(fields).map(k => <code key={k}>{k}</code>).reduce((acc, el, i) => {
      return acc.concat(i > 0 ? [" ", el] : [el]);
    }, [] as ReactNode[]);

  return (
    <>
      <button
        className="publish-fab"
        onClick={() => setOpen(true)}
        title="Publish all drafts to data/manual_cap_overrides.yaml"
      >
        Publish <span className="publish-fab-count">{total}</span> draft{total === 1 ? "" : "s"} → repo
      </button>

      {open && (
        <div className="publish-modal-spa" role="dialog" aria-modal="true">
          <div className="publish-modal-inner">
            <div className="publish-modal-head">
              <h3>
                {step === "review" && `Publish ${total} draft${total === 1 ? "" : "s"} to repo`}
                {step === "preflight" && "Checking for conflicts…"}
                {step === "conflicts" && `Conflict warning — ${conflicts.length} file${conflicts.length === 1 ? "" : "s"} recently changed by others`}
                {step === "confirm" && "Confirm publish"}
                {step === "running" && "Publishing…"}
                {step === "done" && "Published ✓"}
                {step === "error" && "Publish failed"}
              </h3>
              <button className="publish-modal-close" onClick={close}>×</button>
            </div>

            <div className="publish-modal-body">
              {step === "review" && (
                <>
                  <p className="publish-help">
                    Review the changes below. Clicking <b>Publish</b> commits them to
                    {" "}<code>data/manual_cap_overrides.yaml</code> and triggers the
                    rebuild workflow.
                  </p>
                  <table className="publish-table">
                    <thead>
                      <tr>
                        <th>Cap</th><th>Fields</th><th>Author</th>
                      </tr>
                    </thead>
                    <tbody>
                      {drafts.map(d => (
                        <tr key={`${d.module}:${d.cap_id}`}>
                          <td><code>{d.cap_id}</code></td>
                          <td className="pub-fields">{fieldList(d.fields as Record<string, unknown>)}</td>
                          <td className="pub-author">{shortAuthor(d.author?.email)}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                  <div className="publish-actions">
                    <button className="publish-btn-primary" onClick={handleReviewNext}>
                      Publish to repo →
                    </button>
                    <button className="publish-btn-cancel" onClick={close}>Cancel</button>
                  </div>
                </>
              )}

              {step === "preflight" && (
                <p className="publish-running">
                  Checking whether anyone else has touched the files you're about to overwrite…
                </p>
              )}

              {step === "conflicts" && (
                <>
                  <p className="publish-help">
                    The files below were modified on <code>main</code> after the most
                    recent change you'd be overwriting. <b>Your publish will replace
                    their work for these files.</b> Review carefully before continuing.
                  </p>
                  <ul className="publish-conflict-list">
                    {conflicts.map(c => (
                      <li key={c.file} className="publish-conflict-item">
                        <code className="publish-conflict-file">{c.file}</code>
                        <span className="publish-conflict-meta">
                          last edited by <b>@{c.last_commit_author_login}</b>
                          {" "}at {new Date(c.last_commit_at).toLocaleString()}
                          {" "}·{" "}
                          <a href={c.last_commit_url} target="_blank" rel="noopener noreferrer">
                            view commit ↗
                          </a>
                        </span>
                      </li>
                    ))}
                  </ul>
                  <p className="publish-confirm-warn">
                    Cap-field edits compose safely — they're not affected by this warning.
                    Only the listed <i>overwrite</i> files would clobber other users' work.
                  </p>
                  <div className="publish-actions">
                    <button className="publish-btn-confirm" onClick={() => setStep("confirm")}>
                      I understand — continue
                    </button>
                    <button className="publish-btn-cancel" onClick={close}>
                      Cancel
                    </button>
                  </div>
                </>
              )}

              {step === "confirm" && (
                <>
                  <p>You're about to commit <b>{total}</b> draft{total === 1 ? "" : "s"} to:</p>
                  <ul className="publish-confirm-target">
                    <li>Repo: <code>jersgcodes/erp-mapper</code></li>
                    <li>File: <code>data/manual_cap_overrides.yaml</code></li>
                    <li>Branch: <code>main</code></li>
                  </ul>
                  <p className="publish-confirm-warn">
                    This commits to <b>main</b> and dispatches the
                    {" "}<code>apply-published-overrides</code> workflow. The rebuild
                    auto-deploys to <code>mapper.jersgcodes.com</code> in ~1-2 min.
                  </p>
                  <div className="publish-actions">
                    <button className="publish-btn-confirm" onClick={handleConfirm}>
                      Yes, publish to repo
                    </button>
                    <button className="publish-btn-cancel" onClick={() => setStep("review")}>
                      ← Back
                    </button>
                  </div>
                </>
              )}

              {step === "running" && (
                <p className="publish-running">Committing YAML + dispatching workflow…</p>
              )}

              {step === "done" && result && (
                <>
                  <p className="publish-done">
                    Published <b>{result.applied}</b> draft{result.applied === 1 ? "" : "s"}.
                    {result.commit_url && (
                      <>
                        {" "}
                        <a href={result.commit_url} target="_blank" rel="noopener noreferrer">
                          View commit ↗
                        </a>
                      </>
                    )}
                  </p>
                  <p className="muted small">
                    The CI workflow is rebuilding viewers. Refresh in ~30 s to see the
                    changes baked into the canonical baseline.
                  </p>
                  <div className="publish-actions">
                    <button className="publish-btn-primary" onClick={close}>Close</button>
                  </div>
                </>
              )}

              {step === "error" && (
                <>
                  <p className="publish-error">Publish failed: {error}</p>
                  <div className="publish-actions">
                    <button className="publish-btn-primary" onClick={() => setStep("review")}>
                      ← Back
                    </button>
                    <button className="publish-btn-cancel" onClick={close}>Cancel</button>
                  </div>
                </>
              )}
            </div>
          </div>
        </div>
      )}
    </>
  );
}

function shortAuthor(email: string | undefined): string {
  if (!email) return "?";
  const at = email.indexOf("@");
  return at > 0 ? email.slice(0, at) : email;
}
