/**
 * Single source of truth for SME tier display — labels and colour classes.
 *
 * Every component that renders a tier (Type 1.1, Type 2, Pending edits,
 * Change log, dashboard, evidence drill, cap library, etc.) should import
 * TIER_LABEL + TIER_CLASS from here so wording + colour stay aligned.
 *
 * Source field on canonical caps remains the lower-case enum:
 *   required | preferred | advanced | deleted
 *
 * Display label everywhere is the title-case noun:
 *   Mandatory | Preferred | Advanced | Deleted
 *
 * Colour palette (locked 2026-05-09):
 *   Mandatory → amber
 *   Preferred → blue
 *   Advanced  → violet
 */

export type SmeTier = "required" | "preferred" | "advanced" | "deleted";

export const TIER_LABEL: Record<SmeTier, string> = {
  required: "Mandatory",
  preferred: "Preferred",
  advanced: "Advanced",
  deleted: "Deleted",
};

/** One-letter abbreviation, used in compact tier-mix tags + small chips. */
export const TIER_SHORT: Record<SmeTier, string> = {
  required: "M",
  preferred: "P",
  advanced: "A",
  deleted: "—",
};

/**
 * Single CSS class per tier. Components use these exact class names; matching
 * styles live in src/lib/tier.css (imported globally).
 */
export const TIER_CLASS: Record<SmeTier, string> = {
  required: "tier-mandatory",
  preferred: "tier-preferred",
  advanced: "tier-advanced",
  deleted: "tier-deleted",
};

/** Convenience — turn any string-ish tier into its display label. */
export function tierLabel(tier: string | undefined | null): string {
  if (!tier) return "—";
  return TIER_LABEL[tier as SmeTier] ?? tier;
}

/** Convenience — turn any string-ish tier into its CSS class. */
export function tierClass(tier: string | undefined | null): string {
  if (!tier) return "";
  return TIER_CLASS[tier as SmeTier] ?? "";
}
