import { Fragment, useEffect, useMemo, useState } from "react";
import { Link } from "react-router-dom";
import {
  loadDashboardFull,
  type DashboardFull,
  type CoverageCell,
  type CoverageVerdict,
} from "../lib/dashboardFull";
import { tierClass, TIER_SHORT, type SmeTier } from "../lib/tier";
import { useDrafts } from "../contexts/DraftsContext";
import type { Draft } from "../lib/api";
import {
  ModuleDeepDiveAccordion,
  ModuleNavChips,
} from "../components/dash/ModuleDeepDiveAccordion";
import { SolCatDetailPanel } from "../components/dash/SolCatDetailPanel";
import { ModuleSolcatGap } from "../components/dash/ModuleSolcatGap";
import { SolcatQReference } from "../components/dash/SolcatQReference";
import { SubModuleMandatoryMatrix } from "../components/dash/SubModuleMandatoryMatrix";
import { PricingCheckPanel } from "../components/dash/PricingCheckPanel";
import { MultiCoreCheckPanel } from "../components/dash/MultiCoreCheckPanel";
import { TabHelp } from "../components/TabHelp";
import { useUrlParam, readSession, writeSession } from "../lib/urlState";
import "./DashboardPage.css";

type Perspective = "module" | "solcat";
type ModuleSubTab = "checklists" | "deepdive" | "imdagap" | "pricing" | "multicore";
type SolCatSubTab = "coverage" | "detail" | "qref";
type PovKey = "t2" | "t11";
type CoverageMode = "mandatory" | "all";

export function DashboardPage() {
  const [data, setData] = useState<DashboardFull | null>(null);
  const [error, setError] = useState<string | null>(null);
  // Tab state is URL-backed so browser back/forward restores it. Default
  // values omitted from URL (URL stays clean when on the default tab).
  const [perspective, setPerspective] = useUrlParam<Perspective>("p", "module");
  const [moduleTab, setModuleTab] = useUrlParam<ModuleSubTab>("mt", "checklists");
  const [solcatTab, setSolcatTab] = useUrlParam<SolCatSubTab>("st", "coverage");
  const [pov, setPov] = useUrlParam<PovKey>("pov", "t2");
  const [coverageMode, setCoverageMode] = useUrlParam<CoverageMode>("cm", "mandatory");
  // Module focus on Sol cat > Coverage — when set, swaps the heatmap from
  // sol cat × module to a sub-module Mandatory matrix for that module.
  const [focusModule, setFocusModule] = useUrlParam<string>("fmod", "");
  // Multi-module column filter: comma-separated module slugs. Empty = all.
  // When the user picks 1 module they typically want sub-module drill, so
  // the existing focusModule still drives that swap; this `mods` filter is
  // for the standard heatmap "show me only these module columns".
  const [modsCsv, setModsCsv] = useUrlParam<string>("mods", "");
  // Sol cat multi-select: comma-separated sc_ids. Empty = all matching the
  // module filter.
  const [scsCsv, setScsCsv] = useUrlParam<string>("scs", "");

  useEffect(() => {
    loadDashboardFull()
      .then(setData)
      .catch(e => setError(String(e?.message || e)));
  }, []);

  if (error) {
    return (
      <section className="dash-page error">
        <h1>Module Assurance Dashboard</h1>
        <p>Failed to load dashboard payload: {error}</p>
      </section>
    );
  }
  if (!data) {
    return (
      <section className="dash-page">
        <h1>Module Assurance Dashboard</h1>
        <p className="muted">Loading…</p>
      </section>
    );
  }

  const moduleEntries = data.checklist_modules.map(m => ({
    slug: m.slug,
    module_id: m.module_id,
    module_name: m.module_name,
    short: data.module_short[m.slug] || m.slug,
  }));

  const meta = computeMeta(data, perspective, moduleTab, solcatTab, pov, coverageMode);

  return (
    <section className="dash-page">
      <header className="dash-header">
        <h1>Module Assurance Dashboard</h1>
        <p className="dash-lede">
          Two perspectives on the same data: how each module fares as a vendor
          checklist (Module), and what each PSG sol cat covers across modules
          (Sol cat).
        </p>
      </header>

      <nav className="dash-perspective-bar">
        <button
          type="button"
          className={`dash-pb-btn${perspective === "module" ? " active" : ""}`}
          onClick={() => setPerspective("module")}
        >
          <span className="dash-pb-num">A</span>
          <span className="dash-pb-name">Module perspective</span>
          <span className="dash-pb-sub">Checklists · Build chain · Flags</span>
        </button>
        <button
          type="button"
          className={`dash-pb-btn${perspective === "solcat" ? " active" : ""}`}
          onClick={() => setPerspective("solcat")}
        >
          <span className="dash-pb-num">B</span>
          <span className="dash-pb-name">Sol cat perspective</span>
          <span className="dash-pb-sub">Coverage · Sol-cat detail</span>
        </button>
      </nav>

      {perspective === "module" ? (
        <>
          <nav className="dash-tabs">
            <button
              type="button"
              className={`dash-tab${moduleTab === "checklists" ? " active" : ""}`}
              onClick={() => setModuleTab("checklists")}
            >
              1 · Checklists
            </button>
            <button
              type="button"
              className={`dash-tab${moduleTab === "deepdive" ? " active" : ""}`}
              onClick={() => setModuleTab("deepdive")}
            >
              2 · Build chain + flags
            </button>
            <button
              type="button"
              className={`dash-tab${moduleTab === "imdagap" ? " active" : ""}`}
              onClick={() => setModuleTab("imdagap")}
            >
              3 · IMDA gap
            </button>
            <button
              type="button"
              className={`dash-tab${moduleTab === "pricing" ? " active" : ""}`}
              onClick={() => setModuleTab("pricing")}
              title="Vendor pricing reality check — Year-1 SGD per Mandatory coverage % (4 commodity-suite modules)"
            >
              4 · Pricing check
            </button>
            <button
              type="button"
              className={`dash-tab${moduleTab === "multicore" ? " active" : ""}`}
              onClick={() => setModuleTab("multicore")}
              title="Validate the locked Required-cap multi-core split against PSG solutions + reference ERPs"
            >
              5 · Multi-core check
            </button>
            <span className="dash-tab-meta">{meta}</span>
          </nav>

          {moduleTab === "checklists" && (
            <ChecklistsPanel data={data} moduleEntries={moduleEntries} />
          )}
          {moduleTab === "deepdive" && (
            <ModuleDeepDiveAccordion modules={moduleEntries} />
          )}
          {moduleTab === "imdagap" && (
            <ModuleSolcatGap modules={moduleEntries} />
          )}
          {moduleTab === "pricing" && (
            <PricingCheckPanel modules={moduleEntries} />
          )}
          {moduleTab === "multicore" && (
            <MultiCoreCheckPanel modules={moduleEntries} />
          )}
        </>
      ) : (
        <>
          <nav className="dash-tabs">
            <button
              type="button"
              className={`dash-tab${solcatTab === "coverage" ? " active" : ""}`}
              onClick={() => setSolcatTab("coverage")}
            >
              1 · Coverage
            </button>
            <button
              type="button"
              className={`dash-tab${solcatTab === "detail" ? " active" : ""}`}
              onClick={() => setSolcatTab("detail")}
            >
              2 · Sol cat detail
            </button>
            <button
              type="button"
              className={`dash-tab${solcatTab === "qref" ? " active" : ""}`}
              onClick={() => setSolcatTab("qref")}
            >
              3 · By-IMDA-Q reference
            </button>
            <span className="dash-tab-meta">{meta}</span>
          </nav>

          {solcatTab === "coverage" && (
            <CoveragePanel
              data={data}
              pov={pov}
              onPovChange={setPov}
              mode={coverageMode}
              onModeChange={setCoverageMode}
              focusModule={focusModule}
              onFocusModuleChange={setFocusModule}
              modsCsv={modsCsv}
              onModsCsvChange={setModsCsv}
              scsCsv={scsCsv}
              onScsCsvChange={setScsCsv}
            />
          )}
          {solcatTab === "detail" && (
            <SolCatDetailPanel modules={moduleEntries} />
          )}
          {solcatTab === "qref" && (
            <SolcatQReference modules={moduleEntries} />
          )}
        </>
      )}
    </section>
  );
}

function computeMeta(
  data: DashboardFull,
  perspective: Perspective,
  moduleTab: ModuleSubTab,
  solcatTab: SolCatSubTab,
  pov: PovKey,
  mode: CoverageMode,
): string {
  if (perspective === "module") {
    if (moduleTab === "checklists") {
      const totalCaps = data.checklist_modules.reduce(
        (a, m) => a + m.tier_total.r + m.tier_total.p + m.tier_total.a,
        0,
      );
      return `${data.checklist_modules.length} modules · ${totalCaps} caps in checklist`;
    }
    if (moduleTab === "imdagap") {
      return `Pick a sol cat · IMDA Qs ↔ canonical checklist gap`;
    }
    return `${data.checklist_modules.length} modules · build-chain narrative + re-eval flags`;
  }
  if (solcatTab === "coverage") {
    if (mode === "all") {
      const total = data.solcat_rows.reduce((a, sc) => {
        return a + data.module_order.reduce((b, slug) => b + (data.breadth[sc.sc_id]?.[slug] || 0), 0);
      }, 0);
      return `${total} caps in scope · max per-cell ${data.breadth_max} · all tiers (breadth)`;
    }
    const cov = pov === "t11" ? data.coverage_t11 : data.coverage_t2;
    let pass = 0, partial = 0, fail = 0;
    for (const sc of data.solcat_rows) {
      for (const slug of data.module_order) {
        const cell = cov[sc.sc_id]?.[slug];
        if (cell?.verdict === "pass") pass++;
        else if (cell?.verdict === "partial") partial++;
        else if (cell?.verdict === "fail") fail++;
      }
    }
    return `${pass} pass · ${partial} partial · ${fail} fail · ${pov === "t11" ? "Type 1.1 (per-cap)" : "Type 2 (umbrella)"} · Mandatory only`;
  }
  if (solcatTab === "detail") {
    return `${data.solcat_rows.length} sol cats · click to drill into module + sub-module coverage`;
  }
  return `${data.solcat_rows.length} sol cats · per-sol-cat IMDA Q reference`;
}

// ──────────────────────────────────────────────────────────────────────
// Tab 1 — Checklists
// ──────────────────────────────────────────────────────────────────────

function ChecklistsPanel({
  data,
  moduleEntries,
}: {
  data: DashboardFull;
  moduleEntries: Array<{ slug: string; module_id: string; module_name: string; short: string }>;
}) {
  // sessionStorage-backed so accordion expand/collapse survives in-session
  // navigation (back from /canonical/<mod> restores the same expanded set).
  const [collapsed, setCollapsed] = useState<Record<string, boolean>>(() =>
    readSession<Record<string, boolean>>("dash.checklists.collapsed", {}),
  );
  useEffect(() => {
    writeSession("dash.checklists.collapsed", collapsed);
  }, [collapsed]);
  const toggle = (slug: string) =>
    setCollapsed(prev => ({ ...prev, [slug]: !prev[slug] }));

  const allCollapsed = data.checklist_modules.every(m => collapsed[m.slug]);
  const collapseAll = () => {
    const next: Record<string, boolean> = {};
    for (const m of data.checklist_modules) next[m.slug] = true;
    setCollapsed(next);
  };
  const expandAll = () => setCollapsed({});

  return (
    <div className="dash-panel">
      <TabHelp hint="Click a module title to expand the canonical checklist below it; click a cap row to open its full editor.">
        The full canonical checklist for every module — Mandatory + Preferred
        + Advanced caps grouped by sub-module. Use this to scan what each
        module asks of vendors at a glance.
      </TabHelp>
      <div className="dash-chip-bar">
        <span className="dash-chip">
          <strong>{data.checklist_modules.length}</strong> modules
        </span>
        <button
          type="button"
          className="dash-toggle-all"
          onClick={allCollapsed ? expandAll : collapseAll}
          title={allCollapsed ? "Expand every module" : "Collapse every module"}
        >
          {allCollapsed ? "Expand all ▾" : "Collapse all ▸"}
        </button>
        <span className="dash-chip dash-chip-hint">
          Click any module header to toggle one at a time
        </span>
      </div>
      <ModuleNavChips
        modules={moduleEntries}
        anchorPrefix="cl"
        onClickModule={slug => setCollapsed(prev => ({ ...prev, [slug]: false }))}
      />
      {data.checklist_modules.map(m => (
        <article
          key={m.slug}
          id={`cl-${m.slug}`}
          className={`mod-card${collapsed[m.slug] ? " collapsed" : ""}`}
        >
          <div
            className="mod-head"
            onClick={(e) => {
              if ((e.target as HTMLElement).closest("a")) return;
              toggle(m.slug);
            }}
          >
            <span className="mod-id">{m.module_id}</span>
            <Link to={`/canonical/${m.slug}`} className="mod-name">
              {m.module_name}
            </Link>
            <span className="mod-mix">
              <span className="mod-mix-r">{m.tier_total.r}M</span>
              {" · "}
              <span className="mod-mix-p">{m.tier_total.p}P</span>
              {" · "}
              <span className="mod-mix-a">{m.tier_total.a}A</span>
            </span>
            <span className="mod-chev">▾</span>
          </div>
          {!collapsed[m.slug] && (
            <div className="mod-bands">
              {m.bands.map(b => (
                <div key={b.sm_id} className="band">
                  <div className="band-head">
                    <span className="band-name">{b.sm_name}</span>
                    <span className="band-mix">
                      {[
                        b.r > 0 ? `${b.r}M` : null,
                        b.p > 0 ? `${b.p}P` : null,
                        b.a > 0 ? `${b.a}A` : null,
                      ].filter(Boolean).join(" · ")}
                    </span>
                  </div>
                  <div className="band-caps">
                    {b.caps.map(c => (
                      <div key={c.id} className="cap-line">
                        <span className={`tier-chip ${tierClass(c.tier)}`}>
                          {TIER_SHORT[(c.tier as SmeTier) || "required"]}
                        </span>
                        <span>{c.name || c.id}</span>
                      </div>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          )}
        </article>
      ))}
    </div>
  );
}

// ──────────────────────────────────────────────────────────────────────
// Tab 2 — Coverage matrix
// ──────────────────────────────────────────────────────────────────────

type CoverageFilterKey = "all" | "pass_only" | "partial_or_fail" | "vsaas_only";
type CoverageSortKey = "default" | "passing_desc" | "passing_asc" | "name_asc";

interface RowVerdict {
  passing: number;
  in_scope: number;
  label: "PASS" | "PARTIAL" | "FAIL" | "NA";
  toneClass: string;
}

function computeRowVerdict(
  cov: Record<string, Record<string, CoverageCell>>,
  data: DashboardFull,
  sc_id: string,
): RowVerdict {
  let passing = 0;
  let in_scope = 0;
  for (const slug of data.module_order) {
    const v = cov[sc_id]?.[slug]?.verdict;
    if (v === "pass" || v === "partial" || v === "fail") in_scope++;
    if (v === "pass") passing++;
  }
  if (in_scope === 0) return { passing, in_scope, label: "NA", toneClass: "rv-na" };
  if (passing === in_scope) return { passing, in_scope, label: "PASS", toneClass: "rv-pass" };
  if (passing > 0) return { passing, in_scope, label: "PARTIAL", toneClass: "rv-partial" };
  return { passing, in_scope, label: "FAIL", toneClass: "rv-fail" };
}

function CoveragePanel({
  data,
  pov,
  onPovChange,
  mode,
  onModeChange,
  focusModule,
  onFocusModuleChange,
  modsCsv,
  onModsCsvChange,
  scsCsv,
  onScsCsvChange,
}: {
  data: DashboardFull;
  pov: PovKey;
  onPovChange: (next: PovKey) => void;
  mode: CoverageMode;
  onModeChange: (next: CoverageMode) => void;
  focusModule: string;
  onFocusModuleChange: (next: string) => void;
  modsCsv: string;
  onModsCsvChange: (next: string) => void;
  scsCsv: string;
  onScsCsvChange: (next: string) => void;
}) {
  // Parse CSV URL params into Set<string> for fast lookup.
  const selectedMods = useMemo(() => {
    const arr = modsCsv.split(",").map(s => s.trim()).filter(Boolean);
    return new Set(arr);
  }, [modsCsv]);
  const selectedScs = useMemo(() => {
    const arr = scsCsv.split(",").map(s => s.trim()).filter(Boolean);
    return new Set(arr);
  }, [scsCsv]);

  const toggleMod = (slug: string) => {
    const next = new Set(selectedMods);
    if (next.has(slug)) next.delete(slug);
    else next.add(slug);
    onModsCsvChange(Array.from(next).join(","));
  };
  const toggleSc = (scId: string) => {
    const next = new Set(selectedScs);
    if (next.has(scId)) next.delete(scId);
    else next.add(scId);
    onScsCsvChange(Array.from(next).join(","));
  };

  // Sol cat search state — local, not URL-backed (transient).
  const [scSearch, setScSearch] = useState("");
  // When a module focus is set, swap to the sub-module-level Mandatory matrix
  // for that module. Mirrors the Per-module deep-dive's onboarding matrix
  // but lives in the Sol cat > Coverage tab so vendors-vs-sol-cats analysis
  // and per-module sub-module pass/fail share one surface.
  if (focusModule) {
    return (
      <div className="dash-panel">
        <div className="dash-pov-row">
          <span className="dash-pov-label">Module focus</span>
          <select
            className="dash-sort"
            value={focusModule}
            onChange={e => onFocusModuleChange(e.target.value)}
          >
            <option value="">— back to all modules heatmap —</option>
            {data.module_order.map(slug => (
              <option key={slug} value={slug}>
                {data.module_short[slug] || slug}
              </option>
            ))}
          </select>
          <button
            type="button"
            className="dash-toggle-all"
            onClick={() => onFocusModuleChange("")}
            title="Clear module focus and return to the sol cat × module heatmap"
          >
            ← back to all modules
          </button>
        </div>
        <h3 className="dash-section-h">
          {data.module_short[focusModule] || focusModule} —
          sub-module Mandatory pass per sol cat
        </h3>
        <SubModuleMandatoryMatrix
          moduleSlug={focusModule}
          moduleShort={data.module_short[focusModule] || focusModule}
        />
      </div>
    );
  }
  const cov = pov === "t11" ? data.coverage_t11 : data.coverage_t2;
  const [filter, setFilter] = useState<CoverageFilterKey>("all");
  const [sort, setSort] = useState<CoverageSortKey>("default");
  const [expandedCell, setExpandedCell] =
    useState<{ sc_id: string; slug: string } | null>(null);
  // Focus-on-sol-cat — when set, the heatmap collapses to that one row and
  // hides module columns where the focused sol cat is "not_in_scope".
  // Mirrors the Sol cat detail tab's "only relevant modules" behaviour.
  // URL-backed so a focused view is back-button-restorable + shareable.
  const [focusScId, setFocusScId] = useUrlParam<string>("fsc", "");
  // focusModule is hoisted to the page-level (passed in via props) so the
  // module-focus dropdown can be displayed even when CoveragePanel
  // short-circuits to the sub-module matrix.

  // Per-row pass-rate helpers (used by sorts + filters).
  const rowPassCount = (sc_id: string) =>
    data.module_order.reduce((n, slug) => {
      const v = cov[sc_id]?.[slug]?.verdict;
      return v === "pass" ? n + 1 : n;
    }, 0);
  const rowHasPartialOrFail = (sc_id: string) =>
    data.module_order.some(slug => {
      const v = cov[sc_id]?.[slug]?.verdict;
      return v === "partial" || v === "fail";
    });

  // Per-module pass/partial/fail tallies for the summary cards.
  const moduleStats = data.module_order.map(slug => {
    let pass = 0, partial = 0, fail = 0, in_scope = 0;
    for (const sc of data.solcat_rows) {
      const v = cov[sc.sc_id]?.[slug]?.verdict;
      if (v === "pass" || v === "partial" || v === "fail") in_scope++;
      if (v === "pass") pass++;
      else if (v === "partial") partial++;
      else if (v === "fail") fail++;
    }
    return {
      slug,
      short: data.module_short[slug] || slug,
      module_id: data.module_ids[slug] || "?",
      pass, partial, fail, in_scope,
      pct: in_scope > 0 ? Math.round((100 * pass) / in_scope) : 0,
    };
  });

  // Filter + sort the sol-cat rows for the heatmap.
  const visibleRows = data.solcat_rows.filter(sc => {
    if (focusScId) return sc.sc_id === focusScId;
    // Sol cat multi-select: if user has explicitly chosen sol cats, show only those.
    if (selectedScs.size > 0 && !selectedScs.has(sc.sc_id)) return false;
    // Module multi-select: hide sol cats that don't touch any selected module.
    if (selectedMods.size > 0) {
      const overlaps = (sc.modules || []).some(m => selectedMods.has(m));
      if (!overlaps) return false;
    }
    // Sol cat search filter (text contains, case-insensitive).
    if (scSearch.trim()) {
      const q = scSearch.trim().toLowerCase();
      const hay = `${sc.display_name} ${sc.vertical || ""} ${sc.sc_id}`.toLowerCase();
      if (!hay.includes(q)) return false;
    }
    if (filter === "all") return true;
    if (filter === "vsaas_only") return sc.vertical_saas;
    if (filter === "pass_only") return rowPassCount(sc.sc_id) > 0;
    if (filter === "partial_or_fail") return rowHasPartialOrFail(sc.sc_id);
    return true;
  });

  // Visible columns: module multi-select narrows columns; otherwise focused
  // sol cat narrows to its in-scope modules; otherwise all 10.
  const visibleSlugs: string[] = (() => {
    if (selectedMods.size > 0) {
      return data.module_order.filter(s => selectedMods.has(s));
    }
    if (focusScId) {
      return data.module_order.filter(slug => {
        const v = cov[focusScId]?.[slug]?.verdict;
        return v && v !== "not_in_scope" && v !== "na";
      });
    }
    return data.module_order;
  })();

  const sortedRows = visibleRows.slice().sort((a, b) => {
    if (sort === "passing_desc") return rowPassCount(b.sc_id) - rowPassCount(a.sc_id);
    if (sort === "passing_asc") return rowPassCount(a.sc_id) - rowPassCount(b.sc_id);
    if (sort === "name_asc") return a.display_name.localeCompare(b.display_name);
    // default: vertical-SaaS last, then by display name (matches build_dashboard_full.py)
    const av = a.vertical_saas ? 1 : 0;
    const bv = b.vertical_saas ? 1 : 0;
    if (av !== bv) return av - bv;
    return a.display_name.localeCompare(b.display_name);
  });

  return (
    <div className="dash-panel">
      <TabHelp hint="Pick a sol cat in Sol-cat focus to see only its in-scope modules; pick a module in Module focus to swap to a sub-module-level Mandatory matrix.">
        Sol-cat × module heatmap. Each cell = whether the sol cat passes
        that module's Mandatory verdict (all M caps covered).
      </TabHelp>
      <ModulePassCards stats={moduleStats} />

      <div className="dash-pov-row">
        <span className="dash-pov-label">Tier</span>
        <div className="dash-pov-toggle">
          <button
            type="button"
            className={`dash-pov-btn${mode === "mandatory" ? " active" : ""}`}
            onClick={() => onModeChange("mandatory")}
            title="Score each cell on Mandatory cap coverage only. Default. Aligns with IMDA Type 2 umbrella semantics."
          >
            Mandatory only
          </button>
          <button
            type="button"
            className={`dash-pov-btn${mode === "all" ? " active" : ""}`}
            onClick={() => onModeChange("all")}
            title="Show total caps in scope across all tiers (R + P + A). Equivalent to the legacy Breadth heatmap."
          >
            All tiers (breadth)
          </button>
        </div>

        {mode === "mandatory" && (
          <>
            <span className="dash-pov-label" style={{ marginLeft: 16 }}>Format</span>
            <div className="dash-pov-toggle">
              <button
                type="button"
                className={`dash-pov-btn${pov === "t2" ? " active" : ""}`}
                onClick={() => onPovChange("t2")}
                title="IMDA Type 2 umbrella: vendor answers yes only if all Mandatory caps in the module are covered."
              >
                Type 2 (umbrella)
              </button>
              <button
                type="button"
                className={`dash-pov-btn${pov === "t11" ? " active" : ""}`}
                onClick={() => onPovChange("t11")}
                title="IMDA Type 1.1: each Mandatory cap is its own row. Same module-level verdict; per-cap drill is a future enhancement."
              >
                Type 1.1 (per-cap)
              </button>
            </div>
          </>
        )}
      </div>

      <div className="dash-chip-bar">
        {mode === "mandatory" ? (
          <>
            <span className="dash-chip dash-chip-good">Pass = all Mandatory caps covered</span>
            <span className="dash-chip dash-chip-warn">Partial = some Mandatory caps covered</span>
            <span className="dash-chip dash-chip-bad">Fail = zero Mandatory caps covered</span>
            <span className="dash-chip">Grey · = not in scope</span>
          </>
        ) : (
          <>
            <span className="dash-chip">Cell = # caps in scope per (sol cat, module)</span>
            <span className="dash-chip">Bluer = broader catalog reach · max {data.breadth_max}</span>
          </>
        )}
      </div>

      {/* Multi-module column picker — toggle modules to narrow heatmap columns
          AND auto-filter sol cat rows to only those mapped to ≥1 selected
          module. Default = none selected = all 10 columns. */}
      <div className="dash-filter-row">
        <span className="dash-filter-label">Modules</span>
        <div className="dash-filter-pills">
          {data.module_order.map(slug => {
            const selected = selectedMods.has(slug);
            return (
              <button
                key={slug}
                type="button"
                className={`dash-filter-pill${selected ? " active" : ""}`}
                onClick={() => toggleMod(slug)}
                title={selected ? "Click to remove from filter" : "Click to add to filter"}
              >
                {data.module_short[slug] || slug}
              </button>
            );
          })}
          {selectedMods.size > 0 && (
            <button
              type="button"
              className="dash-filter-pill dash-filter-pill-clear"
              onClick={() => onModsCsvChange("")}
              title="Clear module filter (show all 10)"
            >
              Clear ✕
            </button>
          )}
        </div>
        <span className="dash-filter-count">
          {selectedMods.size === 0
            ? `all ${data.module_order.length} modules`
            : `${selectedMods.size} of ${data.module_order.length} modules`}
        </span>
      </div>

      {/* Sol cat search + multi-select chips */}
      <div className="dash-filter-row">
        <span className="dash-filter-label">Sol cats</span>
        <input
          type="search"
          className="dash-sc-search"
          placeholder="Search by name, vertical, id…"
          value={scSearch}
          onChange={e => setScSearch(e.target.value)}
        />
        {scSearch.trim() && (
          <div className="dash-sc-search-hits">
            {data.solcat_rows
              .filter(sc => {
                const q = scSearch.trim().toLowerCase();
                return `${sc.display_name} ${sc.vertical || ""}`.toLowerCase().includes(q)
                  && !selectedScs.has(sc.sc_id);
              })
              .slice(0, 6)
              .map(sc => (
                <button
                  key={sc.sc_id}
                  type="button"
                  className="dash-sc-search-add"
                  onClick={() => toggleSc(sc.sc_id)}
                  title={`Add ${sc.display_name} to selection`}
                >
                  + {sc.display_name}
                </button>
              ))}
          </div>
        )}
      </div>
      {selectedScs.size > 0 && (
        <div className="dash-filter-row dash-sc-chips-row">
          <span className="dash-filter-label">Selected</span>
          <div className="dash-sc-chips">
            {Array.from(selectedScs).map(scId => {
              const sc = data.solcat_rows.find(s => s.sc_id === scId);
              if (!sc) return null;
              return (
                <span key={scId} className="dash-sc-chip">
                  {sc.display_name}
                  <button
                    type="button"
                    className="dash-sc-chip-x"
                    onClick={() => toggleSc(scId)}
                    title="Remove from selection"
                  >
                    ×
                  </button>
                </span>
              );
            })}
            <button
              type="button"
              className="dash-filter-pill dash-filter-pill-clear"
              onClick={() => onScsCsvChange("")}
            >
              Clear all ✕
            </button>
          </div>
        </div>
      )}

      <div className="dash-filter-row">
        <span className="dash-filter-label">Show</span>
        <div className="dash-filter-pills">
          {([
            ["all", `All (${data.solcat_rows.length})`],
            ["pass_only", "Has any pass"],
            ["partial_or_fail", "Has partial / fail"],
            ["vsaas_only", "Vertical SaaS only"],
          ] as Array<[CoverageFilterKey, string]>).map(([key, label]) => (
            <button
              key={key}
              type="button"
              className={`dash-filter-pill${filter === key ? " active" : ""}`}
              onClick={() => setFilter(key)}
              disabled={!!focusScId}
              title={focusScId ? "Clear focus to use row filters" : undefined}
            >
              {label}
            </button>
          ))}
        </div>
        <span className="dash-filter-label" style={{ marginLeft: "auto" }}>Module focus</span>
        <select
          className="dash-sort"
          value={focusModule}
          onChange={e => onFocusModuleChange(e.target.value)}
          title="Pick a module to swap the heatmap to a sol cat × sub-module Mandatory-pass matrix for that module"
        >
          <option value="">— off (sol cat × module) —</option>
          {data.module_order.map(slug => (
            <option key={slug} value={slug}>
              {data.module_short[slug] || slug}
            </option>
          ))}
        </select>
        <span className="dash-filter-label">Sol cat focus</span>
        <select
          className="dash-sort"
          value={focusScId}
          onChange={e => setFocusScId(e.target.value)}
          title="Pick a sol cat to collapse the heatmap to that one row + only show modules in its scope"
        >
          <option value="">All sol cats (no focus)</option>
          {data.solcat_rows
            .slice()
            .sort((a, b) => a.display_name.localeCompare(b.display_name))
            .map(sc => (
              <option key={sc.sc_id} value={sc.sc_id}>
                {sc.display_name}
              </option>
            ))}
        </select>
        <span className="dash-filter-label">Sort</span>
        <select
          className="dash-sort"
          value={sort}
          onChange={e => setSort(e.target.value as CoverageSortKey)}
          disabled={!!focusScId}
          title={focusScId ? "Clear focus to sort" : undefined}
        >
          <option value="default">Default (alpha, vertical-SaaS last)</option>
          <option value="passing_desc">Most modules passing first</option>
          <option value="passing_asc">Fewest modules passing first</option>
          <option value="name_asc">Name (A → Z)</option>
        </select>
        <span className="dash-filter-count">
          {sortedRows.length} of {data.solcat_rows.length} rows
          {focusScId && ` · ${visibleSlugs.length} of ${data.module_order.length} modules`}
        </span>
      </div>

      {mode === "mandatory" ? (
        <CoverageHeatmap
          data={data}
          cov={cov}
          rows={sortedRows}
          visibleSlugs={visibleSlugs}
          expandedCell={expandedCell}
          onCellClick={(sc_id, slug) => {
            setExpandedCell(prev =>
              prev && prev.sc_id === sc_id && prev.slug === slug
                ? null
                : { sc_id, slug },
            );
          }}
        />
      ) : (
        <HeatmapTable
          data={data}
          rows={sortedRows}
          visibleSlugs={visibleSlugs}
          render={(sc_id, slug) => {
            const n = data.breadth[sc_id]?.[slug] || 0;
            const max = Math.max(data.breadth_max, 1);
            let band = "b0";
            if (n > 0) {
              const ratio = n / max;
              band = ratio >= 0.8 ? "b5"
                   : ratio >= 0.6 ? "b4"
                   : ratio >= 0.4 ? "b3"
                   : ratio >= 0.2 ? "b2"
                   : "b1";
            }
            return {
              className: `dash-cell dash-cell-${band}`,
              text: n > 0 ? String(n) : "·",
              title: `${n} caps in scope for ${slug}`,
            };
          }}
        />
      )}
    </div>
  );
}

// Dedicated Coverage heatmap renderer — supports cell-click drill expansion
// + per-row verdict chip (vertical-SaaS rows score on in-scope modules only).
function CoverageHeatmap({
  data,
  cov,
  rows,
  visibleSlugs,
  expandedCell,
  onCellClick,
}: {
  data: DashboardFull;
  cov: Record<string, Record<string, CoverageCell>>;
  rows: typeof data.solcat_rows;
  visibleSlugs?: string[];
  expandedCell: { sc_id: string; slug: string } | null;
  onCellClick: (sc_id: string, slug: string) => void;
}) {
  const slugs = visibleSlugs ?? data.module_order;
  const headers = slugs.map(slug => ({
    slug,
    id: data.module_ids[slug] || "?",
    short: data.module_short[slug] || slug,
  }));
  // 3 leading cols: verdict chip + sol cat name. Then N module cols.
  const colCount = 2 + headers.length;

  return (
    <div className="dash-heatmap-wrap">
      <table className="dash-heatmap dash-heatmap-coverage">
        <thead>
          <tr>
            <th className="dash-rv-col">Verdict</th>
            <th className="dash-sc-col">Sol cat</th>
            {headers.map(h => (
              <th key={h.slug} title={h.slug}>
                <span className="dash-th-id">{h.id}</span>
                <span className="dash-th-short">{h.short}</span>
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          {rows.map(sc => {
            const verdict = computeRowVerdict(cov, data, sc.sc_id);
            const isExpandedRow =
              expandedCell !== null && expandedCell.sc_id === sc.sc_id;
            const expandedCol =
              isExpandedRow ? expandedCell.slug : null;
            const expandedCellData =
              expandedCol ? cov[sc.sc_id]?.[expandedCol] : null;
            return (
              <Fragment key={sc.sc_id}>
                <tr>
                  <td className="dash-rv-cell">
                    <span
                      className={`dash-rv-chip ${verdict.toneClass}`}
                      title={
                        sc.vertical_saas
                          ? `Vertical SaaS — ${verdict.passing}/${verdict.in_scope} of declared in-scope modules pass`
                          : `${verdict.passing}/${verdict.in_scope} modules pass`
                      }
                    >
                      {sc.vertical_saas && <span className="dash-rv-vsaas">v</span>}
                      {verdict.label}
                      <span className="dash-rv-frac">{verdict.passing}/{verdict.in_scope}</span>
                    </span>
                  </td>
                  <td className="dash-sc-cell">
                    <strong>{sc.display_name}</strong>
                    {sc.vertical_saas && (
                      <span
                        className="dash-vsaas-pill"
                        title={`Vertical SaaS — ${sc.vertical_saas_industry}. Verdict computed over its declared in-scope modules only.`}
                      >
                        SaaS
                      </span>
                    )}
                    <div className="dash-vert">{sc.vertical}</div>
                  </td>
                  {headers.map(h => {
                    const cell: CoverageCell = cov[sc.sc_id]?.[h.slug] || {
                      verdict: "not_in_scope", n_r_passing: 0, n_r_bearing: 0,
                    };
                    const v = cell.verdict;
                    const isClickable = v === "partial" || v === "fail";
                    const isExpanded = expandedCol === h.slug;
                    const text = v === "na" || v === "not_in_scope"
                      ? "·"
                      : `${cell.n_r_passing}/${cell.n_r_bearing}`;
                    return (
                      <td
                        key={h.slug}
                        className={`dash-cell ${verdictClass(v)}${isClickable ? " dash-cell-click" : ""}${isExpanded ? " dash-cell-expanded" : ""}`}
                        onClick={isClickable ? () => onCellClick(sc.sc_id, h.slug) : undefined}
                        title={isClickable
                          ? `${v}: ${cell.n_r_passing}/${cell.n_r_bearing} — click to drill into failing caps`
                          : `${v}: ${cell.n_r_passing}/${cell.n_r_bearing} Mandatory caps covered`}
                      >
                        {text}
                      </td>
                    );
                  })}
                </tr>
                {isExpandedRow && expandedCellData && (
                  <tr className="dash-drill-row">
                    <td colSpan={colCount}>
                      <CoverageDrill
                        cell={expandedCellData}
                        moduleShort={data.module_short[expandedCol!] || expandedCol!}
                        moduleSlug={expandedCol!}
                        solCatName={sc.display_name}
                        onClose={() => onCellClick(sc.sc_id, expandedCol!)}
                      />
                    </td>
                  </tr>
                )}
              </Fragment>
            );
          })}
        </tbody>
      </table>
    </div>
  );
}

function CoverageDrill({
  cell,
  moduleShort,
  moduleSlug,
  solCatName,
  onClose,
}: {
  cell: CoverageCell;
  moduleShort: string;
  moduleSlug: string;
  solCatName: string;
  onClose: () => void;
}) {
  const failing = cell.failing_caps || [];
  const passing = cell.passing_caps || [];
  return (
    <div className="dash-drill">
      <div className="dash-drill-head">
        <div>
          <span className="dash-drill-eyebrow">Drill</span>
          <strong className="dash-drill-title">
            {solCatName} × {moduleShort}
          </strong>
          <span className="dash-drill-meta">
            {cell.n_r_passing} pass · {failing.length} fail of {cell.n_r_bearing} Mandatory caps
          </span>
        </div>
        <div className="dash-drill-actions">
          <Link to={`/canonical/${moduleSlug}`} className="dash-drill-link">
            Open {moduleShort} →
          </Link>
          <button type="button" className="dash-drill-close" onClick={onClose} title="Close drill">
            ×
          </button>
        </div>
      </div>
      {failing.length === 0 ? (
        <p className="dash-drill-empty muted small">
          No failing Mandatory caps to show — every required cap is covered (yes/partial).
        </p>
      ) : (
        <ul className="dash-drill-caps">
          {failing.map(c => (
            <li key={c.id} className={`dash-drill-cap dash-cap-${c.fulfils}`}>
              <code className="dash-drill-cap-id">{c.id}</code>
              <span className="dash-drill-cap-name">{c.name}</span>
              <span className={`dash-drill-cap-status status-${c.fulfils}`}>
                {c.fulfils === "no" ? "vendor doesn't cover"
                 : c.fulfils === "unscored" ? "not yet scored"
                 : c.fulfils}
              </span>
              {c.reason && <span className="dash-drill-cap-reason">{c.reason}</span>}
            </li>
          ))}
        </ul>
      )}
      {passing.length > 0 && failing.length > 0 && (
        <details className="dash-drill-passing">
          <summary>Show {passing.length} passing caps</summary>
          <ul className="dash-drill-caps">
            {passing.map(c => (
              <li key={c.id} className={`dash-drill-cap dash-cap-${c.fulfils}`}>
                <code className="dash-drill-cap-id">{c.id}</code>
                <span className="dash-drill-cap-name">{c.name}</span>
                <span className={`dash-drill-cap-status status-${c.fulfils}`}>{c.fulfils}</span>
              </li>
            ))}
          </ul>
        </details>
      )}
    </div>
  );
}

function ModulePassCards({
  stats,
}: {
  stats: Array<{ slug: string; short: string; module_id: string; pass: number; partial: number; fail: number; in_scope: number; pct: number }>;
}) {
  // Per-module unpublished-draft count from DraftsContext. Lets reviewers
  // see at a glance which modules have outstanding edits.
  const { draftsByCap } = useDrafts();
  const editsByModule = useMemo(() => {
    const out: Record<string, number> = {};
    draftsByCap.forEach((d: Draft) => {
      out[d.module] = (out[d.module] || 0) + 1;
    });
    return out;
  }, [draftsByCap]);

  return (
    <div className="dash-mod-cards">
      {stats.map(s => {
        const edits = editsByModule[s.slug] || 0;
        return (
          <Link key={s.slug} to={`/canonical/${s.slug}`} className="dash-mod-card" title={`${s.in_scope} sol cats in scope for ${s.short}${edits > 0 ? ` · ${edits} unpublished draft${edits === 1 ? "" : "s"}` : ""}`}>
            <div className="dash-mod-card-headrow">
              <div className="dash-mod-card-id">{s.module_id}</div>
              {edits > 0 && (
                <span className="dash-mod-card-edits" title={`${edits} unpublished draft${edits === 1 ? "" : "s"} on this module`}>
                  ✎ {edits}
                </span>
              )}
            </div>
            <div className="dash-mod-card-name">{s.short}</div>
            <div className="dash-mod-card-counts">
              <span className="dash-mc-pass">{s.pass}</span>
              <span className="dash-mc-sep">·</span>
              <span className="dash-mc-partial">{s.partial}</span>
              <span className="dash-mc-sep">·</span>
              <span className="dash-mc-fail">{s.fail}</span>
            </div>
            <div className="dash-mod-card-pct">{s.pct}% pass</div>
          </Link>
        );
      })}
    </div>
  );
}

function verdictClass(v: CoverageVerdict): string {
  return `dash-cell-${v}`;
}

// Shared heatmap-table renderer used by Coverage's "All tiers" mode.
function HeatmapTable({
  data,
  render,
  rows,
  visibleSlugs,
}: {
  data: DashboardFull;
  render: (sc_id: string, slug: string) => { className: string; text: string; title?: string };
  rows?: typeof data.solcat_rows;
  visibleSlugs?: string[];
}) {
  const slugs = visibleSlugs ?? data.module_order;
  const headers = useMemo(
    () => slugs.map(slug => ({
      slug,
      id: data.module_ids[slug] || "?",
      short: data.module_short[slug] || slug,
    })),
    [slugs, data.module_ids, data.module_short],
  );

  return (
    <div className="dash-heatmap-wrap">
      <table className="dash-heatmap">
        <thead>
          <tr>
            <th className="dash-sc-col">Sol cat</th>
            {headers.map(h => (
              <th key={h.slug} title={h.slug}>
                <span className="dash-th-id">{h.id}</span>
                <span className="dash-th-short">{h.short}</span>
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          {(rows ?? data.solcat_rows).map(sc => (
            <tr key={sc.sc_id}>
              <td className="dash-sc-cell">
                <strong>{sc.display_name}</strong>
                {sc.vertical_saas && (
                  <span className="dash-vsaas-pill" title={`Vertical SaaS — ${sc.vertical_saas_industry}`}>
                    SaaS
                  </span>
                )}
                <div className="dash-vert">{sc.vertical}</div>
              </td>
              {headers.map(h => {
                const cell = render(sc.sc_id, h.slug);
                return (
                  <td key={h.slug} className={cell.className} title={cell.title}>
                    {cell.text}
                  </td>
                );
              })}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}
