/**
 * Dashboard 3-tab payload — built by scripts/build_dashboard_full.py from the
 * canonical JSONs + sub_modules.yaml + scope + realistic-fulfilment + crosswalk.
 * Mirrors the legacy Astro dashboard.astro data shape.
 */

export type CoverageVerdict = "pass" | "partial" | "fail" | "na" | "not_in_scope";

export interface ChecklistBand {
  sm_id: string;
  sm_name: string;
  family: string | null;
  r: number;
  p: number;
  a: number;
  caps: Array<{ id: string; name: string; tier: string }>;
}

export interface ChecklistModule {
  slug: string;
  module_name: string;
  module_id: string;
  bands: ChecklistBand[];
  tier_total: { r: number; p: number; a: number };
}

export interface SolcatRow {
  sc_id: string;
  display_name: string;
  vertical: string;
  vertical_saas: boolean;
  vertical_saas_industry: string;
  modules: string[];
}

export interface CoverageCellCap {
  id: string;
  name: string;
  fulfils: "yes" | "partial" | "no" | "unscored" | string;
  reason: string;
}

export interface CoverageCell {
  verdict: CoverageVerdict;
  n_r_passing: number;
  n_r_bearing: number;
  /**
   * Per-cap detail for cell drill (added 2026-05-09 for dashboard 4.4).
   * Optional for backwards-compat; older dashboard_full.json lacked these.
   */
  failing_caps?: CoverageCellCap[];
  passing_caps?: CoverageCellCap[];
}

export interface DashboardFull {
  module_order: string[];
  module_short: Record<string, string>;
  module_ids: Record<string, string>;
  checklist_modules: ChecklistModule[];
  solcat_rows: SolcatRow[];
  coverage_t2: Record<string, Record<string, CoverageCell>>;
  coverage_t11: Record<string, Record<string, CoverageCell>>;
  breadth: Record<string, Record<string, number>>;
  breadth_max: number;
}

let _cache: DashboardFull | null = null;
let _inflight: Promise<DashboardFull> | null = null;

export async function loadDashboardFull(): Promise<DashboardFull> {
  if (_cache) return _cache;
  if (_inflight) return _inflight;
  _inflight = fetch(`${import.meta.env.BASE_URL}dashboard_full.json`, { credentials: "same-origin" })
    .then(res => {
      if (!res.ok) throw new Error(`dashboard_full fetch failed: ${res.status}`);
      return res.json() as Promise<DashboardFull>;
    })
    .then(payload => {
      _cache = payload;
      _inflight = null;
      return payload;
    })
    .catch(e => {
      _inflight = null;
      throw e;
    });
  return _inflight;
}

export function _resetDashboardFullCache(): void {
  _cache = null;
  _inflight = null;
}
