import { useModuleState } from "../contexts/ModuleStateContext";
import "./ReorderStatus.css";

interface Props {
  umbrellaKey: string;
}

/**
 * Inline badge next to a sub-module header that shows the most recent
 * flush state for that umbrella's reorder. Auto-dismisses 2s after a
 * successful save via the context's flushStatus map.
 */
export function ReorderStatus({ umbrellaKey }: Props) {
  const { flushStatus } = useModuleState();
  const status = flushStatus[umbrellaKey];
  if (!status || status === "idle") return null;
  if (status === "saving") {
    return <span className="reorder-status reorder-saving">Saving…</span>;
  }
  if (status === "saved") {
    return <span className="reorder-status reorder-saved">Saved ✓</span>;
  }
  return (
    <span
      className="reorder-status reorder-error"
      title="Save failed — refresh the page and try again."
    >
      Save failed
    </span>
  );
}
