/**
 * Shared fuzzy-search hook + helper.
 *
 * Wraps Fuse.js with the defaults we want everywhere in the SPA:
 *   - typo tolerance (threshold 0.35 — generous but not too noisy)
 *   - matches anywhere in the string (location 0, distance 200)
 *   - all tokens must match (matchAllTokens-style behaviour via `useExtendedSearch`)
 *   - results stay in score order so the best match is on top
 *
 * Usage:
 *   const results = useFuzzy(items, query, ["name", "id", "module"]);
 *
 * - When `query` is empty, returns `items` unchanged (no filtering, no copy).
 * - When `query` is non-empty, returns items in fuzzy-relevance order.
 *
 * For consumers that already have other filters (CapLibrary), apply this
 * AFTER the structured filters so the fuzzy step works on a smaller set.
 */

import { useMemo } from "react";
import Fuse, { type IFuseOptions } from "fuse.js";

export interface FuzzyOptions {
  threshold?: number;
  /** Whether to use Fuse's extended-search syntax for AND/OR tokens. */
  extended?: boolean;
}

const DEFAULT_OPTIONS: FuzzyOptions = {
  threshold: 0.35,
  extended: false,
};

export function useFuzzy<T>(
  items: T[],
  query: string,
  keys: (keyof T | string)[],
  options: FuzzyOptions = {},
): T[] {
  const q = query.trim();
  return useMemo(() => {
    if (!q) return items;
    const opts: IFuseOptions<T> = {
      keys: keys as string[],
      threshold: options.threshold ?? DEFAULT_OPTIONS.threshold!,
      ignoreLocation: true,
      includeScore: false,
      shouldSort: true,
      minMatchCharLength: 2,
      useExtendedSearch: options.extended ?? false,
    };
    const fuse = new Fuse(items, opts);
    return fuse.search(q).map(r => r.item);
  }, [items, q, JSON.stringify(keys), options.threshold, options.extended]);
}

/** Imperative version for places where we need fuzzy outside a hook context
 *  (e.g. derived `useMemo` blocks that already collect dependencies). */
export function fuzzyFilter<T>(
  items: T[],
  query: string,
  keys: (keyof T | string)[],
  options: FuzzyOptions = {},
): T[] {
  const q = query.trim();
  if (!q) return items;
  const fuse = new Fuse(items, {
    keys: keys as string[],
    threshold: options.threshold ?? DEFAULT_OPTIONS.threshold!,
    ignoreLocation: true,
    shouldSort: true,
    minMatchCharLength: 2,
    useExtendedSearch: options.extended ?? false,
  });
  return fuse.search(q).map(r => r.item);
}
