import type { Capability } from "../types/canonical";

export const CHECKLIST_FORMATS = ["type1_1", "type2", "pending_edits", "change_log"] as const;
export type ChecklistFormat = typeof CHECKLIST_FORMATS[number];

export function isChecklistFormat(v: unknown): v is ChecklistFormat {
  return typeof v === "string" && (CHECKLIST_FORMATS as readonly string[]).includes(v);
}

// Mirrors the legacy "active question" precedence in scripts/templates/canonical/_renderers_drill.js:
// terse 1-liner first, verbose Type-1 question second, empty third.
export function getCapQuestion(c: Capability): string {
  const vq = c.vendor_questions || {};
  if (vq.question_terse && vq.question_terse.trim().length > 0) return vq.question_terse;
  if (vq.question && vq.question.trim().length > 0) return vq.question;
  return "";
}
