import { useEffect, useMemo, useState } from "react";
import {
  loadStakeholdersSummary,
  type StakeholdersSummary,
  type SolcatQuestion,
} from "../../lib/stakeholdersData";
import { useUrlParam } from "../../lib/urlState";
import { TabHelp } from "../TabHelp";
import "./SolcatQReference.css";

interface ModuleEntry {
  slug: string;
  module_id: string;
  module_name: string;
  short: string;
}

interface Props {
  modules: ModuleEntry[];
}

type RowFilter = "all" | "real_orphan" | "baseline" | "backed";

/**
 * View B — bottom screenshot. Per-sol-cat IMDA Q reference table:
 * each Q (Q1, Q2, …) → which canonical caps it backs + which modules
 * those caps touch + flags for "real orphan" (no cap mapping at all)
 * and "baseline" (handled in compliance_baseline.json).
 *
 * Reads solcat_questions from stakeholders_summary.json — built by
 * scripts/build_stakeholders_viewer.py::_solcat_questions.
 */
export function SolcatQReference({ modules }: Props) {
  const [data, setData] = useState<StakeholdersSummary | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [scId, setScId] = useUrlParam<string>("sc", "");
  const [filter, setFilter] = useState<RowFilter>("all");

  useEffect(() => {
    loadStakeholdersSummary()
      .then(d => {
        setData(d);
        if (!scId && d.sol_cats?.length) {
          // Auto-pick the first sol cat alphabetically.
          const first = d.sol_cats
            .slice()
            .sort((a, b) => a.display_name.localeCompare(b.display_name))[0];
          if (first) setScId(first.id);
        }
      })
      .catch(e => setError(String(e?.message || e)));
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const moduleShort = useMemo(() => {
    const m: Record<string, string> = {};
    for (const x of modules) m[x.slug] = x.short || x.module_name;
    return m;
  }, [modules]);

  const sortedSolCats = useMemo(() => {
    if (!data) return [];
    return (data.sol_cats || []).slice().sort((a, b) =>
      a.display_name.localeCompare(b.display_name),
    );
  }, [data]);

  const sc = sortedSolCats.find(s => s.id === scId);
  const allQs: SolcatQuestion[] = (data?.solcat_questions?.[scId] || []);
  // Real orphan = no cap mapping AND not baseline-handled AND not a
  // follow-up Q (follow-ups elaborate on a parent Q that may itself be
  // backed; counting them as orphans inflates the gap signal).
  const isRealOrphan = (q: SolcatQuestion) =>
    q.caps_backed.length === 0 && !q.baseline && !q.is_follow_up;

  const visibleQs = useMemo(() => {
    if (filter === "all") return allQs;
    if (filter === "real_orphan") return allQs.filter(isRealOrphan);
    if (filter === "baseline") return allQs.filter(q => q.baseline);
    if (filter === "backed") return allQs.filter(q => q.caps_backed.length > 0);
    return allQs;
  }, [allQs, filter]);

  const counts = useMemo(() => {
    const orphan = allQs.filter(isRealOrphan).length;
    const baseline = allQs.filter(q => q.baseline).length;
    const backed = allQs.filter(q => q.caps_backed.length > 0).length;
    return { total: allQs.length, orphan, baseline, backed };
  }, [allQs]);

  if (error) return <div className="dash-panel sqr-error">Failed to load: {error}</div>;
  if (!data) return <div className="dash-panel sqr-loading">Loading…</div>;

  return (
    <div className="dash-panel">
      <TabHelp hint="Real-orphans = Qs the regulator asks but no canonical cap maps to (real gaps). Baseline Qs = CEM/PDPA/VA-PT/cloud-mobile cross-cuts (expected to be cross-tagged).">
        Per-sol-cat IMDA Q reference — every question in the chosen sol cat,
        annotated with how many canonical caps back it and which modules
        those caps belong to. The reverse view of Module &gt; IMDA gap.
      </TabHelp>
      <div className="sqr-picker-row">
        <label className="sqr-picker-label">Sol cat</label>
        <select
          className="sqr-picker"
          value={scId}
          onChange={e => setScId(e.target.value)}
        >
          <option value="">— pick a sol cat —</option>
          {sortedSolCats.map(s => (
            <option key={s.id} value={s.id}>
              {s.display_name}
              {s.vertical_saas ? " · vertical SaaS" : ""}
            </option>
          ))}
        </select>
      </div>

      {!sc ? (
        <div className="sqr-empty">Pick a sol cat from the dropdown above.</div>
      ) : (
        <>
          <header className="sqr-head">
            <h3 className="sqr-h3">{sc.display_name}</h3>
            <div className="sqr-head-meta">
              <span><strong>{sc.vertical}</strong></span>
              <span>·</span>
              <span>{sc.imda_req_count} IMDA reqs</span>
              <span>·</span>
              <span>{counts.total} Qs</span>
            </div>
          </header>

          <div className="sqr-summary">
            <div className="sqr-stat sqr-stat-total">
              <div className="sqr-stat-num">{counts.total}</div>
              <div className="sqr-stat-lbl">Total Qs</div>
            </div>
            <div className="sqr-stat sqr-stat-backed">
              <div className="sqr-stat-num">{counts.backed}</div>
              <div className="sqr-stat-lbl">Backed by caps</div>
            </div>
            <div className="sqr-stat sqr-stat-orphan">
              <div className="sqr-stat-num">{counts.orphan}</div>
              <div className="sqr-stat-lbl">Real orphans</div>
            </div>
            <div className="sqr-stat sqr-stat-baseline">
              <div className="sqr-stat-num">{counts.baseline}</div>
              <div className="sqr-stat-lbl">Baseline-handled</div>
            </div>
          </div>

          <p className="sqr-blurb">
            Inverse view: each IMDA Q in this sol cat → which canonical caps
            it backs.{" "}
            <span className="sqr-tag sqr-tag-orphan">Real orphans</span>{" "}
            = IMDA asked but no canonical cap maps (real checklist gap).{" "}
            <span className="sqr-tag sqr-tag-baseline">Baseline-handled</span>{" "}
            = PDPA / VA-PT / CEM / Cybersecurity / Cloud — handled in{" "}
            <code>compliance_baseline.json</code>, not real gaps.
          </p>

          <div className="sqr-filter-row">
            <span className="sqr-filter-label">Show</span>
            {([
              ["all", `All (${counts.total})`],
              ["backed", `Backed (${counts.backed})`],
              ["real_orphan", `Real orphans (${counts.orphan})`],
              ["baseline", `Baseline (${counts.baseline})`],
            ] as Array<[RowFilter, string]>).map(([key, label]) => (
              <button
                key={key}
                type="button"
                className={`sqr-filter-pill${filter === key ? " active" : ""}`}
                onClick={() => setFilter(key)}
              >
                {label}
              </button>
            ))}
          </div>

          <table className="sqr-table">
            <thead>
              <tr>
                <th className="sqr-th-q">Q#</th>
                <th className="sqr-th-pri">Pri</th>
                <th className="sqr-th-title">IMDA Q title</th>
                <th className="sqr-th-caps">Caps backed (canonical)</th>
                <th className="sqr-th-mods">Modules touched</th>
              </tr>
            </thead>
            <tbody>
              {visibleQs.length === 0 && (
                <tr>
                  <td colSpan={5} className="sqr-empty-row">
                    No Qs match the active filter.
                  </td>
                </tr>
              )}
              {visibleQs.map(q => {
                const status: "backed" | "orphan" | "baseline" | "followup" =
                  q.baseline ? "baseline"
                  : q.caps_backed.length > 0 ? "backed"
                  : q.is_follow_up ? "followup"
                  : "orphan";
                return (
                  <tr key={q.q_num} className={`sqr-row sqr-row-${status}`}>
                    <td className="sqr-cell-q">
                      <code>{q.q_num}</code>
                      {q.is_follow_up && (
                        <span className="sqr-followup" title="Follow-up question">↳</span>
                      )}
                    </td>
                    <td className="sqr-cell-pri">
                      {q.priority && (
                        <span className={`sqr-pri sqr-pri-${q.priority}`}>
                          {q.priority}
                        </span>
                      )}
                    </td>
                    <td className="sqr-cell-title">
                      {q.q_title}
                      {q.baseline && (
                        <span className="sqr-tag sqr-tag-baseline">baseline</span>
                      )}
                    </td>
                    <td className="sqr-cell-caps">
                      {q.baseline ? (
                        <span className="sqr-baseline-note">
                          handled in <code>compliance_baseline.json</code> — vendor-level cert, not a module feature
                        </span>
                      ) : q.is_follow_up && q.caps_backed.length === 0 ? (
                        <span className="sqr-followup-note">elaboration / follow-up of an earlier Q</span>
                      ) : q.caps_backed.length === 0 ? (
                        <span className="sqr-orphan-note">no canonical cap maps — real orphan</span>
                      ) : (
                        <div className="sqr-cap-pills">
                          {q.caps_backed.map(c => (
                            <code key={c.id} className="sqr-cap-pill" title={c.name}>
                              {c.id}
                            </code>
                          ))}
                        </div>
                      )}
                    </td>
                    <td className="sqr-cell-mods">
                      {q.modules_touched.length === 0 ? (
                        <span className="muted">—</span>
                      ) : (
                        q.modules_touched.map((m, i) => (
                          <span key={m} className="sqr-mod-tag">
                            {moduleShort[m] || m}
                            {i < q.modules_touched.length - 1 ? ", " : ""}
                          </span>
                        ))
                      )}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </>
      )}
    </div>
  );
}
