import { useState, type FormEvent } from "react";
import type { SubModuleEntry } from "../types/canonical";
import { useAuth } from "../contexts/AuthContext";
import {
  saveAddition,
  type AdditionFields,
  type AppTier,
} from "../lib/additions";
import "./AddRequirementModal.css";

interface Props {
  /** Current module slug — read-only on the form. */
  module: string;
  /** Module display name for the header. */
  moduleName?: string;
  /** Sub-modules known for this module (from the canonical's `sub_modules`
   *  block). Used to populate the sub-module dropdown. */
  subModules: SubModuleEntry[];
  /** Required-tier umbrella clusters for this module (from canonical's
   *  `preferred_clusters.required.clusters` block). Empty/null when the
   *  module is single-core. When present (multi-core modules: mfg / asset
   *  / sc / hr), the modal shows an umbrella picker WHEN tier=required.
   *  Selecting an umbrella routes the new cap into that cluster via the
   *  Phase-1 manual_cluster_assignments override flow. */
  requiredClusters?: Array<{ id: string; name: string }>;
  onClose: () => void;
  onSaved: () => void;
}

/**
 * v2 "Add new requirement" modal. Writes a new cap addition to the user's
 * draft branch at drafts/<user>/_additions/<module>/<cap_id>.yaml.
 *
 * Three logical groups of fields:
 *   1. Identity        — name (required), sub-module picker (optional)
 *   2. Question        — vendor_question (required), terse, t2 (both optional)
 *   3. Traceability    — IMDA Q ref, source cap mapping, note (all optional)
 *
 * Tier (required/preferred/advanced) is required — no preselect.
 *
 * cap_id is auto-generated on save: <prefix>.user_<slug>_<rand4>. The user
 * doesn't pick it directly to avoid ID-collision footguns.
 */
export function AddRequirementModal({
  module, moduleName, subModules, requiredClusters, onClose, onSaved,
}: Props) {
  const { user, auth } = useAuth();

  const [name, setName] = useState("");
  const [description, setDescription] = useState("");
  const [tier, setTier] = useState<AppTier | "">("");
  const [subModuleId, setSubModuleId] = useState("");
  const [clusterId, setClusterId] = useState("");
  const [vendorQuestion, setVendorQuestion] = useState("");
  const [vendorQuestionTerse, setVendorQuestionTerse] = useState("");
  const [vendorQuestionT2, setVendorQuestionT2] = useState("");
  const [imdaQRef, setImdaQRef] = useState("");
  const [sourceCapMapping, setSourceCapMapping] = useState("");
  const [note, setNote] = useState("");

  // Umbrella picker only shows for Mandatory tier on multi-core modules.
  // Preferred/Advanced are single-cluster everywhere today — the picker
  // would be useless. This mirrors the rule in step19's scope guard.
  const showClusterPicker = tier === "required" && (requiredClusters?.length || 0) > 0;

  const [saving, setSaving] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // De-dup sub-module options across families. SubModuleEntry has
  // {id, canonical_name, ...} — we want a unique-by-id flat list.
  const subModuleOptions = (() => {
    const seen = new Set<string>();
    const out: Array<{ id: string; name: string }> = [];
    for (const e of subModules) {
      const id = (e as unknown as { id?: string }).id;
      const nm = (e as unknown as { canonical_name?: string; name?: string }).canonical_name
        || (e as unknown as { name?: string }).name
        || id || "";
      if (!id || seen.has(id)) continue;
      seen.add(id);
      out.push({ id, name: nm });
    }
    return out;
  })();

  const validate = (): string | null => {
    if (!name.trim()) return "Name is required.";
    if (!tier) return "Tier is required.";
    if (!vendorQuestion.trim()) return "Vendor question is required.";
    if (name.length > 200) return "Name is too long (max 200 chars).";
    return null;
  };

  const handleSubmit = async (e: FormEvent) => {
    e.preventDefault();
    setError(null);
    const err = validate();
    if (err) { setError(err); return; }
    if (!auth || !user) { setError("Not signed in."); return; }
    setSaving(true);
    try {
      const fields: AdditionFields = {
        name: name.trim(),
        description: description.trim() || undefined,
        sme_tier: tier as AppTier,
        sub_module_id: subModuleId || undefined,
        cluster_id: (showClusterPicker && clusterId) ? clusterId : undefined,
        vendor_question: vendorQuestion.trim(),
        vendor_question_terse: vendorQuestionTerse.trim() || undefined,
        vendor_question_t2: vendorQuestionT2.trim() || undefined,
        imda_q_ref: imdaQRef.trim() || undefined,
        source_cap_mapping: sourceCapMapping.trim() || undefined,
        note: note.trim() || undefined,
      };
      await saveAddition(auth, user.login, user.email || user.login, module, fields);
      onSaved();
      onClose();
    } catch (e: unknown) {
      setError(e instanceof Error ? e.message : String(e));
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="arm-shell" role="dialog" aria-modal="true">
      <div className="arm-card">
        <header className="arm-head">
          <h2>Add new requirement</h2>
          <div className="arm-sub muted small">
            Module: <code>{moduleName || module}</code>
          </div>
          <button type="button" className="arm-close" onClick={onClose}>×</button>
        </header>

        <form onSubmit={handleSubmit} className="arm-form">
          <section className="arm-section">
            <h3 className="arm-sec-h">Identity</h3>
            <label className="arm-label">
              <span>Name <span className="arm-req">*</span></span>
              <input
                type="text"
                value={name}
                onChange={e => setName(e.target.value)}
                placeholder="e.g. Bank Transaction Reconciliation"
                maxLength={200}
                required
              />
            </label>
            <label className="arm-label">
              <span>Tier <span className="arm-req">*</span></span>
              <select value={tier} onChange={e => setTier(e.target.value as AppTier | "")} required>
                <option value="">Select tier…</option>
                <option value="required">Required (Mandatory)</option>
                <option value="preferred">Preferred</option>
                <option value="advanced">Advanced / Enterprise</option>
              </select>
            </label>
            <label className="arm-label">
              <span>Sub-module (optional)</span>
              <select value={subModuleId} onChange={e => setSubModuleId(e.target.value)}>
                <option value="">— Ungrouped —</option>
                {subModuleOptions.map(o => (
                  <option key={o.id} value={o.id}>{o.name}</option>
                ))}
              </select>
            </label>
            {showClusterPicker && (
              <label className="arm-label">
                <span>Umbrella (multi-core split)</span>
                <select value={clusterId} onChange={e => setClusterId(e.target.value)}>
                  <option value="">— Default (Other) —</option>
                  {(requiredClusters || []).map(c => (
                    <option key={c.id} value={c.id}>{c.name}</option>
                  ))}
                </select>
                <span className="arm-hint muted small">
                  This module's Mandatory tier is split into multiple cores. Pick
                  the umbrella that best fits — or leave default and the cap
                  lands in the "Other" tail.
                </span>
              </label>
            )}
            {tier && tier !== "required" && (requiredClusters?.length || 0) > 0 && (
              <div className="arm-note arm-note-info">
                ℹ Umbrella picker is Mandatory-tier only — Preferred and Advanced are single-cluster on this module.
              </div>
            )}
            <label className="arm-label">
              <span>Description (optional)</span>
              <textarea
                value={description}
                onChange={e => setDescription(e.target.value)}
                rows={2}
                placeholder="One-sentence definition of what this capability covers."
              />
            </label>
          </section>

          <section className="arm-section">
            <h3 className="arm-sec-h">Vendor question</h3>
            <label className="arm-label">
              <span>Verbose question <span className="arm-req">*</span></span>
              <textarea
                value={vendorQuestion}
                onChange={e => setVendorQuestion(e.target.value)}
                rows={3}
                placeholder="Does your solution… (full IMDA-style Type 1 question)"
                required
              />
            </label>
            <label className="arm-label">
              <span>Terse (Type 1.1 — single line, optional)</span>
              <input
                type="text"
                value={vendorQuestionTerse}
                onChange={e => setVendorQuestionTerse(e.target.value)}
                placeholder="Single-line summary"
              />
            </label>
            <label className="arm-label">
              <span>Type 2 bullet (verb-led, optional)</span>
              <input
                type="text"
                value={vendorQuestionT2}
                onChange={e => setVendorQuestionT2(e.target.value)}
                placeholder="e.g. Reconcile bank transactions against ledger entries"
              />
            </label>
          </section>

          <section className="arm-section">
            <h3 className="arm-sec-h">Traceability (optional — pipeline picks these up)</h3>
            <label className="arm-label">
              <span>IMDA Q reference</span>
              <input
                type="text"
                value={imdaQRef}
                onChange={e => setImdaQRef(e.target.value)}
                placeholder="e.g. Q5, Q12"
              />
            </label>
            <label className="arm-label">
              <span>Source cap mapping</span>
              <input
                type="text"
                value={sourceCapMapping}
                onChange={e => setSourceCapMapping(e.target.value)}
                placeholder="Related existing cap ids, comma-separated (e.g. fin.general_ledger)"
              />
            </label>
            <label className="arm-label">
              <span>Note</span>
              <textarea
                value={note}
                onChange={e => setNote(e.target.value)}
                rows={2}
                placeholder="Why this requirement matters / context"
              />
            </label>
          </section>

          {error && <div className="arm-error">{error}</div>}

          <footer className="arm-footer">
            <button type="button" className="arm-btn-cancel" onClick={onClose}>Cancel</button>
            <button type="submit" className="arm-btn-primary" disabled={saving}>
              {saving ? "Saving…" : "Save addition (draft)"}
            </button>
          </footer>
        </form>
      </div>
    </div>
  );
}
